# ================= AUTOTRADE SESSION STORAGE =================
def _autotrade_get_sessions():
    default_sessions = ["NY", "LON", "ASIA"]
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""
                CREATE TABLE IF NOT EXISTS autotrade_config (
                    key TEXT PRIMARY KEY,
                    value TEXT
                )
            """)
            c.execute("SELECT value FROM autotrade_config WHERE key='sessions'")
            row = c.fetchone()
            if row is not None:
                parsed = [s.strip().upper() for s in str(row[0] or '').split(",") if s.strip()]
                if parsed:
                    return parsed
            c.execute(
                "INSERT OR REPLACE INTO autotrade_config(key,value) VALUES('sessions',?)",
                (",".join(default_sessions),)
            )
            conn.commit()
    except Exception:
        pass
    return list(default_sessions)

def _autotrade_set_sessions(val: str):
    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("""
                CREATE TABLE IF NOT EXISTS autotrade_config (
                    key TEXT PRIMARY KEY,
                    value TEXT
                )
            """)
            c.execute(
                "INSERT OR REPLACE INTO autotrade_config(key,value) VALUES('sessions',?)",
                (val.upper(),)
            )
            conn.commit()
    except Exception:
        pass
