# =========================================================
# 🤖 AUTOTRADE — Bybit V5 helpers + DB
# =========================================================
import hmac
import hashlib
import uuid

def _bybit_base_url() -> str:
    return "https://api-testnet.bybit.com" if BYBIT_TESTNET else "https://api.bybit.com"

def _bybit_v5_sign(ts_ms: str, body: str) -> str:
    """
    Bybit V5 signature:
      sign = HMAC_SHA256(secret, timestamp + api_key + recv_window + body)
    """
    msg = f"{ts_ms}{BYBIT_API_KEY}{BYBIT_RECV_WINDOW}{body}".encode("utf-8")
    return hmac.new(BYBIT_API_SECRET.encode("utf-8"), msg, hashlib.sha256).hexdigest()

def _bybit_v5_request(method: str, path: str, payload: dict | None = None) -> dict:
    import requests
    from urllib.parse import urlencode

    method = (method or "GET").upper().strip()
    payload = payload or {}

    base = _bybit_base_url()
    url = base + path

    ts_ms = str(int(time.time() * 1000))

    # For V5 signing:
    # - GET requests must be signed with the *query string* (not the body),
    #   and the query must actually be sent to Bybit.
    # - POST requests are signed with the JSON body.
    body = ""
    query_str = ""

    if method == "GET":
        # Support callers that pass params in payload (recommended).
        # If path already has '?', keep it and append any payload params.
        if "?" in url:
            url_base, url_q = url.split("?", 1)
            url = url_base
            query_str = url_q
        if payload:
            extra = urlencode(payload, doseq=True)
            query_str = f"{query_str}&{extra}" if (query_str and extra) else (query_str or extra)

        if query_str:
            url = f"{url}?{query_str}"

        sign_payload = query_str
    else:
        body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False)
        sign_payload = body

    sign = _bybit_v5_sign(ts_ms, sign_payload) if (BYBIT_API_KEY and BYBIT_API_SECRET) else ""

    headers = {
        "Content-Type": "application/json",
        "X-BAPI-API-KEY": BYBIT_API_KEY,
        "X-BAPI-TIMESTAMP": ts_ms,
        "X-BAPI-RECV-WINDOW": BYBIT_RECV_WINDOW,
        "X-BAPI-SIGN": sign,
    }

    try:
        if method == "GET":
            r = requests.get(url, headers=headers, timeout=15)
        else:
            r = requests.post(url, headers=headers, data=body.encode("utf-8"), timeout=15)
        return r.json()
    except Exception as e:
        return {"retCode": -1, "retMsg": f"{type(e).__name__}: {e}", "result": None}
def _bybit_get_instr_filters(symbol: str) -> dict:
    """Return best-effort Bybit linear instrument filters.

    Keys returned as strings when available:
    - minQty
    - qtyStep
    - minNotional
    - contractSize
    - tickSize
    """
    sym = _bybit_linear_symbol(symbol)
    if sym in _INSTR_FILTER_CACHE:
        return _INSTR_FILTER_CACHE[sym]
    out = {"minQty": None, "qtyStep": None, "minNotional": None, "contractSize": None, "tickSize": None}
    try:
        res = _bybit_v5_request("GET", "/v5/market/instruments-info", {"category": "linear", "symbol": sym})
        items = (((res or {}).get("result") or {}).get("list") or [])
        if items:
            info = items[0] or {}
            lot = info.get("lotSizeFilter") or {}
            price_filter = info.get("priceFilter") or {}

            if lot.get("minOrderQty") is not None:
                out["minQty"] = str(lot.get("minOrderQty"))
            if lot.get("qtyStep") is not None:
                out["qtyStep"] = str(lot.get("qtyStep"))
            # Current Bybit V5 field for linear min notional is lotSizeFilter.minNotionalValue
            min_notional = lot.get("minNotionalValue")
            if min_notional is None:
                nf = info.get("notionalFilter") or {}
                min_notional = nf.get("minNotional")
            if min_notional is not None:
                out["minNotional"] = str(min_notional)
            if info.get('contractSize') is not None:
                out['contractSize'] = str(info.get('contractSize'))
            if price_filter.get('tickSize') is not None:
                out['tickSize'] = str(price_filter.get('tickSize'))
    except Exception:
        pass
    _INSTR_FILTER_CACHE[sym] = out
    return out



def _fmt_qty(qty: float, step) -> str:
    """Format qty as Bybit-safe decimal string aligned to qtyStep.

    Safety rule (critical): never round UP quantities, because that can increase
    the true $ risk beyond the intended risk-per-trade. We therefore round DOWN
    to the nearest qtyStep multiple.
    """
    try:
        if qty is None:
            return "0"
        dqty = Decimal(str(qty))

        if step is None:
            return format(dqty, "f")

        dstep = Decimal(str(step))
        if dstep <= 0:
            return format(dqty, "f")

        mult = (dqty / dstep).to_integral_value(rounding=ROUND_DOWN)
        dq = (mult * dstep).quantize(dstep)  # keeps correct decimals
        if dq <= 0:
            return "0"
        return format(dq, "f")
    except Exception:
        try:
            return format(Decimal(str(qty)), "f")
        except Exception:
            return str(qty)


def _round_qty_down(symbol: str, qty: float, entry_price: float) -> tuple[float | None, str | None]:
    """Decimal-safe rounding DOWN to Bybit qtyStep and safety-checking minQty/minNotional.

    CRITICAL SAFETY:
    - We never round UP qty to satisfy minNotional/minQty because that can increase
      the true $ risk beyond the user's /riskmode.
    - If, after rounding DOWN, qty does not meet exchange minimums, we SKIP the trade.
    """
    try:
        if qty is None or float(qty) <= 0:
            return (None, "qty<=0")

        f = _bybit_get_instr_filters(symbol)
        step_s = f.get("qtyStep")
        min_qty_s = f.get("minQty")
        min_not_s = f.get("minNotional")
        cs_s = f.get("contractSize")

        dqty = Decimal(str(qty))
        dentry = Decimal(str(entry_price)) if entry_price and entry_price > 0 else None

        def _d(x):
            if x is None:
                return None
            try:
                return Decimal(str(x))
            except Exception:
                return None

        dstep = _d(step_s)
        dmin = _d(min_qty_s)
        dmin_not = _d(min_not_s)
        dcs = _d(cs_s) or Decimal('1')

        # Round DOWN to step
        if dstep and dstep > 0:
            mult = (dqty / dstep).to_integral_value(rounding=ROUND_DOWN)
            dqty = (mult * dstep).quantize(dstep)

        if dqty <= 0:
            return (None, "qty_rounds_to_0")

        # Enforce minQty without rounding up
        if dmin and dqty < dmin:
            return (None, "below_minQty_after_round_down")

        # Enforce minNotional without rounding up
        if dmin_not and dentry and dentry > 0:
            notional = dqty * dentry * dcs
            if notional < dmin_not:
                return (None, "below_minNotional_after_round_down")

        return (float(dqty), None)

    except Exception as e:
        return (None, f"qty_round_fail:{type(e).__name__}")




def _round_price_to_tick(symbol: str, price: float, rounding=ROUND_DOWN) -> float:
    """Round a price to Bybit tick size. Best-effort only."""
    try:
        if price is None:
            return 0.0
        f = _bybit_get_instr_filters(symbol)
        tick_s = f.get("tickSize")
        if not tick_s:
            return float(price)
        dprice = Decimal(str(price))
        dtick = Decimal(str(tick_s))
        if dtick <= 0:
            return float(price)
        mult = (dprice / dtick).to_integral_value(rounding=rounding)
        out = (mult * dtick).quantize(dtick)
        return float(out)
    except Exception:
        try:
            return float(price)
        except Exception:
            return 0.0


def _effective_equity_for_risk(user: dict | None = None, prefer_live: bool = True) -> float:
    """Single source of truth for risk-based equity.

    LIVE mode prefers Bybit-reported equity; otherwise falls back to user-stored equity.
    """
    eq = 0.0
    try:
        if isinstance(user, dict):
            eq = float(user.get("equity", 0.0) or 0.0)
    except Exception:
        eq = 0.0
    if prefer_live:
        try:
            live_eq = _live_equity_usdt()
            if live_eq is not None and float(live_eq) > 0:
                return float(live_eq)
        except Exception:
            pass
    return max(0.0, float(eq or 0.0))


def _risk_amount_from_pct(equity: float, risk_pct: float) -> float:
    try:
        if float(equity) <= 0:
            return 0.0
        return max(0.0, float(equity) * (float(risk_pct) / 100.0))
    except Exception:
        return 0.0


def _risk_pct_from_amount(equity: float, risk_usd: float) -> float:
    try:
        if float(equity) <= 0:
            return 0.0
        return max(0.0, (float(risk_usd) / float(equity)) * 100.0)
    except Exception:
        return 0.0


def _autotrade_live_reference_price(symbol: str, fallback_entry: float = 0.0) -> float:
    """Best-effort executable reference price for live sizing.

    We use a current market reference instead of a potentially stale setup entry so market-order
    sizing stays aligned with real stop distance.
    """
    sym = _bybit_linear_symbol(symbol)
    try:
        res = _bybit_v5_request("GET", "/v5/market/tickers", {"category": "linear", "symbol": sym})
        items = (((res or {}).get("result") or {}).get("list") or [])
        if items:
            t = items[0] or {}
            for k in ("markPrice", "lastPrice", "indexPrice"):
                try:
                    px = float(t.get(k) or 0.0)
                    if px > 0:
                        return px
                except Exception:
                    pass
    except Exception:
        pass

    try:
        best = get_cached_futures_tickers() or {}
        base = sym[:-4] if sym.endswith("USDT") else sym
        mv = best.get(base)
        if mv:
            px = float(getattr(mv, "last", 0.0) or 0.0)
            if px > 0:
                return px
    except Exception:
        pass
    try:
        return float(fallback_entry or 0.0)
    except Exception:
        return 0.0


def _autotrade_true_risk_usd(entry_price: float, stop_price: float, qty_contracts: float, contract_size: float = 1.0) -> float:
    try:
        return abs(float(entry_price) - float(stop_price)) * abs(float(qty_contracts)) * abs(float(contract_size or 1.0))
    except Exception:
        return 0.0


def _autotrade_find_live_position(symbol: str, side: str | None = None) -> dict | None:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or "").upper().strip()
    try:
        for p in _bybit_get_open_positions_linear():
            psym = _pos_symbol(p)
            if psym != sym:
                continue
            if side_u:
                pside = _pos_side_text(p)
                if pside != side_u:
                    continue
            return p
    except Exception:
        return None
    return None
def _autotrade_ready() -> bool:
    if not AUTOTRADE_ENABLED:
        return False
    if AUTOTRADE_OWNER_UID <= 0:
        return False
    if AUTOTRADE_MODE not in ("paper", "live"):
        return False
    if AUTOTRADE_MODE == "live" and (not BYBIT_API_KEY or not BYBIT_API_SECRET):
        return False
    return True

def _bybit_get_equity_usdt() -> float:
    """Returns account equity (USDT) from Bybit V5 wallet-balance.

    Tries common account types (UNIFIED, CONTRACT) and returns the first positive equity found.
    """
    def _extract_equity(res: dict) -> float:
        try:
            if int(res.get("retCode", -1)) != 0:
                return 0.0
            lst = ((res.get("result") or {}).get("list") or [])
            if not lst:
                return 0.0
            # V5 response: result.list[].coin[] contains entries like {"coin":"USDT","equity":"..."}
            coins = ((lst[0] or {}).get("coin") or [])
            usdt = None
            for c in coins:
                if str((c or {}).get("coin", "")).upper() == "USDT":
                    usdt = c or {}
                    break
            if not usdt and coins:
                usdt = coins[0] or {}
            eq = float(usdt.get("equity") or usdt.get("walletBalance") or usdt.get("availableToWithdraw") or 0.0)
            return max(0.0, eq)
        except Exception:
            return 0.0

    for acct in ("UNIFIED", "CONTRACT"):
        res = _bybit_v5_request("GET", f"/v5/account/wallet-balance?accountType={acct}&coin=USDT")
        eq = _extract_equity(res)
        if eq > 0:
            return eq
    return 0.0


def _live_equity_usdt() -> float | None:
    """LIVE mode equity source. Returns None if unavailable.

    Uses Bybit V5 wallet-balance (UNIFIED, USDT) and falls back to None on failure.
    """
    try:
        if not AUTOTRADE_ENABLED:
            return None
        if str(AUTOTRADE_MODE).lower() != "live":
            return None
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return None
        eq = float(_bybit_get_equity_usdt() or 0.0)
        return eq if eq > 0 else None
    except Exception:
        return None



def _tz_melbourne():
    try:
        return ZoneInfo("Australia/Melbourne")
    except Exception:
        return timezone.utc

def _parse_iso_utcish(iso_s: str) -> Optional[datetime]:
    """Parse ISO text and treat naive timestamps as UTC."""
    if not iso_s:
        return None
    try:
        dt = datetime.fromisoformat(str(iso_s).replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt
    except Exception:
        return None


def _dt_local(dt: datetime) -> datetime:
    try:
        if getattr(dt, "tzinfo", None) is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(_tz_melbourne())
    except Exception:
        return dt


def _fmt_dt_local(dt: datetime, fmt: str = "%Y-%m-%d %H:%M:%S") -> str:
    try:
        return _dt_local(dt).strftime(fmt)
    except Exception:
        try:
            return dt.isoformat(timespec="seconds")
        except Exception:
            return str(dt)


def _fmt_iso_to_local(iso_s: str) -> str:
    """Convert ISO string (UTC or with tz) to Melbourne local display."""
    if not iso_s:
        return ""
    dt = _parse_iso_utcish(str(iso_s))
    if dt is None:
        return str(iso_s)
    return _fmt_dt_local(dt)

def _ms_to_local_str(ms: int | str | None) -> str:
    try:
        if ms is None:
            return ""
        ms_i = int(float(ms))
        dt = datetime.fromtimestamp(ms_i/1000.0, tz=timezone.utc)
        return _fmt_dt_local(dt)
    except Exception:
        return ""

def _bybit_get_open_positions_linear() -> list[dict]:
    """Return cached open linear USDT positions (Bybit V5).

    Short cache keeps status/report/autotrade commands responsive and avoids repeated
    position-list hits within the same second burst.
    """
    cache_key = 'bybit_open_positions_linear'
    try:
        ttl = max(1, int(BYBIT_OPEN_POSITIONS_CACHE_TTL_SEC or 6))
        if cache_valid(cache_key, ttl):
            cached = cache_get(cache_key)
            return list(cached or []) if isinstance(cached, list) else []
    except Exception:
        pass
    try:
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return []
        res = _bybit_v5_request("GET", "/v5/position/list", {
            "category": "linear",
            "settleCoin": "USDT",
            "limit": 200,
        })
        if int(res.get("retCode", -1)) != 0:
            return []
        lst = ((res.get("result") or {}).get("list") or [])
        out = []
        for p in lst:
            try:
                size = float(p.get("size") or 0.0)
            except Exception:
                size = 0.0
            if size == 0:
                continue
            out.append(p)
        try:
            cache_set(cache_key, list(out))
        except Exception:
            pass
        return out
    except Exception:
        stale = cache_get(cache_key)
        return list(stale or []) if isinstance(stale, list) else []

def _norm_trade_side(side: str) -> str:
    try:
        s = str(side or '').strip().upper()
        if s in ('BUY', 'LONG'):
            return 'BUY'
        if s in ('SELL', 'SHORT'):
            return 'SELL'
        return s
    except Exception:
        return ''

def _pos_side_text(p: dict) -> str:
    try:
        s = str(p.get("side") or "").upper()
        return "BUY" if s == "BUY" else "SELL" if s == "SELL" else s
    except Exception:
        return ""

def _pos_symbol(p: dict) -> str:
    try:
        return _bybit_linear_symbol(str(p.get("symbol") or ""))
    except Exception:
        return str(p.get("symbol") or "")

def _pos_unreal_pnl(p: dict) -> float:
    try:
        return float(p.get("unrealisedPnl") or p.get("unrealizedPnl") or 0.0)
    except Exception:
        return 0.0

def _pos_mark(p: dict) -> float:
    try:
        return float(p.get("markPrice") or 0.0)
    except Exception:
        return 0.0

def _pos_entry(p: dict) -> float:
    try:
        return float(p.get("avgPrice") or p.get("entryPrice") or 0.0)
    except Exception:
        return 0.0

def _bybit_exit_close_side_for_position_side(side: str | None) -> str:
    try:
        s = str(side or '').upper().strip()
        if s == 'BUY':
            return 'SELL'
        if s == 'SELL':
            return 'BUY'
    except Exception:
        pass
    return ''


def _bybit_order_close_side(order: dict) -> str:
    """Best-effort close-side for Bybit exit orders.

    For TP/SL orders Bybit may not always expose a normal side field consistently,
    so we also infer from text like 'close short' / 'close long'.
    Returned value is the exchange order side that would close the position: BUY or SELL.
    """
    try:
        s = str((order or {}).get('side') or '').upper().strip()
        if s in {'BUY', 'SELL'}:
            return s
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'close short' in txt:
            return 'BUY'
        if 'close long' in txt:
            return 'SELL'
    except Exception:
        pass
    return ''


def _bybit_order_matches_close_side(order: dict, want_close_side: str | None = None) -> bool:
    try:
        want = str(want_close_side or '').upper().strip()
        if not want:
            return True
        got = _bybit_order_close_side(order)
        if not got:
            # Do not reject an otherwise valid TP/SL order just because Bybit omitted side.
            return True
        return got == want
    except Exception:
        return False


def _bybit_detect_open_sl_price(symbol: str, side: str | None = None) -> float:
    """Detect the effective SL price from active exchange TP/SL orders.

    This is needed because Bybit partial TP/SL pairs do not always populate the
    position-level stopLoss field, even though the SL is real and active.
    """
    sym = _bybit_linear_symbol(symbol)
    if not sym:
        return 0.0
    want_close_side = _bybit_exit_close_side_for_position_side(side)
    buckets: list[dict] = []
    try:
        for o in (_bybit_get_open_orders_linear(sym) or []):
            try:
                if _bybit_linear_symbol(str((o or {}).get('symbol') or '')) != sym:
                    continue
                if not _bybit_order_matches_close_side(o, want_close_side):
                    continue
                if not _bybit_is_sl_exit_order(o):
                    continue
                px = float(_bybit_order_sl_price(o) or _bybit_order_working_price(o) or 0.0)
                if px <= 0:
                    continue
                qty = abs(float(_bybit_order_filled_qty(o) or 0.0))
                if qty <= 0:
                    qty = 1.0
                matched = False
                for b in buckets:
                    if _price_close_enough(float(b.get('price') or 0.0), px, rel_tol=0.0010):
                        b['qty'] = float(b.get('qty') or 0.0) + qty
                        b['count'] = int(b.get('count') or 0) + 1
                        matched = True
                        break
                if not matched:
                    buckets.append({'price': float(px), 'qty': float(qty), 'count': 1})
            except Exception:
                continue
    except Exception:
        return 0.0
    if not buckets:
        return 0.0
    buckets.sort(key=lambda x: (float(x.get('qty') or 0.0), int(x.get('count') or 0), float(x.get('price') or 0.0)), reverse=True)
    try:
        return float((buckets[0] or {}).get('price') or 0.0)
    except Exception:
        return 0.0


def _pos_stop(p: dict) -> float:
    try:
        raw = float(p.get("stopLoss") or 0.0)
        if raw > 0:
            return raw
    except Exception:
        pass
    try:
        return float(_bybit_detect_open_sl_price(_pos_symbol(p), _pos_side_text(p)) or 0.0)
    except Exception:
        return 0.0

def _pos_size(p: dict) -> float:
    try:
        return float(p.get("size") or 0.0)
    except Exception:
        return 0.0

def _estimate_position_risk_usd(p: dict) -> float:
    """Estimate risk using entry vs stopLoss if available; otherwise 0."""
    try:
        entry = _pos_entry(p)
        sl = _pos_stop(p)
        size = abs(_pos_size(p))
        if entry <= 0 or sl <= 0 or size <= 0:
            return 0.0
        return abs(entry - sl) * size
    except Exception:
        return 0.0

def _pos_take_profit(p: dict) -> float:
    try:
        return float(p.get("takeProfit") or 0.0)
    except Exception:
        return 0.0


def _price_close_enough(a: float, b: float, rel_tol: float = 0.002, abs_tol: float = 1e-8) -> bool:
    try:
        a = float(a or 0.0)
        b = float(b or 0.0)
        if a <= 0 or b <= 0:
            return False
        return abs(a - b) <= max(abs_tol, max(abs(a), abs(b)) * float(rel_tol))
    except Exception:
        return False


def _dedupe_price_targets(values: list[float], rel_tol: float = 0.0005) -> list[float]:
    """Return ordered positive targets with near-duplicates removed."""
    out: list[float] = []
    try:
        for raw in (values or []):
            try:
                px = float(raw or 0.0)
            except Exception:
                px = 0.0
            if px <= 0:
                continue
            if any(_price_close_enough(px, seen, rel_tol=rel_tol) for seen in out):
                continue
            out.append(float(px))
    except Exception:
        return [float(x) for x in (values or []) if float(x or 0.0) > 0]
    return out


def _be_min_quality_for_session(session_name: str) -> float:
    sess = str(session_name or '').upper().strip()
    if sess == 'NY':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 80.0)
    if sess == 'LON':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 76.0)
    if sess == 'ASIA':
        return max(float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY), 82.0)
    return float(AUTOTRADE_BE_AFTER_TP_MIN_QUALITY)


def _backtest_should_move_sl_to_be_after_tp(setup: "Setup", session_name: str) -> bool:
    """Single-TP model: no break-even step is used."""
    return False

def _autotrade_live_exit_plan_from_targets(entry: float, sl: float, tp, alt_target_a, alt_target_b, side: str) -> dict:
    tp = _resolve_single_tp(entry, sl, tp=tp, alt_target_a=alt_target_a, alt_target_b=alt_target_b, side=side)
    return {
        'partial_tp': 0.0,
        'final_tp': float(tp or 0.0),
        'partial_fraction': 1.0,
        'effective_tp': float(tp or 0.0),
        'effective_alt_target_a': 0.0,
        'effective_alt_target_b': 0.0,
    }


def _autotrade_live_exit_plan_for_trade(trade_or_setup) -> dict:
    return _autotrade_live_exit_plan_from_targets(
        float(getattr(trade_or_setup, 'entry', 0.0) if hasattr(trade_or_setup, 'entry') else (trade_or_setup.get('entry') if isinstance(trade_or_setup, dict) else 0.0) or 0.0),
        float(getattr(trade_or_setup, 'sl', 0.0) if hasattr(trade_or_setup, 'sl') else (trade_or_setup.get('sl') if isinstance(trade_or_setup, dict) else 0.0) or 0.0),
        getattr(trade_or_setup, 'tp', None) if hasattr(trade_or_setup, 'tp') else (trade_or_setup.get('tp') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'alt_target_a', None) if hasattr(trade_or_setup, 'alt_target_a') else (trade_or_setup.get('alt_target_a') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'alt_target_b', None) if hasattr(trade_or_setup, 'alt_target_b') else (trade_or_setup.get('alt_target_b') if isinstance(trade_or_setup, dict) else None),
        getattr(trade_or_setup, 'side', '') if hasattr(trade_or_setup, 'side') else (trade_or_setup.get('side') if isinstance(trade_or_setup, dict) else ''),
    )


def _bybit_order_active(order: dict) -> bool:
    try:
        status = str(order.get('orderStatus') or '').upper().strip()
        return status not in {'FILLED', 'CANCELLED', 'REJECTED', 'DEACTIVATED'}
    except Exception:
        return False


def _bybit_order_working_price(order: dict) -> float:
    try:
        for key in ('triggerPrice', 'trigger_price', 'stopOrderPrice', 'stop_order_price', 'price'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_tp_price(order: dict) -> float:
    try:
        for key in ('takeProfit', 'take_profit', 'tpTriggerPrice', 'tp_trigger_price', 'tpLimitPrice', 'tp_limit_price', 'tpPrice', 'tp_price'):
            v = float((order or {}).get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'takeprofit' in txt or 'partialtakeprofit' in txt or 'pf_tp' in txt:
            v = float(_bybit_order_working_price(order) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_sl_price(order: dict) -> float:
    try:
        for key in ('stopLoss', 'stop_loss', 'slTriggerPrice', 'sl_trigger_price', 'slLimitPrice', 'sl_limit_price', 'slPrice', 'sl_price'):
            v = float((order or {}).get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    try:
        txt = _bybit_order_kind_text(order)
        if 'stoploss' in txt or 'pf_sl' in txt:
            v = float(_bybit_order_working_price(order) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0

def _bybit_order_kind_text(order: dict) -> str:
    try:
        bits = [
            str(order.get('orderType') or ''),
            str(order.get('stopOrderType') or ''),
            str(order.get('stop_order_type') or ''),
            str(order.get('createType') or ''),
            str(order.get('create_type') or ''),
            str(order.get('orderLinkId') or ''),
        ]
        return ' '.join([b for b in bits if b]).lower()
    except Exception:
        return ''


def _bybit_is_tp_exit_order(order: dict) -> bool:
    try:
        if not _bybit_order_active(order):
            return False
        if not _bybit_order_reduce_only(order):
            return False
        if float(_bybit_order_tp_price(order) or 0.0) > 0:
            return True
        txt = _bybit_order_kind_text(order)
        if 'stoploss' in txt and 'takeprofit' not in txt and 'partialtakeprofit' not in txt:
            return False
        if 'partialtakeprofit' in txt or 'takeprofit' in txt or 'pf_tp' in txt:
            return True
        order_type = str(order.get('orderType') or '').upper().strip()
        trig = float(order.get('triggerPrice') or order.get('trigger_price') or 0.0)
        if order_type == 'MARKET' and trig > 0:
            return True
        if order_type == 'LIMIT':
            return True
    except Exception:
        pass
    return False


def _bybit_is_sl_exit_order(order: dict) -> bool:
    try:
        if not _bybit_order_active(order):
            return False
        if not _bybit_order_reduce_only(order):
            return False
        if float(_bybit_order_sl_price(order) or 0.0) > 0:
            return True
        txt = _bybit_order_kind_text(order)
        if 'partialtakeprofit' in txt or 'takeprofit' in txt or 'pf_tp' in txt:
            return False
        if 'stoploss' in txt or 'pf_sl' in txt:
            return True
        trig = float(order.get('triggerPrice') or order.get('trigger_price') or 0.0)
        order_type = str(order.get('orderType') or '').upper().strip()
        return bool(order_type == 'MARKET' and trig > 0)
    except Exception:
        return False


def _bybit_has_matching_tp_exit(symbol: str, close_side: str, tp_price: float) -> bool:
    sym = _bybit_linear_symbol(symbol)
    want_side = str(close_side or '').upper().strip()
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, want_side):
                continue
            if not _bybit_is_tp_exit_order(o):
                continue
            px = float(_bybit_order_tp_price(o) or _bybit_order_working_price(o) or 0.0)
            if _price_close_enough(px, tp_price, rel_tol=0.0010):
                return True
        except Exception:
            continue
    return False


def _bybit_has_open_tp_order_at(symbol: str, tp_price: float, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    return _bybit_has_matching_tp_exit(sym, close_side, float(tp_price or 0.0))


def _bybit_has_matching_sl_exit(symbol: str, close_side: str, sl_price: float) -> bool:
    sym = _bybit_linear_symbol(symbol)
    want_side = str(close_side or '').upper().strip()
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, want_side):
                continue
            if not _bybit_is_sl_exit_order(o):
                continue
            px = float(_bybit_order_sl_price(o) or _bybit_order_working_price(o) or 0.0)
            if _price_close_enough(px, sl_price, rel_tol=0.0010):
                return True
        except Exception:
            continue
    return False


def _bybit_has_open_sl_order_at(symbol: str, sl_price: float, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    return _bybit_has_matching_sl_exit(sym, close_side, float(sl_price or 0.0))


def _bybit_sum_open_exit_qty_at(symbol: str, trigger_price: float, side: str | None = None, kind: str = 'tp') -> float:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    close_side = ''
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    want_kind = str(kind or 'tp').lower().strip()
    total = 0.0
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, close_side):
                continue
            is_match = _bybit_is_sl_exit_order(o) if want_kind == 'sl' else _bybit_is_tp_exit_order(o)
            if not is_match:
                continue
            px = float((_bybit_order_sl_price(o) if want_kind == 'sl' else _bybit_order_tp_price(o)) or _bybit_order_working_price(o) or 0.0)
            if not _price_close_enough(px, float(trigger_price or 0.0), rel_tol=0.0010):
                continue
            total += abs(float(_bybit_order_filled_qty(o) or 0.0))
        except Exception:
            continue
    return float(total)


def _autotrade_min_child_exit_qty(symbol: str, trigger_price: float) -> float:
    """Minimum child-order quantity needed for one TP slice on Bybit."""
    try:
        sym = _bybit_linear_symbol(symbol)
        filt = _bybit_get_instr_filters(sym)
        step_s = filt.get('qtyStep')
        min_qty_s = filt.get('minQty')
        min_not_s = filt.get('minNotional')
        cs_s = filt.get('contractSize')

        dstep = Decimal(str(step_s)) if step_s not in (None, '', 0, '0') else Decimal('0.00000001')
        if dstep <= 0:
            dstep = Decimal('0.00000001')
        dmin_qty = Decimal(str(min_qty_s)) if min_qty_s not in (None, '', 0, '0') else Decimal('0')
        dmin_not = Decimal(str(min_not_s)) if min_not_s not in (None, '', 0, '0') else Decimal('0')
        dcs = Decimal(str(cs_s)) if cs_s not in (None, '', 0, '0') else Decimal('1')
        dpx = Decimal(str(trigger_price)) if float(trigger_price or 0.0) > 0 else Decimal('0')

        need = dmin_qty
        if dmin_not > 0 and dpx > 0 and dcs > 0:
            need = max(need, (dmin_not / (dpx * dcs)))
        if need <= 0:
            need = dstep
        steps = (need / dstep).to_integral_value(rounding=ROUND_UP)
        return float((steps * dstep).quantize(dstep))
    except Exception:
        return 0.0


def _autotrade_build_tp_order_slices(symbol: str, tp_targets: list[float], base_qty: float, tp_fraction: float | None = None) -> list[dict]:
    """Build TP slices that satisfy Bybit qtyStep/minQty/minNotional constraints."""
    out: list[dict] = []
    try:
        sym = _bybit_linear_symbol(symbol)
        tp_targets = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or [])])
        total_qty = float(base_qty or 0.0)
        if not tp_targets or total_qty <= 0:
            return []

        if len(tp_targets) == 1:
            qty_i, qreason = _round_qty_down(sym, total_qty, tp_targets[0])
            if not qty_i or qty_i <= 0:
                return [{'idx': 1, 'tp': float(tp_targets[0]), 'qty': 0.0, 'ok': False, 'reason': str(qreason or 'qty_invalid')}]
            return [{'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(qty_i), 'ok': True, 'reason': ''}]

        tp_targets = list(tp_targets[:2])
        filt = _bybit_get_instr_filters(sym)
        step_s = filt.get('qtyStep')
        dstep = Decimal(str(step_s)) if step_s not in (None, '', 0, '0') else Decimal('0.00000001')
        if dstep <= 0:
            dstep = Decimal('0.00000001')
        dtotal_steps = (Decimal(str(total_qty)) / dstep).to_integral_value(rounding=ROUND_DOWN)
        if dtotal_steps <= 0:
            return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'reason': 'qty_rounds_to_0'}]

        min1 = Decimal(str(_autotrade_min_child_exit_qty(sym, tp_targets[0]) or 0.0))
        min2 = Decimal(str(_autotrade_min_child_exit_qty(sym, tp_targets[1]) or 0.0))
        min1_steps = (min1 / dstep).to_integral_value(rounding=ROUND_UP) if min1 > 0 else Decimal('1')
        min2_steps = (min2 / dstep).to_integral_value(rounding=ROUND_UP) if min2 > 0 else Decimal('1')

        if dtotal_steps < (min1_steps + min2_steps):
            short_qty = float(((min1_steps + min2_steps - dtotal_steps) * dstep).quantize(dstep))
            return [
                {'idx': 1, 'tp': float(tp_targets[0]), 'qty': 0.0, 'ok': False, 'reason': f'tp_child_qty_below_exchange_min(shortfall={short_qty:g})'},
                {'idx': 2, 'tp': float(tp_targets[1]), 'qty': 0.0, 'ok': False, 'reason': f'tp_child_qty_below_exchange_min(shortfall={short_qty:g})'},
            ]

        first = float(tp_fraction if tp_fraction is not None else AUTOTRADE_LIVE_TP_FRACTION)
        first = max(0.10, min(0.90, first))
        want1_steps = (Decimal(str(total_qty * first)) / dstep).to_integral_value(rounding=ROUND_DOWN)
        alloc1_steps = max(min1_steps, min(want1_steps, dtotal_steps - min2_steps))
        alloc2_steps = dtotal_steps - alloc1_steps

        q1 = float((alloc1_steps * dstep).quantize(dstep))
        q2 = float((alloc2_steps * dstep).quantize(dstep))
        q1, r1 = _round_qty_down(sym, q1, tp_targets[0])
        q2, r2 = _round_qty_down(sym, q2, tp_targets[1])
        if not q1 or q1 <= 0 or not q2 or q2 <= 0:
            return [
                {'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(q1 or 0.0), 'ok': bool(q1 and q1 > 0), 'reason': str(r1 or 'qty_invalid')},
                {'idx': 2, 'tp': float(tp_targets[1]), 'qty': float(q2 or 0.0), 'ok': bool(q2 and q2 > 0), 'reason': str(r2 or 'qty_invalid')},
            ]

        return [
            {'idx': 1, 'tp': float(tp_targets[0]), 'qty': float(q1), 'ok': True, 'reason': ''},
            {'idx': 2, 'tp': float(tp_targets[1]), 'qty': float(q2), 'ok': True, 'reason': ''},
        ]
    except Exception as e:
        return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'reason': f'{type(e).__name__}: {e}'}]


def _autotrade_place_reduce_only_tp_order_slice(symbol: str, side: str, idx: int, tp_price: float, qty_i: float) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        if side_u not in {'BUY', 'SELL'}:
            return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': 'bad_side'}
        tp_px = _round_price_to_tick(sym, float(tp_price or 0.0), rounding=ROUND_HALF_UP)
        if tp_px <= 0:
            tp_px = float(tp_price or 0.0)
        close_side = 'Sell' if side_u == 'BUY' else 'Buy'
        if _bybit_has_matching_tp_exit(sym, close_side.upper(), tp_px):
            return {'idx': int(idx or 0), 'tp': float(tp_px), 'qty': float(qty_i or 0.0), 'ok': True, 'retCode': 0, 'retMsg': 'already_present', 'existing': True}
        filt = _bybit_get_instr_filters(sym)
        qty_step = filt.get('qtyStep')
        trigger_direction = 1 if side_u == 'BUY' else 2
        link_id = f"pf_tp_{int(idx or 0)}_{sym}_{int(time.time()*1000)%100000000}_{uuid.uuid4().hex[:6]}"[:36]
        payload = {
            'category': 'linear',
            'symbol': sym,
            'side': close_side,
            'orderType': 'Market',
            'qty': _fmt_qty(float(qty_i or 0.0), qty_step),
            'triggerPrice': str(float(tp_px)),
            'triggerDirection': int(trigger_direction),
            'triggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
            'timeInForce': 'IOC',
            'reduceOnly': True,
            'closeOnTrigger': True,
            'positionIdx': 0,
            'orderLinkId': link_id,
        }
        res = _bybit_v5_request('POST', '/v5/order/create', payload)
        return {
            'idx': int(idx or 0),
            'tp': float(tp_px),
            'qty': float(qty_i or 0.0),
            'ok': int((res or {}).get('retCode', -1)) == 0,
            'retCode': (res or {}).get('retCode'),
            'retMsg': (res or {}).get('retMsg'),
            'order_payload': payload,
        }
    except Exception as e:
        return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}'}


def _autotrade_place_reduce_only_tp_orders(symbol: str, side: str, tp_targets: list[float], base_qty: float, tp_fraction: float | None = None) -> list[dict]:
    """Place exactly two native close-trigger TP orders, not book limit orders."""
    results = []
    try:
        slices = _autotrade_build_tp_order_slices(symbol, tp_targets, base_qty, tp_fraction=tp_fraction)
        for item in (slices or []):
            idx = int(item.get('idx') or 0)
            tp = float(item.get('tp') or 0.0)
            qty_i = float(item.get('qty') or 0.0)
            if not item.get('ok'):
                results.append({'idx': idx, 'tp': tp, 'qty': qty_i, 'ok': False, 'retMsg': str(item.get('reason') or 'qty_invalid')})
                continue
            results.append(_autotrade_place_reduce_only_tp_order_slice(symbol, side, idx, tp, qty_i))
        return results
    except Exception as e:
        return [{'idx': 0, 'tp': 0.0, 'qty': 0.0, 'ok': False, 'retMsg': f'{type(e).__name__}: {e}'}]


def _autotrade_confirm_tp_targets_present(symbol: str, side: str, tp_targets: list[float], wait_sec: float | None = None, step_sec: float | None = None) -> tuple[bool, list[float]]:
    want = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or []) if float(x or 0.0) > 0])
    if not want:
        return False, []
    deadline = time.time() + float(wait_sec if wait_sec is not None else AUTOTRADE_TP_CONFIRM_WAIT_SEC)
    step = max(0.10, float(step_sec if step_sec is not None else AUTOTRADE_TP_CONFIRM_STEP_SEC))
    missing = list(want)
    while True:
        try:
            missing = [px for px in want if not _bybit_has_open_tp_order_at(symbol, px, side=side)]
        except Exception:
            missing = list(want)
        if not missing:
            return True, []
        if time.time() >= deadline:
            return False, missing
        time.sleep(step)


def _autotrade_place_partial_tpsl_pair_slice(symbol: str, side: str, idx: int, tp_price: float, stop_loss: float, qty_i: float) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        if side_u not in {'BUY', 'SELL'}:
            return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': 'bad_side', 'placement': 'partial_pair'}
        tp_px = _round_price_to_tick(sym, float(tp_price or 0.0), rounding=ROUND_HALF_UP)
        sl_px = _round_price_to_tick(sym, float(stop_loss or 0.0), rounding=ROUND_HALF_UP)
        if tp_px <= 0 or sl_px <= 0:
            return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': 'bad_tp_or_sl', 'placement': 'partial_pair'}
        filt = _bybit_get_instr_filters(sym)
        qty_step = filt.get('qtyStep')
        payload = {
            'category': 'linear',
            'symbol': sym,
            'tpslMode': 'Partial',
            'positionIdx': 0,
            'takeProfit': str(float(tp_px)),
            'stopLoss': str(float(sl_px)),
            'tpTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
            'slTriggerBy': str(AUTOTRADE_LIVE_TP_TRIGGER_BY),
            'tpOrderType': 'Market',
            'slOrderType': 'Market',
            'tpSize': _fmt_qty(float(qty_i or 0.0), qty_step),
            'slSize': _fmt_qty(float(qty_i or 0.0), qty_step),
        }
        res = _bybit_v5_request('POST', '/v5/position/trading-stop', payload)
        ok = int((res or {}).get('retCode', -1)) == 0
        return {
            'idx': int(idx or 0),
            'tp': float(tp_px),
            'qty': float(qty_i or 0.0),
            'ok': bool(ok),
            'retCode': (res or {}).get('retCode'),
            'retMsg': (res or {}).get('retMsg'),
            'order_payload': payload,
            'placement': 'partial_pair',
        }
    except Exception as e:
        return {'idx': int(idx or 0), 'tp': float(tp_price or 0.0), 'qty': float(qty_i or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}', 'placement': 'partial_pair'}


def _autotrade_place_confirmed_tp_orders(symbol: str, side: str, tp_targets: list[float], base_qty: float, stop_loss: float, tp_fraction: float | None = None) -> list[dict]:
    """Attach exactly two visible exchange TP targets using native Partial TP/SL pairs.

    Bybit's full-position SL mode was intermittently coexisting without any visible TP attachments.
    The reliable path for the UI and the actual exchange state is to create two Partial TP/SL pairs,
    each with the same stop-loss and its own TP slice size.
    """
    results: list[dict] = []
    try:
        want = _dedupe_price_targets([float(x or 0.0) for x in (tp_targets or []) if float(x or 0.0) > 0])
        if len(want) != 2 or float(base_qty or 0.0) <= 0 or float(stop_loss or 0.0) <= 0:
            return [{'idx': 0, 'tp': 0.0, 'qty': float(base_qty or 0.0), 'ok': False, 'retMsg': 'invalid_tp_layout'}]

        slices = _autotrade_build_tp_order_slices(symbol, want, base_qty, tp_fraction=tp_fraction)
        good_slices = [x for x in (slices or []) if bool(x.get('ok')) and float(x.get('qty') or 0.0) > 0 and float(x.get('tp') or 0.0) > 0]
        if len(good_slices) != 2:
            bad_reason = '; '.join(str(x.get('reason') or 'qty_invalid') for x in (slices or [])) or 'qty_invalid'
            return [{'idx': 0, 'tp': 0.0, 'qty': float(base_qty or 0.0), 'ok': False, 'retMsg': f'invalid_tp_slices:{bad_reason}'}]

        _autotrade_cancel_reduce_only_tp_orders(symbol, side=side)
        _autotrade_clear_position_full_tp_sl(symbol)
        time.sleep(0.20)

        for item in good_slices:
            results.append(
                _autotrade_place_partial_tpsl_pair_slice(
                    symbol,
                    side,
                    int(item.get('idx') or 0),
                    float(item.get('tp') or 0.0),
                    float(stop_loss or 0.0),
                    float(item.get('qty') or 0.0),
                )
            )

        ok_tp, missing = _autotrade_confirm_tp_targets_present(symbol, side, want, wait_sec=max(AUTOTRADE_TP_CONFIRM_WAIT_SEC, 3.5), step_sec=AUTOTRADE_TP_CONFIRM_STEP_SEC)
        sl_ok = False
        try:
            sl_ok = _bybit_has_open_sl_order_at(symbol, float(stop_loss or 0.0), side=side)
            if not sl_ok:
                sl_qty = _bybit_sum_open_exit_qty_at(symbol, float(stop_loss or 0.0), side=side, kind='sl')
                sl_ok = bool(sl_qty >= max(0.0, float(base_qty or 0.0) * 0.90))
        except Exception:
            sl_ok = False
        if not sl_ok:
            try:
                sl_ok = bool(ok_tp and any(bool((x or {}).get('ok')) and str((x or {}).get('placement') or '') == 'partial_pair' for x in (results or [])))
            except Exception:
                sl_ok = False

        if (not ok_tp) and AUTOTRADE_TP_FALLBACK_TO_PARTIAL_TPSL:
            secondary = _autotrade_place_reduce_only_tp_orders(symbol, side, want, base_qty, tp_fraction=tp_fraction)
            results.extend(secondary or [])
            ok_tp, missing = _autotrade_confirm_tp_targets_present(symbol, side, want, wait_sec=max(AUTOTRADE_TP_CONFIRM_WAIT_SEC, 3.5), step_sec=AUTOTRADE_TP_CONFIRM_STEP_SEC)

        if (not ok_tp) or (not sl_ok):
            results.append({
                'idx': 0,
                'tp': 0.0,
                'qty': float(base_qty or 0.0),
                'ok': False,
                'retMsg': 'tp_or_sl_not_confirmed_on_exchange',
                'missing_targets': list(missing or []),
                'sl_ok': bool(sl_ok),
            })
        return results
    except Exception as e:
        return [{'idx': 0, 'tp': 0.0, 'qty': float(base_qty or 0.0), 'ok': False, 'retMsg': f'{type(e).__name__}: {e}'}]


def _autotrade_cancel_reduce_only_tp_orders(symbol: str, side: str | None = None, keep_stop_price: float | None = None) -> int:
    count = 0
    sym = _bybit_linear_symbol(symbol)
    close_side = ''
    side_u = str(side or '').upper().strip()
    if side_u == 'BUY':
        close_side = 'SELL'
    elif side_u == 'SELL':
        close_side = 'BUY'
    keep_sl = float(keep_stop_price or 0.0)
    for o in _bybit_get_open_orders_linear(sym):
        try:
            if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                continue
            if not _bybit_order_matches_close_side(o, close_side):
                continue
            if not _bybit_order_reduce_only(o):
                continue
            if not _bybit_order_active(o):
                continue
            px = _bybit_order_working_price(o)
            if keep_sl > 0 and _bybit_is_sl_exit_order(o) and _price_close_enough(px, keep_sl, rel_tol=0.0010):
                continue
            if not _bybit_is_tp_exit_order(o):
                continue
            oid = str(o.get('orderId') or '')
            if not oid:
                continue
            res = _bybit_v5_request('POST', '/v5/order/cancel', {'category': 'linear', 'symbol': sym, 'orderId': oid})
            if int((res or {}).get('retCode', -1)) == 0:
                count += 1
        except Exception:
            continue
    return count


def _autotrade_wait_live_position(symbol: str, side: str, wait_sec: float = 4.0, step_sec: float = 0.35):
    deadline = time.time() + max(0.2, float(wait_sec or 0.0))
    last_pos = None
    while time.time() < deadline:
        last_pos = _autotrade_find_live_position(symbol, side=side)
        if last_pos and abs(float(_pos_size(last_pos) or 0.0)) > 0:
            return last_pos
        time.sleep(max(0.05, float(step_sec or 0.2)))
    return last_pos


def _autotrade_wait_live_entry_confirmation(symbol: str, side: str, order_id: str = '', order_link_id: str = '', wait_sec: float = 9.0, step_sec: float = 0.4) -> dict:
    """Wait for position visibility, but fall back to order-state proof when Bybit lags."""
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    deadline = time.time() + max(0.5, float(wait_sec or 0.0))
    last_state = {}
    while time.time() < deadline:
        pos = _autotrade_find_live_position(sym, side=side_u)
        if pos and abs(float(_pos_size(pos) or 0.0)) > 0:
            return {
                'position': pos,
                'filled_confirmed': True,
                'filled_qty': abs(float(_pos_size(pos) or 0.0)),
                'avg_price': float(_pos_entry(pos) or 0.0),
                'reason': 'position_visible',
                'order_state': last_state,
            }
        state = _bybit_get_order_linear_state(sym, order_id=order_id, order_link_id=order_link_id)
        if state:
            last_state = state
            status = str((state or {}).get('orderStatus') or '').upper().strip()
            filled_qty = float(_bybit_order_filled_qty(state) or 0.0)
            if status in {'CANCELLED', 'REJECTED', 'DEACTIVATED'} and filled_qty <= 0:
                return {
                    'position': None,
                    'filled_confirmed': False,
                    'filled_qty': 0.0,
                    'avg_price': 0.0,
                    'reason': f'order_{status.lower()}',
                    'order_state': last_state,
                }
        time.sleep(max(0.05, float(step_sec or 0.2)))

    filled_qty = float(_bybit_order_filled_qty(last_state) or 0.0)
    status = str((last_state or {}).get('orderStatus') or '').upper().strip()
    return {
        'position': None,
        'filled_confirmed': bool(filled_qty > 0 and status in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED'}),
        'filled_qty': filled_qty,
        'avg_price': float(_bybit_order_avg_price(last_state) or 0.0),
        'reason': ('fill_confirmed_visibility_pending' if (filled_qty > 0 and status in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED'}) else ('order_status_' + status.lower() if status else 'live_entry_fill_not_confirmed')),
        'order_state': last_state,
    }


def _autotrade_force_close_live_position(symbol: str, side: str, qty: float | None = None) -> dict:
    try:
        sym = _bybit_linear_symbol(symbol)
        side_u = str(side or '').upper().strip()
        if side_u not in {'BUY', 'SELL'}:
            return {'retCode': -1, 'retMsg': 'bad_side'}
        live_pos = _autotrade_find_live_position(sym, side=side_u)
        live_qty = abs(float(qty or (_pos_size(live_pos) if live_pos else 0.0) or 0.0))
        if live_qty <= 0:
            return {'retCode': 0, 'retMsg': 'no_live_qty'}
        qty_i, qreason = _round_qty_down(sym, live_qty, float(_pos_entry(live_pos) if live_pos else 0.0))
        if not qty_i or qty_i <= 0:
            return {'retCode': -1, 'retMsg': f'close_qty_invalid:{qreason}'}
        filt = _bybit_get_instr_filters(sym)
        payload = {
            'category': 'linear',
            'symbol': sym,
            'side': 'Sell' if side_u == 'BUY' else 'Buy',
            'orderType': 'Market',
            'qty': _fmt_qty(qty_i, filt.get('qtyStep')),
            'timeInForce': 'IOC',
            'reduceOnly': True,
            'positionIdx': 0,
            'orderLinkId': f"pf_fc_{sym}_{int(time.time()*1000)%100000000}_{uuid.uuid4().hex[:6]}"[:36],
        }
        return _bybit_v5_request('POST', '/v5/order/create', payload)
    except Exception as e:
        return {'retCode': -1, 'retMsg': f'{type(e).__name__}: {e}'}


def _autotrade_apply_position_tp_sl(symbol: str, stop_loss: float, take_profit: float) -> dict:
    payload = {
        'category': 'linear',
        'symbol': _bybit_linear_symbol(symbol),
        'stopLoss': str(float(stop_loss or 0.0)) if float(stop_loss or 0.0) > 0 else '0',
        'tpslMode': 'Full',
        'positionIdx': 0,
    }
    if float(take_profit or 0.0) > 0:
        payload['takeProfit'] = str(float(take_profit))
    return _bybit_v5_request('POST', '/v5/position/trading-stop', payload)


def _autotrade_clear_position_full_tp_sl(symbol: str) -> dict:
    try:
        payload = {
            'category': 'linear',
            'symbol': _bybit_linear_symbol(symbol),
            'takeProfit': '0',
            'stopLoss': '0',
            'tpslMode': 'Full',
            'positionIdx': 0,
        }
        return _bybit_v5_request('POST', '/v5/position/trading-stop', payload)
    except Exception as e:
        return {'retCode': -1, 'retMsg': f'{type(e).__name__}: {e}'}


def _autotrade_repair_live_exit_protection(uid: int, trade_row: dict, live_pos: dict | None = None) -> dict:
    result = {'checked': False, 'sl_fixed': False, 'tp_fixed': False, 'tp_order_fixed': False, 'be_applied': False, 'symbol': '', 'side': ''}
    try:
        if str(AUTOTRADE_MODE).lower() != 'live':
            return result
        if not trade_row:
            return result
        sym = _bybit_linear_symbol(str(trade_row.get('symbol') or ''))
        side = str(trade_row.get('side') or '').upper().strip()
        result['symbol'] = sym
        result['side'] = side
        if side not in {'BUY', 'SELL'} or not sym:
            return result
        pos = live_pos or _autotrade_find_live_position(sym, side=side)
        if not pos:
            return result
        result['checked'] = True

        entry = float(_pos_entry(pos) or trade_row.get('entry') or 0.0)
        target_sl = float(trade_row.get('sl') or 0.0)
        target_tp = _resolve_single_tp(entry, target_sl, trade_row.get('tp'), trade_row.get('alt_target_a'), trade_row.get('alt_target_b'), side)

        current_sl = float(_pos_stop(pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0)
        current_tp = float(_pos_take_profit(pos) or 0.0)

        sl_ok = bool(target_sl > 0 and current_sl > 0 and _price_close_enough(current_sl, target_sl, rel_tol=0.0020))
        tp_ok = bool(target_tp > 0 and current_tp > 0 and _price_close_enough(current_tp, target_tp, rel_tol=0.0020))

        if not (sl_ok and tp_ok):
            last_res = _autotrade_apply_position_tp_sl(sym, target_sl, target_tp)
            time.sleep(0.35)
            pos = _autotrade_find_live_position(sym, side=side) or pos
            current_sl = float(_pos_stop(pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0)
            current_tp = float(_pos_take_profit(pos) or 0.0)
            sl_ok = bool(target_sl > 0 and current_sl > 0 and _price_close_enough(current_sl, target_sl, rel_tol=0.0020))
            tp_ok = bool(target_tp > 0 and current_tp > 0 and _price_close_enough(current_tp, target_tp, rel_tol=0.0020))
            result['sl_apply_res'] = last_res

        result['sl_fixed'] = bool(sl_ok)
        result['tp_fixed'] = bool(tp_ok)
        result['pending_missing'] = [name for name, flag in (('SL', not sl_ok), ('TP', not tp_ok)) if bool(flag)]
        return result
    except Exception:
        return result
        if not trade_row:
            return result
        sym = _bybit_linear_symbol(str(trade_row.get('symbol') or ''))
        side = str(trade_row.get('side') or '').upper().strip()
        result['symbol'] = sym
        result['side'] = side
        if side not in {'BUY', 'SELL'} or not sym:
            return result
        pos = live_pos or _autotrade_find_live_position(sym, side=side)
        if not pos:
            return result
        result['checked'] = True

        plan = _autotrade_live_exit_plan_for_trade(trade_row)
        partial_tp = float(plan.get('partial_tp') or 0.0)
        entry = float(_pos_entry(pos) or trade_row.get('entry') or 0.0)
        current_sl = float(_pos_stop(pos) or 0.0)
        target_sl = float(trade_row.get('sl') or 0.0)
        initial_qty = abs(float(trade_row.get('qty') or 0.0))
        live_qty = abs(float(_pos_size(pos) or 0.0))

        lifecycle_row = {}
        try:
            ident = str(trade_row.get('trade_id') or trade_row.get('setup_id') or '').strip()
            if ident:
                lifecycle_row = _trade_lifecycle_detail_row(int(uid), ident, sync=False) or {}
        except Exception:
            lifecycle_row = {}

        tp_hit = bool(float((lifecycle_row or {}).get('tp_hit_ts') or 0.0) > 0.0)
        be_allowed = bool(tp_hit)
        if entry > 0 and initial_qty > 0 and live_qty > 0 and not tp_hit:
            partial_fraction = float(plan.get('partial_fraction') or AUTOTRADE_LIVE_TP_FRACTION)
            qty_drop_threshold = max(initial_qty * 0.45, initial_qty * (1.0 - partial_fraction + 0.08))
            qty_reduced = live_qty < max(initial_qty * 0.98, initial_qty - max(1e-9, initial_qty * 0.02))
            tp_order_still_open = False
            try:
                tp_order_still_open = _bybit_has_open_tp_order_at(sym, partial_tp, side=side) if partial_tp > 0 else False
            except Exception:
                tp_order_still_open = False
            current_sl_is_be = bool(entry > 0 and current_sl > 0 and _trade_lifecycle_is_be_or_better(side, current_sl, entry))
            tp_hit = bool((live_qty <= qty_drop_threshold) or (qty_reduced and not tp_order_still_open) or current_sl_is_be)
            be_allowed = bool(tp_hit)

        desired_sl = float(entry) if (tp_hit and be_allowed and entry > 0) else float(target_sl)
        effective_sl = 0.0
        has_partial_sl = False
        try:
            effective_sl = float(_bybit_detect_open_sl_price(sym, side=side) or 0.0)
        except Exception:
            effective_sl = 0.0
        try:
            has_partial_sl = _bybit_has_open_sl_order_at(sym, desired_sl, side=side) if desired_sl > 0 else False
        except Exception:
            has_partial_sl = False
        current_or_detected_sl = float(current_sl or effective_sl or 0.0)
        current_sl_is_be = bool(entry > 0 and current_or_detected_sl > 0 and _trade_lifecycle_is_be_or_better(side, current_or_detected_sl, entry))
        has_any_real_sl = bool((current_sl > 0) or (effective_sl > 0) or has_partial_sl)
        sl_matches_target = bool(
            desired_sl > 0 and (
                (current_sl > 0 and _price_close_enough(current_sl, desired_sl))
                or (effective_sl > 0 and _price_close_enough(effective_sl, desired_sl))
                or has_partial_sl
                or (tp_hit and desired_sl == float(entry) and current_sl_is_be)
            )
        )

        need_sl_rebuild = bool(desired_sl > 0 and (not has_any_real_sl or not sl_matches_target))
        if need_sl_rebuild:
            last_sl_res = {}
            for _ in range(2):
                last_sl_res = _autotrade_apply_position_tp_sl(sym, desired_sl, 0.0)
                time.sleep(0.25)
                refreshed_pos = _autotrade_find_live_position(sym, side=side) or pos
                refreshed_sl = float(_pos_stop(refreshed_pos) or 0.0) if refreshed_pos else 0.0
                if refreshed_sl <= 0:
                    try:
                        refreshed_sl = float(_bybit_detect_open_sl_price(sym, side=side) or 0.0)
                    except Exception:
                        refreshed_sl = 0.0
                sl_ok = bool(refreshed_sl > 0 and (_price_close_enough(refreshed_sl, desired_sl) or (tp_hit and desired_sl == float(entry) and _trade_lifecycle_is_be_or_better(side, refreshed_sl, entry))))
                if sl_ok:
                    result['sl_fixed'] = True
                    need_sl_rebuild = False
                    if tp_hit and desired_sl == float(entry):
                        result['be_applied'] = True
                    break
            if need_sl_rebuild:
                result['sl_apply_res'] = last_sl_res
        elif tp_hit and desired_sl == float(entry) and current_sl_is_be:
            result['be_applied'] = True

        desired_targets = _dedupe_price_targets([
            float(trade_row.get('alt_target_a') or 0.0),
            float(trade_row.get('alt_target_b') or 0.0),
        ]) if tp_hit else _dedupe_price_targets([
            float(partial_tp or 0.0),
            float(trade_row.get('alt_target_a') or 0.0),
            float(trade_row.get('alt_target_b') or 0.0),
        ])

        need_tp_rebuild = False
        missing_target_prices = []
        if desired_targets and live_qty > 0:
            target_slices = _autotrade_build_tp_order_slices(
                sym,
                desired_targets,
                live_qty,
                tp_fraction=float(plan.get('partial_fraction') or AUTOTRADE_LIVE_TP_FRACTION),
            )
            for item in (target_slices or []):
                try:
                    if not bool(item.get('ok')):
                        continue
                    tp_px = float(item.get('tp') or 0.0)
                    if tp_px > 0 and not _bybit_has_open_tp_order_at(sym, tp_px, side=side):
                        missing_target_prices.append(tp_px)
                except Exception:
                    continue
            need_tp_rebuild = bool(missing_target_prices)

        if (need_sl_rebuild or need_tp_rebuild) and live_qty > 0:
            try:
                _autotrade_cancel_reduce_only_tp_orders(sym, side=side)
            except Exception:
                pass
            try:
                _autotrade_clear_position_full_tp_sl(sym)
            except Exception:
                pass
            time.sleep(0.30)

            tp_results = []
            missing_after_repair = []
            if desired_targets:
                tp_results = _autotrade_place_confirmed_tp_orders(
                    sym,
                    side,
                    desired_targets,
                    live_qty,
                    desired_sl if float(desired_sl or 0.0) > 0 else float(target_sl or 0.0),
                    tp_fraction=float(plan.get('partial_fraction') or AUTOTRADE_LIVE_TP_FRACTION),
                )
                ok_after_repair, missing_after_repair = _autotrade_confirm_tp_targets_present(
                    sym, side, desired_targets,
                    wait_sec=max(AUTOTRADE_TP_CONFIRM_WAIT_SEC, 3.5),
                    step_sec=AUTOTRADE_TP_CONFIRM_STEP_SEC,
                )
                result['tp_fixed'] = bool(ok_after_repair)
                if tp_hit and ok_after_repair:
                    result['tp_order_fixed'] = True
            result['missing_tp_after_repair'] = list(missing_after_repair or [])
            result['tp_order_results'] = tp_results

            if desired_sl > 0:
                last_sl_res = _autotrade_apply_position_tp_sl(sym, desired_sl, 0.0)
                time.sleep(0.25)
                refreshed_pos = _autotrade_find_live_position(sym, side=side) or pos
                refreshed_sl = float(_pos_stop(refreshed_pos) or 0.0) if refreshed_pos else 0.0
                if refreshed_sl <= 0:
                    try:
                        refreshed_sl = float(_bybit_detect_open_sl_price(sym, side=side) or 0.0)
                    except Exception:
                        refreshed_sl = 0.0
                sl_ok = bool(refreshed_sl > 0 and (_price_close_enough(refreshed_sl, desired_sl) or (tp_hit and desired_sl == float(entry) and _trade_lifecycle_is_be_or_better(side, refreshed_sl, entry))))
                if sl_ok:
                    result['sl_fixed'] = True
                    if tp_hit and desired_sl == float(entry):
                        result['be_applied'] = True
                else:
                    result['sl_apply_res'] = last_sl_res

        try:
            final_pos = _autotrade_find_live_position(sym, side=side) or pos
            snap = _autotrade_live_position_status(int(uid), final_pos, trade_row=trade_row) if final_pos else {}
            result['pending_missing'] = [name for name, flag in (('SL', snap.get('missing_sl')), ('TP', snap.get('missing_tp') or snap.get('missing_tp'))) if bool(flag)]
            if tp_hit and bool(snap.get('be_active')):
                result['be_applied'] = True
        except Exception:
            pass
        return result
    except Exception:
        return result

def _ts_seconds_from_any(value) -> float:
    try:
        if value in (None, "", 0, "0"):
            return 0.0
        v = float(value)
        if v <= 0:
            return 0.0
        return (v / 1000.0) if v > 10_000_000_000 else v
    except Exception:
        return 0.0


def _bybit_order_reduce_only(order: dict) -> bool:
    try:
        for key in ('reduceOnly', 'reduce_only', 'closeOnTrigger', 'close_on_trigger'):
            val = order.get(key)
            if isinstance(val, bool) and val:
                return True
            sval = str(val or '').strip().lower()
            if sval in {'true', '1', 'yes', 'y'}:
                return True
    except Exception:
        pass
    return False


def _bybit_order_filled_time_ts(order: dict) -> float:
    try:
        for key in ('updatedTime', 'updated_time', 'createdTime', 'created_time', 'orderTime', 'execTime', 'transactTime'):
            ts = _ts_seconds_from_any(order.get(key))
            if ts > 0:
                return ts
    except Exception:
        pass
    return 0.0


def _bybit_order_avg_price(order: dict) -> float:
    try:
        for key in ('avgPrice', 'avg_price', 'price', 'triggerPrice', 'trigger_price'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _bybit_order_filled_qty(order: dict) -> float:
    try:
        for key in ('cumExecQty', 'cum_exec_qty', 'cumFilledQty', 'filledQty', 'qty'):
            v = float(order.get(key) or 0.0)
            if v > 0:
                return abs(v)
    except Exception:
        pass
    return 0.0


def _bybit_get_recent_filled_orders_linear(symbol: str, lookback_hours: int = 168, limit: int = 200) -> list[dict]:
    """Recent filled order history for one linear symbol.

    We use this for live-position attribution only. The result is cached briefly because
    /status and /autotrade_debug may be called back-to-back.
    """
    sym = _bybit_linear_symbol(symbol)
    cache_key = f"bybit_order_history:{sym}:{int(lookback_hours)}:{int(limit)}"
    try:
        if cache_valid(cache_key, 30):
            return list(cache_get(cache_key) or [])
    except Exception:
        pass

    end_ms = int(time.time() * 1000)
    start_ms = int((time.time() - max(1, int(lookback_hours)) * 3600.0) * 1000)
    payload = {
        'category': 'linear',
        'symbol': sym,
        'startTime': start_ms,
        'endTime': end_ms,
        'limit': int(max(20, min(int(limit), 200))),
    }
    out = []
    try:
        res = _bybit_v5_request('GET', '/v5/order/history', payload)
        if int((res or {}).get('retCode', -1)) == 0:
            out = (((res or {}).get('result') or {}).get('list') or [])
    except Exception:
        out = []

    try:
        cache_set(cache_key, list(out or []))
    except Exception:
        pass
    return list(out or [])


def _autotrade_resolve_live_position_open_info(uid: int, p: dict, journal_open: Optional[list[dict]] = None) -> dict:
    """Resolve the authoritative open timestamp for one live Bybit position.

    Evidence priority:
    1) Matching autotrade journal OPEN row (authoritative for the bot's anchored trading-day accounting).
    2) Bybit filled order history for the same symbol/side and same-position characteristics.
    3) Bybit live position createdTime.

    Why journal-first:
    - Bybit aggregate positions can be updated or scaled in later, which can make exchange-side
      timestamps look newer than the real open for today's /dayreset bucket.
    - The bot's own open-trade journal is the most reliable source for deciding whether a live
      position is carried from a prior anchored day or opened today.
    """
    sym = _pos_symbol(p)
    side = _pos_side_text(p)
    entry = float(_pos_entry(p) or 0.0)
    size = abs(float(_pos_size(p) or 0.0))
    position_created_ts = _ts_seconds_from_any(p.get('createdTime') or p.get('created_time'))
    position_updated_ts = _ts_seconds_from_any(p.get('updatedTime') or p.get('updated_time'))

    info = {
        'symbol': sym,
        'side': side,
        'opened_ts': 0.0,
        'source': 'unknown',
        'position_created_ts': float(position_created_ts or 0.0),
        'position_updated_ts': float(position_updated_ts or 0.0),
        'journal_ts': 0.0,
        'journal_trade_id': '',
        'exchange_order_ts': 0.0,
        'exchange_order_id': '',
        'exchange_order_price': 0.0,
        'exchange_order_qty': 0.0,
        'notes': '',
    }

    def _entry_rel_diff(a: float, b: float) -> float:
        try:
            a = float(a or 0.0)
            b = float(b or 0.0)
            if a <= 0 or b <= 0:
                return 999.0
            return abs(a - b) / max(abs(a), abs(b), 1e-9)
        except Exception:
            return 999.0

    def _qty_rel_diff(a: float, b: float) -> float:
        try:
            a = abs(float(a or 0.0))
            b = abs(float(b or 0.0))
            if a <= 0 or b <= 0:
                return 999.0
            return abs(a - b) / max(a, b, 1e-9)
        except Exception:
            return 999.0

    journal_matches = []
    for t in (journal_open or []):
        try:
            if str(t.get('symbol') or '').upper() != str(sym).upper():
                continue
            if str(t.get('side') or '').upper() != str(side).upper():
                continue
            j_entry = float(t.get('entry') or 0.0)
            j_qty = abs(float(t.get('qty') or 0.0))
            entry_rel = _entry_rel_diff(j_entry, entry)
            qty_rel = _qty_rel_diff(j_qty, size)
            if entry_rel <= 0.0075 or qty_rel <= 0.35:
                journal_matches.append((entry_rel, qty_rel, -float(t.get('opened_ts') or 0.0), t))
        except Exception:
            continue
    if journal_matches:
        best_journal = sorted(journal_matches, key=lambda x: (x[0], x[1], x[2]))[0][3]
        try:
            info['journal_ts'] = float(best_journal.get('opened_ts') or 0.0)
            info['journal_trade_id'] = str(best_journal.get('trade_id') or '')
        except Exception:
            pass

    order_candidates = []
    try:
        for o in _bybit_get_recent_filled_orders_linear(sym, lookback_hours=168, limit=200):
            try:
                if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                    continue
                o_side = str(o.get('side') or '').upper().strip()
                if o_side != side:
                    continue
                if _bybit_order_reduce_only(o):
                    continue
                o_status = str(o.get('orderStatus') or '').upper().strip()
                o_qty = _bybit_order_filled_qty(o)
                if o_status not in {'FILLED', 'PARTIALLYFILLED', 'PARTIALLY_FILLED', ''} and o_qty <= 0:
                    continue
                ts = _bybit_order_filled_time_ts(o)
                if ts <= 0:
                    continue
                o_price = _bybit_order_avg_price(o)
                entry_rel = _entry_rel_diff(o_price, entry)
                qty_rel = _qty_rel_diff(o_qty, size)
                if entry_rel <= 0.0075 or qty_rel <= 0.35:
                    order_candidates.append((entry_rel, qty_rel, ts, o))
            except Exception:
                continue
    except Exception:
        order_candidates = []

    if order_candidates:
        best_entry_rel = min(x[0] for x in order_candidates)
        shortlist = [x for x in order_candidates if x[0] <= max(best_entry_rel + 0.0015, 0.0080)]
        best_order = sorted(shortlist, key=lambda x: (x[2], x[0], x[1]))[0][3]
        info['exchange_order_ts'] = _bybit_order_filled_time_ts(best_order)
        info['exchange_order_id'] = str(best_order.get('orderId') or best_order.get('orderLinkId') or '')
        info['exchange_order_price'] = float(_bybit_order_avg_price(best_order) or 0.0)
        info['exchange_order_qty'] = float(_bybit_order_filled_qty(best_order) or 0.0)

    exchange_ts = float(info.get('exchange_order_ts') or 0.0)
    journal_ts = float(info.get('journal_ts') or 0.0)
    created_ts = float(info.get('position_created_ts') or 0.0)

    if journal_ts > 0:
        info['opened_ts'] = journal_ts
        info['source'] = 'autotrade_journal'
        if exchange_ts > 0 and abs(exchange_ts - journal_ts) > 3600.0:
            info['notes'] = 'exchange_ts_ignored_for_day_bucket'
    elif exchange_ts > 0:
        info['opened_ts'] = exchange_ts
        info['source'] = 'bybit_order_history'
    elif created_ts > 0:
        info['opened_ts'] = created_ts
        info['source'] = 'bybit_position_created'
    else:
        info['opened_ts'] = 0.0
        info['source'] = 'unknown'

    return info


def _autotrade_realized_pnl_today(uid: int, now_utc: Optional[datetime] = None) -> float:
    """Realized PnL for autotrade journal rows closed inside the active trading-day window."""
    try:
        user = _autotrade_user_settings(int(uid))
        start_utc, end_utc = _admin_today_window_utc(now_utc, uid=int(uid), user=user)
        start_ts = int(start_utc.timestamp())
        end_ts = int(end_utc.timestamp())
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "SELECT COALESCE(SUM(pnl_usdt), 0) FROM autotrade_trades WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?",
                (int(uid), start_ts, end_ts),
            )
            row = cur.fetchone()
            return float((row[0] if row else 0.0) or 0.0)
    except Exception:
        return 0.0




def _bybit_closed_pnl_event_ts(row: dict) -> float:
    try:
        for key in ('updatedTime', 'updated_time', 'createdTime', 'created_time', 'execTime', 'fillTime'):
            ts = _ts_seconds_from_any((row or {}).get(key))
            if ts > 0:
                return ts
    except Exception:
        pass
    return 0.0


def _bybit_closed_pnl_event_qty(row: dict) -> float:
    try:
        for key in ('closedSize', 'closed_size', 'qty', 'size', 'closedQty', 'execQty'):
            v = float((row or {}).get(key) or 0.0)
            if v > 0:
                return abs(v)
    except Exception:
        pass
    return 0.0


def _opposite_side_text(side: str) -> str:
    s = str(side or '').upper().strip()
    if s == 'BUY':
        return 'SELL'
    if s == 'SELL':
        return 'BUY'
    return s


def _bybit_closed_pnl_event_side_candidates(row: dict) -> set[str]:
    """Return possible open-side labels that may correspond to a closed-pnl row.

    Bybit payloads are inconsistent across endpoints / environments: some rows expose the
    original position side, while others can look like the closing execution side. We accept
    both the raw side and its opposite when reconciling journal rows so close-sync and
    performance reporting remain robust.
    """
    raw = str((row or {}).get('side') or '').upper().strip()
    out = set()
    if raw:
        out.add(raw)
        opp = _opposite_side_text(raw)
        if opp:
            out.add(opp)
    return out or {'BUY', 'SELL'}


def _bybit_get_closed_pnl_linear(start_ts: float, end_ts: float, symbol: str | None = None, limit: int = 200) -> list[dict]:
    """Fetch Bybit closed-PnL rows for the requested window.

    Best-effort pagination is used because the exchange may return a cursor.
    """
    if str(AUTOTRADE_MODE).lower() != 'live' or not BYBIT_API_KEY or not BYBIT_API_SECRET:
        return []
    start_ms = int(max(0.0, float(start_ts or 0.0)) * 1000)
    end_ms = int(max(float(end_ts or 0.0), float(start_ts or 0.0)) * 1000)
    sym = _bybit_linear_symbol(symbol) if symbol else None
    out = []
    cursor = None
    seen = set()
    for _ in range(8):
        payload = {
            'category': 'linear',
            'startTime': start_ms,
            'endTime': end_ms,
            'limit': int(max(20, min(int(limit or 200), 200))),
        }
        if sym:
            payload['symbol'] = sym
        if cursor:
            payload['cursor'] = cursor
        try:
            res = _bybit_v5_request('GET', '/v5/position/closed-pnl', payload)
            if int((res or {}).get('retCode', -1)) != 0:
                break
            result = (res or {}).get('result') or {}
            rows = result.get('list') or []
            if not rows:
                break
            added = 0
            for r in rows:
                try:
                    key = (
                        _bybit_linear_symbol(str((r or {}).get('symbol') or '')),
                        str((r or {}).get('side') or '').upper().strip(),
                        int(_bybit_closed_pnl_event_ts(r) or 0),
                        str((r or {}).get('orderId') or (r or {}).get('execId') or ''),
                        float((r or {}).get('closedPnl') or 0.0),
                    )
                    if key in seen:
                        continue
                    seen.add(key)
                    out.append(r)
                    added += 1
                except Exception:
                    continue
            cursor = str(result.get('nextPageCursor') or result.get('nextPageToken') or '').strip()
            if not cursor or added <= 0:
                break
        except Exception:
            break
    return list(out)


def _bybit_closed_pnl_summary(start_ts: float, end_ts: float, symbol: str | None = None) -> dict:
    """Summarize Bybit closed-PnL rows inside a UTC window.

    Returns exchange-truth totals for the anchored trading day so /status and
    /autotrade_debug can reflect live realized results even before journal
    reconciliation finishes.
    """
    rows = _bybit_get_closed_pnl_linear(start_ts, end_ts, symbol=symbol, limit=200) or []
    net_pnl = 0.0
    realized_loss = 0.0
    count = 0
    normalized_rows = []
    for r in rows:
        try:
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            if ts <= 0 or ts < float(start_ts) or ts >= float(end_ts):
                continue
            pnl = float((r or {}).get('closedPnl') or (r or {}).get('closed_pnl') or 0.0)
            net_pnl += pnl
            if pnl < 0:
                realized_loss += abs(pnl)
            count += 1
            normalized_rows.append(r)
        except Exception:
            continue
    return {
        'rows': normalized_rows,
        'count': int(count),
        'net_pnl': float(net_pnl),
        'realized_loss': float(realized_loss),
    }


def _autotrade_db_close_trade(trade_id: str, closed_ts: float, pnl_usdt: float, outcome: str, note_append: str = '') -> None:
    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            row = cur.execute("SELECT note, symbol, side FROM autotrade_trades WHERE trade_id=?", (str(trade_id),)).fetchone()
            old_note = str((row[0] if row else '') or '')
            old_symbol = str((row[1] if row else '') or '')
            old_side = str((row[2] if row else '') or '')
            note_parts = [old_note.strip()] if old_note and old_note.strip() else []
            extra = str(note_append or '').strip()
            if extra and extra not in note_parts:
                note_parts.append(extra)
            merged_note = ' | '.join([x for x in note_parts if x])
            cur.execute(
                """UPDATE autotrade_trades
                   SET status='CLOSED', closed_ts=?, pnl_usdt=?, outcome=?, note=?
                   WHERE trade_id=?""",
                (int(float(closed_ts or 0.0)), float(pnl_usdt or 0.0), str(outcome or '').upper().strip(), merged_note, str(trade_id)),
            )
            conn.commit()
            try:
                life = cur.execute("SELECT setup_id FROM admin_setup_lifecycle WHERE trade_id=? LIMIT 1", (str(trade_id),)).fetchone()
                sid = str((life[0] if life else '') or '')
            except Exception:
                sid = ''
        if sid:
            _admin_setup_lifecycle_merge(
                int(AUTOTRADE_OWNER_UID or 0), sid,
                symbol=old_symbol,
                side=old_side,
                closed_ts=float(closed_ts or 0.0),
                state='closed',
                outcome=str(outcome or '').upper().strip(),
                pnl_usdt=float(pnl_usdt or 0.0),
                last_reason=str(note_append or ''),
            )
    except Exception:
        pass


def _autotrade_sync_closed_trades_from_exchange(uid: int, now_utc: Optional[datetime] = None, lookback_days: int = 14) -> dict:
    """Reconcile OPEN journal rows against live Bybit state and closed-PnL history.

    This is the missing link between live exchange closures and the bot's day accounting.
    Without this sync, /status and /autotrade_debug can only see still-open positions plus
    whatever was manually written into autotrade_trades.
    """
    summary = {'checked': 0, 'closed': 0, 'matched_events': 0}
    if str(AUTOTRADE_MODE).lower() != 'live':
        return summary
    try:
        open_rows = _autotrade_db_open_trades(int(uid)) or []
    except Exception:
        open_rows = []
    if not open_rows:
        return summary

    try:
        live_positions = _bybit_get_open_positions_linear() or []
    except Exception:
        live_positions = []
    live_keys = {
        (str(_pos_symbol(p) or '').upper(), str(_pos_side_text(p) or '').upper())
        for p in (live_positions or [])
    }

    now_ts = float((now_utc or datetime.now(timezone.utc)).astimezone(timezone.utc).timestamp())
    min_open_ts = min(float(t.get('opened_ts') or now_ts) for t in open_rows) if open_rows else now_ts
    start_ts = max(0.0, min(min_open_ts, now_ts) - 86400.0 * max(1, int(lookback_days)))
    closed_rows = _bybit_get_closed_pnl_linear(start_ts, now_ts, limit=200)

    event_pool: dict[tuple[str, str], list[dict]] = defaultdict(list)
    for r in (closed_rows or []):
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            if not sym:
                continue
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            if ts <= 0:
                continue
            pnl = float((r or {}).get('closedPnl') or 0.0)
            qty = float(_bybit_closed_pnl_event_qty(r) or 0.0)
            event = {
                'ts': ts,
                'pnl': pnl,
                'qty': qty,
                'raw': r,
                'used': False,
            }
            for side in _bybit_closed_pnl_event_side_candidates(r):
                event_pool[(sym, side)].append(event)
        except Exception:
            continue
    for key in list(event_pool.keys()):
        event_pool[key].sort(key=lambda x: (float(x.get('ts') or 0.0), float(x.get('qty') or 0.0)))

    rows_by_key: dict[tuple[str, str], list[dict]] = defaultdict(list)
    for t in open_rows:
        try:
            key = (str(t.get('symbol') or '').upper(), str(t.get('side') or '').upper())
            rows_by_key[key].append(t)
        except Exception:
            continue
    for key in list(rows_by_key.keys()):
        rows_by_key[key].sort(key=lambda x: float(x.get('opened_ts') or 0.0))

    for key, trades in rows_by_key.items():
        events = event_pool.get(key) or []
        for idx, trade in enumerate(trades):
            summary['checked'] += 1
            sym, side = key
            if key in live_keys:
                continue
            trade_id = str(trade.get('trade_id') or '')
            opened_ts = float(trade.get('opened_ts') or 0.0)
            trade_qty = abs(float(trade.get('qty') or 0.0))
            next_open_ts = None
            for later in trades[idx + 1:]:
                later_ts = float(later.get('opened_ts') or 0.0)
                if later_ts > opened_ts:
                    next_open_ts = later_ts
                    break

            candidates = []
            for ev in events:
                if ev.get('used'):
                    continue
                ev_ts = float(ev.get('ts') or 0.0)
                if ev_ts <= 0 or ev_ts + 300.0 < opened_ts:
                    continue
                if next_open_ts and ev_ts >= next_open_ts:
                    continue
                candidates.append(ev)
            if not candidates:
                continue

            matched = []
            matched_qty = 0.0
            matched_pnl = 0.0
            for ev in candidates:
                matched.append(ev)
                matched_pnl += float(ev.get('pnl') or 0.0)
                matched_qty += abs(float(ev.get('qty') or 0.0))
                if trade_qty > 0 and matched_qty > 0 and matched_qty >= trade_qty * 0.80:
                    break
                if trade_qty <= 0:
                    break
            if not matched:
                continue

            close_ts = max(float(ev.get('ts') or 0.0) for ev in matched)
            for ev in matched:
                ev['used'] = True
            outcome = 'BREAKEVEN'
            if matched_pnl > 0:
                outcome = 'WIN'
            elif matched_pnl < 0:
                outcome = 'LOSS'
            note_bits = ['exchange_close_sync']
            if len(matched) > 1:
                note_bits.append(f'partial_close_events={len(matched)}')
            _autotrade_db_close_trade(trade_id, close_ts, matched_pnl, outcome, ' | '.join(note_bits))
            summary['closed'] += 1
            summary['matched_events'] += len(matched)
    return summary


def _autotrade_trade_day_label(ts: float, user: dict) -> str:
    try:
        dt_local = datetime.fromtimestamp(float(ts), _user_tzinfo(user))
        start_local, _ = _anchored_day_window(dt_local, _user_day_reset_hhmm(user))
        return start_local.strftime('%Y-%m-%d')
    except Exception:
        return ''




def _autotrade_reconstruct_provisional_closes(uid: int, days: int = 7) -> list[dict]:
    """Conservative admin-history fallback for older deployments.

    Uses historical setup identity + exchange closed-PnL events when older journal rows are
    missing. This is only used to avoid a useless all-zero performance report after upgrades.
    It never overrides journal-confirmed bot trades.
    """
    if str(AUTOTRADE_MODE).lower() != 'live':
        return []
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    tz = _user_tzinfo(user)
    start_local, end_local = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    end_ts = float(end_local.astimezone(timezone.utc).timestamp())

    try:
        journal_trades = db_list_autotrade_trades_all(int(uid)) or []
    except Exception:
        journal_trades = []

    closed_rows = _bybit_get_closed_pnl_linear(max(0.0, start_ts - 86400.0 * 5.0), end_ts, limit=300) or []
    if not closed_rows:
        return []

    journal_event_keys = set()
    for t in journal_trades:
        try:
            if float(t.get('closed_ts') or 0.0) <= 0:
                continue
            sym = str(t.get('symbol') or '').upper()
            side = str(t.get('side') or '').upper()
            cts = float(t.get('closed_ts') or 0.0)
            pnl = round(float(t.get('pnl') or 0.0), 8)
            journal_event_keys.add((sym, side, int(cts // 60), pnl))
            journal_event_keys.add((sym, _opposite_side_text(side), int(cts // 60), pnl))
        except Exception:
            continue

    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            rows = cur.execute(
                """
                WITH candidates AS (
                    SELECT e.setup_id AS setup_id,
                           e.user_id AS user_id,
                           e.emailed_ts AS emailed_ts,
                           0.0 AS generated_ts,
                           'emailed_setups' AS source_kind
                    FROM emailed_setups e
                    WHERE e.user_id = ?
                      AND e.emailed_ts >= ?
                    UNION ALL
                    SELECT g.setup_id AS setup_id,
                           g.user_id AS user_id,
                           0.0 AS emailed_ts,
                           MAX(g.created_ts) AS generated_ts,
                           'generated_setups' AS source_kind
                    FROM generated_setups g
                    WHERE g.user_id = ?
                      AND g.created_ts >= ?
                      AND COALESCE(NULLIF(g.setup_id,''),'') <> ''
                    GROUP BY g.user_id, g.setup_id
                )
                SELECT c.setup_id,
                       MAX(c.emailed_ts) AS emailed_ts,
                       MAX(c.generated_ts) AS generated_ts,
                       MIN(c.source_kind) AS source_kind,
                       COALESCE(MAX(l.executed_ts), 0) AS executed_ts,
                       COALESCE(MAX(l.closed_ts), 0) AS lifecycle_closed_ts,
                       COALESCE(MAX(NULLIF(l.trade_id,'')), '') AS trade_id,
                       COALESCE(MAX(NULLIF(l.symbol,'')), MAX(NULLIF(s.symbol,'')), MAX(NULLIF(g.symbol,'')), '') AS symbol,
                       COALESCE(MAX(NULLIF(l.side,'')), MAX(NULLIF(s.side,'')), MAX(NULLIF(g.side,'')), '') AS side,
                       COALESCE(MAX(NULLIF(l.state,'')), '') AS state,
                       COALESCE(MAX(s.created_ts), 0) AS signal_created_ts
                FROM candidates c
                LEFT JOIN admin_setup_lifecycle l ON l.setup_id = c.setup_id
                LEFT JOIN signals s ON s.setup_id = c.setup_id
                LEFT JOIN generated_setups g ON g.setup_id = c.setup_id AND g.user_id = c.user_id
                GROUP BY c.setup_id
                ORDER BY MAX(c.emailed_ts) ASC, MAX(c.generated_ts) ASC, COALESCE(MAX(s.created_ts),0) ASC, c.setup_id ASC
                """,
                (int(uid), float(start_ts - 86400.0 * 3.0), int(uid), float(start_ts - 86400.0 * 3.0)),
            ).fetchall() or []
            setup_rows = [dict(r) for r in rows]
    except Exception:
        setup_rows = []

    if not setup_rows:
        return []

    grouped: dict[str, list[dict]] = defaultdict(list)
    for r in setup_rows:
        sym = str(r.get('symbol') or '').upper()
        if not sym:
            continue
        base_ts = float(r.get('executed_ts') or 0.0) or float(r.get('emailed_ts') or 0.0) or float(r.get('generated_ts') or 0.0) or float(r.get('signal_created_ts') or 0.0)
        if base_ts <= 0:
            continue
        r['_base_ts'] = base_ts
        grouped[sym].append(r)
    for key in list(grouped.keys()):
        grouped[key].sort(key=lambda x: (float(x.get('_base_ts') or 0.0), str(x.get('setup_id') or '')))

    event_pool: dict[str, list[dict]] = defaultdict(list)
    for r in closed_rows:
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            ts = float(_bybit_closed_pnl_event_ts(r) or 0.0)
            pnl = round(float((r or {}).get('closedPnl') or 0.0), 8)
            if not sym or ts <= 0:
                continue
            qty = float(_bybit_closed_pnl_event_qty(r) or 0.0)
            sides = sorted(_bybit_closed_pnl_event_side_candidates(r))
            if any((sym, side, int(ts // 60), pnl) in journal_event_keys for side in sides):
                continue
            ev = {
                'ts': ts,
                'pnl': pnl,
                'qty': qty,
                'raw': r,
                'used': False,
                'sides': set(sides),
            }
            event_pool[sym].append(ev)
        except Exception:
            continue
    for key in list(event_pool.keys()):
        event_pool[key].sort(key=lambda x: (float(x.get('ts') or 0.0), abs(float(x.get('qty') or 0.0))))

    provisional = []
    for sym, setups in grouped.items():
        events = event_pool.get(sym) or []
        if not events:
            continue
        for i, srow in enumerate(setups):
            try:
                if str(srow.get('trade_id') or '').strip():
                    continue
                if float(srow.get('lifecycle_closed_ts') or 0.0) > 0:
                    continue
                base_ts = float(srow.get('_base_ts') or 0.0)
                if base_ts <= 0:
                    continue
                next_ts = None
                for later in setups[i+1:]:
                    later_ts = float(later.get('_base_ts') or 0.0)
                    if later_ts > base_ts:
                        next_ts = later_ts
                        break
                setup_side = str(srow.get('side') or '').upper().strip()
                best = None
                fallback = None
                for ev in events:
                    if ev.get('used'):
                        continue
                    ev_ts = float(ev.get('ts') or 0.0)
                    if ev_ts + 300.0 < base_ts:
                        continue
                    if next_ts and ev_ts >= next_ts:
                        continue
                    if fallback is None:
                        fallback = ev
                    if not setup_side or setup_side in (ev.get('sides') or set()):
                        best = ev
                        break
                best = best or fallback
                if not best:
                    continue
                best['used'] = True
                pnl = float(best.get('pnl') or 0.0)
                provisional.append({
                    'setup_id': str(srow.get('setup_id') or ''),
                    'symbol': sym,
                    'side': setup_side,
                    'opened_ts': base_ts,
                    'closed_ts': float(best.get('ts') or 0.0),
                    'pnl': pnl,
                    'outcome': 'WIN' if pnl > 0 else ('LOSS' if pnl < 0 else 'BREAKEVEN'),
                    'provisional': True,
                    'note': 'provisional_exchange_match_from_setup_history',
                })
            except Exception:
                continue
    return provisional


def _autotrade_exchange_close_fallback_rows(uid: int, days: int = 7) -> list[dict]:
    """Last-resort exchange-close fallback for performance reporting.

    Used only when the bot journal has no usable closed trades for the requested window.
    It aggregates raw Bybit closed-PnL events inside the anchored trading-day window and
    excludes any events already represented by journal-confirmed or provisional matches.
    """
    if str(AUTOTRADE_MODE).lower() != 'live':
        return []
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    tz = _user_tzinfo(user)
    start_local, end_local = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    end_ts = float(end_local.astimezone(timezone.utc).timestamp())

    excluded = set()
    try:
        for t in (db_list_autotrade_trades_all(int(uid)) or []):
            try:
                cts = float(t.get('closed_ts') or 0.0)
                if cts < start_ts or cts >= end_ts:
                    continue
                sym = str(t.get('symbol') or '').upper()
                side = str(t.get('side') or '').upper()
                pnl = round(float(t.get('pnl') or 0.0), 8)
                excluded.add((sym, side, int(cts), pnl))
            except Exception:
                continue
    except Exception:
        pass

    try:
        for t in (_autotrade_reconstruct_provisional_closes(int(uid), days=days) or []):
            try:
                cts = float(t.get('closed_ts') or 0.0)
                sym = str(t.get('symbol') or '').upper()
                side = str(t.get('side') or '').upper()
                pnl = round(float(t.get('pnl') or 0.0), 8)
                excluded.add((sym, side, int(cts), pnl))
            except Exception:
                continue
    except Exception:
        pass

    fallback = []
    for ev in (_bybit_get_closed_pnl_linear(start_ts, end_ts, limit=max(200, days * 80)) or []):
        try:
            sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper()
            ts = float(_bybit_closed_pnl_event_ts(ev) or 0.0)
            pnl = round(float((ev or {}).get('closedPnl') or 0.0), 8)
            if not sym or ts <= 0:
                continue
            sides = _bybit_closed_pnl_event_side_candidates(ev) or {''}
            if any((sym, str(side or '').upper(), int(ts), pnl) in excluded for side in sides):
                continue
            matched_side = ''
            for side in sides:
                key = (sym, str(side or '').upper(), int(ts), pnl)
                if key in excluded:
                    matched_side = str(side or '').upper()
                    break
            if not matched_side:
                matched_side = str(sorted(sides)[0] if sides else '').upper()
            fallback.append({
                'symbol': sym,
                'side': matched_side,
                'opened_ts': 0.0,
                'closed_ts': ts,
                'pnl': float(pnl),
                'outcome': 'WIN' if pnl > 0 else ('LOSS' if pnl < 0 else 'BREAKEVEN'),
                'exchange_only': True,
                'note': 'exchange_only_fallback_close',
            })
        except Exception:
            continue
    return fallback


def _autotrade_performance_rows(uid: int, days: int = 7) -> list[dict]:
    """Journal-first bot lifecycle performance rows.

    Primary source stays the bot journal. If older deployments are missing journal rows,
    a conservative *emailed-setup-linked* provisional fallback is added first, followed by
    a raw exchange-close fallback. Unlike older versions, fallback reconciliation is applied
    even when journal history is only partial.
    """
    days = int(max(2, min(int(days or 7), 3650)))
    user = _autotrade_user_settings(int(uid))
    _autotrade_sync_closed_trades_from_exchange(int(uid), lookback_days=max(14, days + 5))
    try:
        trades = db_list_autotrade_trades_all(int(uid)) or []
    except Exception:
        trades = []

    tz = _user_tzinfo(user)
    start_local, _ = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    day_starts = [start_local - timedelta(days=i) for i in range(days - 1, -1, -1)]
    by_day: dict[str, dict] = {}
    for ds in day_starts:
        by_day[ds.strftime('%Y-%m-%d')] = {
            'day': ds.strftime('%Y-%m-%d'),
            'opened': 0,
            'closed': 0,
            'wins': 0,
            'losses': 0,
            'net_pnl': 0.0,
            'avg_win': 0.0,
            'avg_loss': 0.0,
            'gross_profit': 0.0,
            'gross_loss': 0.0,
            'journal_confirmed_closes': 0,
            'exchange_reconciled_closes': 0,
            'provisional_emailed_setup_closes': 0,
            'exchange_only_fallback_closes': 0,
        }

    def _label(ts: float) -> str:
        return _autotrade_trade_day_label(ts, user)

    for t in trades:
        try:
            ots = float(t.get('opened_ts') or 0.0)
            if ots > 0:
                lab = _label(ots)
                if lab in by_day:
                    by_day[lab]['opened'] += 1
            cts = float(t.get('closed_ts') or 0.0)
            if cts <= 0:
                continue
            lab = _label(cts)
            if lab not in by_day:
                continue
            pnl = float(t.get('pnl') or 0.0)
            row = by_day[lab]
            row['closed'] += 1
            row['journal_confirmed_closes'] += 1
            if 'exchange_close_sync' in str(t.get('note') or ''):
                row['exchange_reconciled_closes'] += 1
            row['net_pnl'] += pnl
            if pnl > 0:
                row['wins'] += 1
                row['gross_profit'] += pnl
            elif pnl < 0:
                row['losses'] += 1
                row['gross_loss'] += abs(pnl)
        except Exception:
            continue

    for t in _autotrade_reconstruct_provisional_closes(int(uid), days=days):
        try:
            lab = _label(float(t.get('closed_ts') or 0.0))
            if lab not in by_day:
                continue
            row = by_day[lab]
            row['closed'] += 1
            row['exchange_reconciled_closes'] += 1
            row['provisional_emailed_setup_closes'] += 1
            open_lab = _label(float(t.get('opened_ts') or 0.0))
            if open_lab in by_day:
                by_day[open_lab]['opened'] += 1
            pnl = float(t.get('pnl') or 0.0)
            row['net_pnl'] += pnl
            if pnl > 0:
                row['wins'] += 1
                row['gross_profit'] += pnl
            elif pnl < 0:
                row['losses'] += 1
                row['gross_loss'] += abs(pnl)
        except Exception:
            continue

    for t in _autotrade_exchange_close_fallback_rows(int(uid), days=days):
        try:
            lab = _label(float(t.get('closed_ts') or 0.0))
            if lab not in by_day:
                continue
            row = by_day[lab]
            row['closed'] += 1
            row['exchange_reconciled_closes'] += 1
            row['exchange_only_fallback_closes'] += 1
            pnl = float(t.get('pnl') or 0.0)
            row['net_pnl'] += pnl
            if pnl > 0:
                row['wins'] += 1
                row['gross_profit'] += pnl
            elif pnl < 0:
                row['losses'] += 1
                row['gross_loss'] += abs(pnl)
        except Exception:
            continue

    for row in by_day.values():
        win_n = int(row.get('wins') or 0)
        loss_n = int(row.get('losses') or 0)
        gp = float(row.get('gross_profit') or 0.0)
        gl = float(row.get('gross_loss') or 0.0)
        row['avg_win'] = (gp / win_n) if win_n > 0 else 0.0
        row['avg_loss'] = (-(gl / loss_n)) if loss_n > 0 else 0.0
    return [by_day[ds.strftime('%Y-%m-%d')] for ds in day_starts]

def _autotrade_performance_summary(rows: list[dict]) -> dict:
    closed = sum(int(r.get('closed') or 0) for r in rows)
    wins = sum(int(r.get('wins') or 0) for r in rows)
    losses = sum(int(r.get('losses') or 0) for r in rows)
    net = sum(float(r.get('net_pnl') or 0.0) for r in rows)
    gross_profit = sum(float(r.get('gross_profit') or 0.0) for r in rows)
    gross_loss = sum(float(r.get('gross_loss') or 0.0) for r in rows)
    best_day = max(rows, key=lambda r: float(r.get('net_pnl') or 0.0)) if rows else None
    worst_day = min(rows, key=lambda r: float(r.get('net_pnl') or 0.0)) if rows else None
    win_rate = (wins / (wins + losses) * 100.0) if (wins + losses) > 0 else 0.0
    profit_factor = (gross_profit / gross_loss) if gross_loss > 0 else (float('inf') if gross_profit > 0 else 0.0)
    avg_win = (gross_profit / wins) if wins > 0 else 0.0
    avg_loss = (-(gross_loss / losses)) if losses > 0 else 0.0
    expectancy = (net / closed) if closed > 0 else 0.0
    return {
        'closed': closed,
        'wins': wins,
        'losses': losses,
        'net': net,
        'win_rate': win_rate,
        'profit_factor': profit_factor,
        'avg_win': avg_win,
        'avg_loss': avg_loss,
        'best_day': best_day,
        'worst_day': worst_day,
        'expectancy': expectancy,
    }

def _autotrade_day_risk_metrics(uid: int, equity: float) -> dict:
    """Compute authoritative AutoTrade day metrics using the configured trading-day window.

    Live-position day bucketing uses one authoritative open timestamp per current Bybit position.
    That timestamp is resolved from exchange evidence first, then matching journal state, then
    position.createdTime as a final fallback.
    """
    cap = 0.0
    open_pnl = 0.0
    realized_pnl_today = 0.0
    realized_loss_today = 0.0
    mode = str(AUTOTRADE_MODE).lower()
    user = _autotrade_user_settings(uid)

    try:
        if equity and equity > 0:
            user = dict(user)
            user["equity"] = float(equity)
    except Exception:
        pass

    try:
        cap = float(daily_cap_usd(user) or 0.0) if equity and equity > 0 else 0.0
    except Exception:
        cap = 0.0

    try:
        if mode == "live":
            _autotrade_sync_closed_trades_from_exchange(int(uid), lookback_days=14)
    except Exception:
        pass

    start_utc, end_utc = _admin_today_window_utc(uid=int(uid), user=user)
    closed_summary = {'count': 0, 'net_pnl': 0.0, 'realized_loss': 0.0}
    try:
        if mode == "live":
            closed_summary = _bybit_closed_pnl_summary(float(start_utc.timestamp()), float(end_utc.timestamp()))
            realized_pnl_today = float(closed_summary.get('net_pnl') or 0.0)
            realized_loss_today = float(closed_summary.get('realized_loss') or 0.0)
        else:
            realized_pnl_today = float(_autotrade_realized_pnl_today(int(uid)) or 0.0)
            realized_loss_today = max(0.0, -float(realized_pnl_today))
    except Exception:
        realized_pnl_today = 0.0
        realized_loss_today = 0.0
        closed_summary = {'count': 0, 'net_pnl': 0.0, 'realized_loss': 0.0}

    start_ts = float(start_utc.timestamp())
    end_ts = float(end_utc.timestamp())

    current_total_open_risk = 0.0
    current_day_open_risk = 0.0
    live_open_risk_charged_today = 0.0
    carried_open_risk = 0.0
    open_positions_now = 0
    inherited_open_positions = 0
    opened_today_count = 0
    closed_today_count = 0
    closed_today_rows = []
    position_classifications = []

    try:
        with sqlite3.connect(DB_PATH) as conn:
            cur = conn.cursor()
            cur.execute(
                "SELECT COUNT(*) FROM autotrade_trades WHERE uid=? AND opened_ts>=? AND opened_ts<?",
                (int(uid), int(start_ts), int(end_ts)),
            )
            row = cur.fetchone()
            opened_today_count = int((row[0] if row else 0) or 0)
    except Exception:
        opened_today_count = 0
    try:
        closed_today_rows = _autotrade_closed_activity_rows_window(int(uid), float(start_ts), float(end_ts)) or []
        closed_today_count = int(len(closed_today_rows))
        if closed_today_rows:
            realized_pnl_today = float(sum(
                float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0)
                for r in closed_today_rows
            ))
            realized_loss_today = float(sum(
                abs(float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0))
                for r in closed_today_rows
                if float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0) < 0.0
            ))
        elif mode == "live":
            closed_today_count = int(closed_summary.get('count') or 0)
    except Exception:
        closed_today_rows = []
        closed_today_count = int(closed_summary.get('count') or 0) if mode == "live" else 0

    journal_open = []
    try:
        journal_open = _autotrade_db_open_trades(int(uid)) or []
    except Exception:
        journal_open = []

    def _opened_ts_from_trade(t: dict) -> float:
        try:
            return float(t.get('opened_ts') or 0.0)
        except Exception:
            return 0.0

    if mode == "live":
        try:
            positions = _bybit_get_open_positions_linear()
        except Exception:
            positions = []
        open_positions_now = len(positions)
        open_pnl = float(sum(_pos_unreal_pnl(p) for p in positions) or 0.0) if positions else 0.0

        for p in positions:
            est = float(_estimate_position_risk_usd(p) or 0.0)
            info = _autotrade_resolve_live_position_open_info(int(uid), p, journal_open=journal_open)
            opened_ts = float(info.get('opened_ts') or 0.0)
            psym = _pos_symbol(p)
            pside = _pos_side_text(p)
            if est <= 0:
                try:
                    matches = [t for t in journal_open
                               if str(t.get('symbol') or '').upper() == str(psym).upper()
                               and str(t.get('side') or '').upper() == str(pside).upper()]
                    if matches:
                        matched_journal = [t for t in matches if abs(float(t.get('opened_ts') or 0.0) - float(info.get('journal_ts') or 0.0)) <= 1.0]
                        risk_pool = matched_journal or matches
                        est = max(
                            float(_autotrade_estimated_risk_usd(float(t.get('entry') or 0.0), float(t.get('sl') or 0.0), float(t.get('qty') or 0.0)) or 0.0)
                            for t in risk_pool
                        )
                except Exception:
                    pass
            est = max(0.0, float(est or 0.0))
            current_total_open_risk += est

            if opened_ts > 0 and opened_ts < start_ts:
                bucket = 'carried'
                carried_open_risk += est
                inherited_open_positions += 1
            else:
                bucket = 'current_day'
                current_day_open_risk += est

            position_classifications.append({
                'symbol': psym,
                'side': pside,
                'risk': float(est),
                'opened_ts': float(opened_ts or 0.0),
                'bucket': bucket,
                'source': str(info.get('source') or 'unknown'),
                'journal_ts': float(info.get('journal_ts') or 0.0),
                'position_created_ts': float(info.get('position_created_ts') or 0.0),
                'exchange_order_ts': float(info.get('exchange_order_ts') or 0.0),
                'notes': str(info.get('notes') or ''),
            })
        inherited_open_positions = min(int(inherited_open_positions), int(open_positions_now))
        current_day_open_positions = max(0, int(open_positions_now) - int(inherited_open_positions))
        # Live day-cap accounting should charge only positions opened inside the current
        # anchored trading day. Carried exposure is shown separately but must not consume
        # today's new-trade budget again.
        live_open_risk_charged_today = float(current_day_open_risk)
        # Keep the day-open count anchored to confirmed current-day opens, but if the
        # local journal is incomplete, never understate day activity versus confirmed
        # exchange closes plus current-day live positions.
        opened_today_count = max(int(opened_today_count), int(current_day_open_positions))
        opened_today_count = max(int(opened_today_count), int(closed_today_count) + int(current_day_open_positions))
    else:
        open_positions_now = len(journal_open)
        for t in journal_open:
            est = max(0.0, float(_autotrade_estimated_risk_usd(float(t.get('entry') or 0.0), float(t.get('sl') or 0.0), float(t.get('qty') or 0.0)) or 0.0))
            opened_ts = _opened_ts_from_trade(t)
            current_total_open_risk += est
            if opened_ts and opened_ts < start_ts:
                bucket = 'carried'
                carried_open_risk += est
                inherited_open_positions += 1
            else:
                bucket = 'current_day'
                current_day_open_risk += est
            position_classifications.append({
                'symbol': str(t.get('symbol') or '').upper(),
                'side': str(t.get('side') or '').upper(),
                'risk': float(est),
                'opened_ts': float(opened_ts or 0.0),
                'bucket': bucket,
                'source': 'autotrade_journal',
                'journal_ts': float(opened_ts or 0.0),
                'position_created_ts': 0.0,
                'exchange_order_ts': 0.0,
                'notes': '',
            })
        open_pnl = 0.0

    if float(live_open_risk_charged_today or 0.0) <= 0.0:
        live_open_risk_charged_today = float(current_day_open_risk)
    daily_used_total = max(0.0, float(live_open_risk_charged_today) - float(realized_pnl_today))
    remaining_raw = float("inf") if cap <= 0 else (float(cap) - float(daily_used_total))
    over_by = abs(float(remaining_raw)) if cap > 0 and remaining_raw < 0 else 0.0

    return {
        "cap": float(cap),
        "open_risk": float(current_total_open_risk),
        "used_risk": float(current_day_open_risk),
        "used_total": float(daily_used_total),
        "open_pnl": float(open_pnl),
        "realized_pnl_today": float(realized_pnl_today),
        "realized_loss_today": float(realized_loss_today),
        "remaining": float(remaining_raw),
        "over_by": float(over_by),
        "current_total_open_risk": float(current_total_open_risk),
        "current_day_open_risk": float(current_day_open_risk),
        "live_open_risk_charged_today": float(live_open_risk_charged_today),
        "carried_open_risk": float(carried_open_risk),
        "open_positions_now": int(open_positions_now),
        "inherited_open_positions": int(inherited_open_positions),
        "opened_today_count": int(opened_today_count),
        "closed_today_count": int(closed_today_count),
        "closed_today_rows": closed_today_rows,
        "day_start_ts": float(start_ts),
        "day_end_ts": float(end_ts),
        "position_classifications": position_classifications,
    }

def _autotrade_user_settings(uid: int) -> dict:
    """Return user dict after daily reset (so caps are current)."""
    try:
        return reset_daily_if_needed(get_user(int(uid)) or {})
    except Exception:
        return get_user(int(uid)) or {}

def _autotrade_per_trade_risk_usd(uid: int, equity: float) -> float:
    user = _autotrade_user_settings(uid)
    mode = str(user.get("risk_mode", DEFAULT_RISK_MODE)).upper()
    val = float(user.get("risk_value", DEFAULT_RISK_VALUE) or DEFAULT_RISK_VALUE)
    # compute_risk_usd uses live equity when available, but we pass user updated equity anyway
    try:
        if equity and equity > 0:
            user = dict(user)
            user["equity"] = float(equity)
    except Exception:
        pass
    return float(compute_risk_usd(user, mode, val) or 0.0)

def _autotrade_daily_cap_usd(uid: int, equity: float) -> float:
    user = _autotrade_user_settings(uid)
    try:
        if equity and equity > 0:
            user = dict(user)
            user["equity"] = float(equity)
    except Exception:
        pass
    return float(daily_cap_usd(user) or 0.0)

def _autotrade_remaining_risk_usd(uid: int, equity: float) -> float:
    user = _autotrade_user_settings(uid)
    # keep equity aligned for pct caps
    try:
        if equity and equity > 0:
            user2 = dict(user)
            user2["equity"] = float(equity)
        else:
            user2 = user
    except Exception:
        user2 = user
    cap = float(daily_cap_usd(user2) or 0.0)
    used = float(_risk_used_total_today(int(uid), user2) or 0.0)
    if cap <= 0:
        return float("inf")
    return max(0.0, cap - used)

def _autotrade_db_init():
    with sqlite3.connect(DB_PATH) as conn:
        c = conn.cursor()
        c.execute('''
            CREATE TABLE IF NOT EXISTS autotrade_trades (
                trade_id TEXT PRIMARY KEY,
                uid INTEGER,
                opened_ts INTEGER,
                day_utc TEXT NOT NULL DEFAULT \'\',
                session TEXT,
                setup_id TEXT,
                symbol TEXT,
                side TEXT,
                entry REAL,
                sl REAL,
                tp REAL,
                alt_target_a REAL,
                alt_target_b REAL,
                qty REAL,
                conf INTEGER,
                quality_score REAL,
                atr_pct REAL,
                engine TEXT,
                status TEXT DEFAULT 'OPEN',
                closed_ts INTEGER,
                outcome TEXT,
                pnl REAL
            )
        ''')
        c.execute("CREATE INDEX IF NOT EXISTS idx_autotrade_uid_opened ON autotrade_trades(uid, opened_ts)")
        c.execute("CREATE INDEX IF NOT EXISTS idx_autotrade_status ON autotrade_trades(status)")
        conn.commit()

def _autotrade_db_open_trades(uid: int) -> list[dict]:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute("SELECT * FROM autotrade_trades WHERE uid=? AND status='OPEN' ORDER BY opened_ts DESC", (uid,))
        return [dict(r) for r in c.fetchall()]

def _autotrade_db_closed_trades_window(uid: int, start_ts: float, end_ts: float) -> list[dict]:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute(
            """SELECT * FROM autotrade_trades
               WHERE uid=? AND closed_ts IS NOT NULL AND closed_ts>=? AND closed_ts<?
               ORDER BY closed_ts DESC""",
            (int(uid), float(start_ts), float(end_ts)),
        )
        return [dict(r) for r in c.fetchall()]


def _autotrade_closed_activity_rows_window(uid: int, start_ts: float, end_ts: float) -> list[dict]:
    """Closed-trade activity rows, journal-first with Bybit fallback for live admin.

    Why this exists:
    - /status and /autotrade_report should not show zero closed trades just because the
      local journal missed some closes during a restart or delayed reconciliation.
    - In LIVE mode for the owner/admin, Bybit closed-PnL rows are the source of truth for
      closed activity inside the requested window.
    """
    try:
        base_rows = _autotrade_db_closed_trades_window(int(uid), float(start_ts), float(end_ts)) or []
    except Exception:
        base_rows = []

    out = []
    seen = set()

    def _row_key(symbol: str, side: str, ts: float, pnl: float) -> tuple:
        return (
            str(_bybit_linear_symbol(symbol or '')).upper(),
            str(side or '').upper().strip(),
            int(float(ts or 0.0) // 60),
            round(float(pnl or 0.0), 8),
        )

    for r in (base_rows or []):
        try:
            sym = str(_bybit_linear_symbol((r or {}).get('symbol') or '')).upper()
            side = str((r or {}).get('side') or '').upper().strip()
            ts = float((r or {}).get('closed_ts') or 0.0)
            pnl = float((r or {}).get('pnl_usdt') if (r or {}).get('pnl_usdt') is not None else (r or {}).get('pnl') or 0.0)
            if not sym or ts <= 0:
                continue
            out.append(dict(r))
            seen.add(_row_key(sym, side, ts, pnl))
        except Exception:
            continue

    live_owner = (str(AUTOTRADE_MODE).lower() == 'live') and (int(uid) == int(AUTOTRADE_OWNER_UID or 0))
    if live_owner:
        try:
            span_hours = max(1.0, (float(end_ts) - float(start_ts)) / 3600.0)
            exch_rows = _bybit_get_closed_pnl_linear(float(start_ts), float(end_ts), limit=max(200, int(span_hours * 40))) or []
        except Exception:
            exch_rows = []
        for ev in (exch_rows or []):
            try:
                ts = float(_bybit_closed_pnl_event_ts(ev) or 0.0)
                if ts <= 0 or ts < float(start_ts) or ts >= float(end_ts):
                    continue
                sym = str(_bybit_linear_symbol((ev or {}).get('symbol') or '')).upper()
                if not sym:
                    continue
                pnl = float((ev or {}).get('closedPnl') or (ev or {}).get('closed_pnl') or 0.0)
                raw_side = str((ev or {}).get('side') or '').upper().strip()
                sides = _bybit_closed_pnl_event_side_candidates(ev) or {'BUY', 'SELL'}
                if any(_row_key(sym, side, ts, pnl) in seen for side in sides):
                    continue
                side = raw_side if raw_side in sides else str(sorted(sides)[0] if sides else '').upper()
                if not side:
                    side = 'BUY'
                row = {
                    'trade_id': f"exchange::{sym}::{side}::{int(ts)}::{abs(hash((sym, side, int(ts), round(pnl, 8))))}",
                    'uid': int(uid),
                    'symbol': sym,
                    'side': side,
                    'pnl_usdt': float(pnl),
                    'closed_ts': float(ts),
                    'status': 'CLOSED',
                    'outcome': 'WIN' if pnl > 0 else ('LOSS' if pnl < 0 else 'BREAKEVEN'),
                    'note': 'exchange_closed_pnl_fallback',
                }
                out.append(row)
                seen.add(_row_key(sym, side, ts, pnl))
            except Exception:
                continue

    out.sort(key=lambda r: float((r or {}).get('closed_ts') or 0.0), reverse=True)
    return out

AUTOTRADE_SYMBOL_GUARD_TTL_SEC = int(os.environ.get("AUTOTRADE_SYMBOL_GUARD_TTL_SEC", "1800") or 1800)
AUTOTRADE_RECENT_SYMBOL_SYNC_SEC = int(os.environ.get("AUTOTRADE_RECENT_SYMBOL_SYNC_SEC", "180") or 180)
AUTOTRADE_PLACED_GUARD_CLEANUP_SEC = int(os.environ.get("AUTOTRADE_PLACED_GUARD_CLEANUP_SEC", "172800") or 172800)

_AUTOTRADE_RUNTIME_SYMBOL_LOCKS: dict[str, float] = {}
_AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD = threading.Lock()

def _autotrade_symbol_lock_key(uid: int, symbol: str) -> str:
    return f"{int(uid)}:{_bybit_linear_symbol(symbol)}"

def _autotrade_runtime_symbol_lock_acquire(uid: int, symbol: str, ttl_sec: int | None = None) -> bool:
    ttl = int(ttl_sec or AUTOTRADE_SYMBOL_GUARD_TTL_SEC)
    key = _autotrade_symbol_lock_key(uid, symbol)
    now = float(time.time())
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        ts = float(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.get(key) or 0.0)
        if ts and (now - ts) <= ttl:
            return False
        _AUTOTRADE_RUNTIME_SYMBOL_LOCKS[key] = now
        stale_before = now - max(float(ttl), 60.0)
        for k, v in list(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.items()):
            try:
                if float(v or 0.0) < stale_before:
                    _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(k, None)
            except Exception:
                _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(k, None)
    return True

def _autotrade_runtime_symbol_lock_release(uid: int, symbol: str) -> None:
    key = _autotrade_symbol_lock_key(uid, symbol)
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(key, None)

def _autotrade_runtime_symbol_lock_active(uid: int, symbol: str, ttl_sec: int | None = None) -> bool:
    ttl = int(ttl_sec or AUTOTRADE_SYMBOL_GUARD_TTL_SEC)
    key = _autotrade_symbol_lock_key(uid, symbol)
    now = float(time.time())
    with _AUTOTRADE_RUNTIME_SYMBOL_LOCKS_GUARD:
        ts = float(_AUTOTRADE_RUNTIME_SYMBOL_LOCKS.get(key) or 0.0)
        if not ts:
            return False
        if (now - ts) > ttl:
            _AUTOTRADE_RUNTIME_SYMBOL_LOCKS.pop(key, None)
            return False
        return True

def _autotrade_exec_cleanup(stale_pending_sec: int = 1800, stale_failed_sec: int = 86400, stale_placed_sec: int = AUTOTRADE_PLACED_GUARD_CLEANUP_SEC) -> None:
    try:
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='PENDING' AND updated_ts<?", (now - float(stale_pending_sec),))
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='FAILED' AND updated_ts<?", (now - float(stale_failed_sec),))
            c.execute("DELETE FROM autotrade_exec_guard WHERE status='PLACED' AND updated_ts<?", (now - float(stale_placed_sec),))
            conn.commit()
    except Exception:
        pass


def _autotrade_exec_reserve(uid: int, setup_id: str, symbol: str, side: str, setup_ttl_sec: int = 86400, symbol_ttl_sec: int = AUTOTRADE_SYMBOL_GUARD_TTL_SEC, symdir_ttl_sec: int = AUTOTRADE_SYMBOL_GUARD_TTL_SEC) -> tuple[bool, list[str], str]:
    """Atomically reserve execution keys to prevent duplicate orders."""
    now = float(time.time())
    sid = str(setup_id or '').strip()
    sym = _bybit_linear_symbol(symbol)
    sd = str(side or '').upper().strip()
    if not sym or sd not in {'BUY','SELL'}:
        return (False, [], 'bad_guard_identity')

    setup_key = f"setup:{int(uid)}:{sid}" if sid else ''
    symbol_key = f"symbol:{int(uid)}:{sym}"
    symdir_key = f"symdir:{int(uid)}:{sym}:{sd}"
    checks = []
    if setup_key:
        checks.append((setup_key, 'SETUP', float(setup_ttl_sec)))
    checks.append((symbol_key, 'SYMBOL', float(symbol_ttl_sec)))
    checks.append((symdir_key, 'SYMDIR', float(symdir_ttl_sec)))

    try:
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            c.execute('BEGIN IMMEDIATE')
            reserved = []
            for guard_key, gtype, ttl in checks:
                row = c.execute("SELECT status, updated_ts, note FROM autotrade_exec_guard WHERE guard_key=?", (guard_key,)).fetchone()
                if row:
                    status = str(row[0] or '').upper()
                    updated_ts = float(row[1] or 0.0)
                    age = now - updated_ts
                    if status in {'PENDING', 'PLACED'} and age <= ttl:
                        conn.rollback()
                        return (False, reserved, f'duplicate_guard_block:{gtype.lower()}')
                c.execute("INSERT OR REPLACE INTO autotrade_exec_guard(guard_key, uid, setup_id, symbol, side, guard_type, status, created_ts, updated_ts, note) VALUES(?,?,?,?,?,?,?,?,?,?)",
                          (guard_key, int(uid), sid, sym, sd, gtype, 'PENDING', now, now, ''))
                reserved.append(guard_key)
            conn.commit()
            return (True, reserved, '')
    except Exception as e:
        return (False, [], f'guard_reserve_error:{type(e).__name__}')


def _autotrade_exec_mark(keys: list[str], status: str, note: str = '') -> None:
    try:
        if not keys:
            return
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            c = conn.cursor()
            for k in keys:
                c.execute("UPDATE autotrade_exec_guard SET status=?, updated_ts=?, note=? WHERE guard_key=?",
                          (str(status or '').upper(), now, str(note or '')[:500], str(k)))
            conn.commit()
    except Exception:
        pass


def _autotrade_get_local_symbol_activity(uid: int, symbol: str) -> dict:
    sym = _bybit_linear_symbol(symbol)
    out = {"open_trades": [], "latest_open_ts": 0.0, "latest_close_ts": 0.0, "latest_trade_ts": 0.0}
    try:
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            c.execute("SELECT * FROM autotrade_trades WHERE uid=? AND UPPER(symbol)=? ORDER BY opened_ts DESC", (int(uid), str(sym).upper()))
            rows = [dict(r) for r in c.fetchall()]
        opens = []
        for r in rows:
            status = str(r.get('status') or '').upper()
            try:
                open_ts = float(r.get('opened_ts') or 0.0)
            except Exception:
                open_ts = 0.0
            try:
                close_ts = float(r.get('closed_ts') or 0.0)
            except Exception:
                close_ts = 0.0
            out['latest_open_ts'] = max(float(out['latest_open_ts'] or 0.0), open_ts)
            out['latest_close_ts'] = max(float(out['latest_close_ts'] or 0.0), close_ts)
            out['latest_trade_ts'] = max(float(out['latest_trade_ts'] or 0.0), open_ts, close_ts)
            if status == 'OPEN':
                opens.append(r)
        out['open_trades'] = opens
    except Exception:
        pass
    return out


def _autotrade_get_pending_symbol_guards(uid: int, symbol: str) -> list[dict]:
    sym = _bybit_linear_symbol(symbol)
    out = []
    try:
        now = float(time.time())
        with sqlite3.connect(DB_PATH) as conn:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
            c.execute("SELECT * FROM autotrade_exec_guard WHERE uid=? AND UPPER(symbol)=? ORDER BY updated_ts DESC", (int(uid), str(sym).upper()))
            rows = [dict(r) for r in c.fetchall()]
        for r in rows:
            status = str(r.get('status') or '').upper()
            age = now - float(r.get('updated_ts') or 0.0)
            if status == 'PENDING' and age <= float(AUTOTRADE_SYMBOL_GUARD_TTL_SEC):
                out.append(r)
            elif status == 'PLACED' and age <= float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC):
                out.append(r)
        return out
    except Exception:
        return []


def _autotrade_symbol_cooldown_remaining(uid: int, symbol: str, session_label: str) -> float:
    act = _autotrade_get_local_symbol_activity(uid, symbol)
    last_ts = float(act.get('latest_trade_ts') or 0.0)
    if last_ts <= 0:
        return 0.0
    cooldown_sec = max(float(cooldown_hours_for_session(session_label)) * 3600.0, float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC))
    return max(0.0, (last_ts + cooldown_sec) - float(time.time()))


def _autotrade_log_symbol_block(uid: int, symbol: str, side: str, reason: str, extra: str = '') -> None:
    try:
        msg = f"{reason} uid={int(uid)} symbol={_bybit_linear_symbol(symbol)} side={str(side or '').upper()}"
        if extra:
            msg += f" | {extra}"
        logger.warning(msg)
    except Exception:
        pass


def _autotrade_can_open_symbol(uid: int, symbol: str, side: str, session_label: str) -> tuple[bool, str, dict]:
    """Single hardened gatekeeper for symbol tradability."""
    sym = _bybit_linear_symbol(symbol)
    sd = str(side or '').upper().strip()
    detail = {
        'symbol': sym,
        'side': sd,
        'session': str(session_label or '').upper(),
        'live_open_position': False,
        'local_open_trade': False,
        'live_open_order': False,
        'pending_guard': False,
        'runtime_lock': False,
        'cooldown_remaining_sec': 0.0,
        'recent_trade_remaining_sec': 0.0,
        'local_open_count': 0,
        'pending_guard_count': 0,
    }
    if not sym or sd not in {'BUY', 'SELL'}:
        return (False, 'blocked_bad_symbol_identity', detail)

    _autotrade_exec_cleanup()

    if _autotrade_runtime_symbol_lock_active(uid, sym):
        detail['runtime_lock'] = True
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_inflight_lock', 'runtime_lock_active')
        return (False, 'blocked_duplicate_inflight_lock', detail)

    if str(AUTOTRADE_MODE).lower() == 'live':
        try:
            for p in _bybit_get_open_positions_linear():
                if _pos_symbol(p) == sym and abs(float(_pos_size(p) or 0.0)) > 0:
                    detail['live_open_position'] = True
                    _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_open_position', 'live_position_present')
                    return (False, 'blocked_duplicate_open_position', detail)
        except Exception:
            pass

    local_activity = _autotrade_get_local_symbol_activity(uid, sym)
    local_opens = local_activity.get('open_trades') or []
    if local_opens:
        detail['local_open_trade'] = True
        detail['local_open_count'] = len(local_opens)
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_existing_local_trade_state', f"open_trades={len(local_opens)}")
        return (False, 'blocked_by_existing_local_trade_state', detail)

    pending_guards = _autotrade_get_pending_symbol_guards(uid, sym)
    if pending_guards:
        detail['pending_guard'] = True
        detail['pending_guard_count'] = len(pending_guards)
        statuses = ','.join(sorted({str(x.get('status') or '').upper() for x in pending_guards}))
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_pending_order', f"guards={len(pending_guards)} statuses={statuses}")
        return (False, 'blocked_duplicate_pending_order', detail)

    if str(AUTOTRADE_MODE).lower() == 'live':
        try:
            if _autotrade_has_live_open_order(sym, side=None):
                detail['live_open_order'] = True
                _autotrade_log_symbol_block(uid, sym, sd, 'blocked_duplicate_pending_order', 'live_open_order_present')
                return (False, 'blocked_duplicate_pending_order', detail)
        except Exception:
            pass

    latest_open_ts = float(local_activity.get('latest_open_ts') or 0.0)
    if latest_open_ts > 0:
        recent_remaining = max(0.0, (latest_open_ts + float(AUTOTRADE_RECENT_SYMBOL_SYNC_SEC)) - float(time.time()))
        detail['recent_trade_remaining_sec'] = recent_remaining
        if recent_remaining > 0:
            _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_recent_symbol_trade', f"remaining_sec={int(recent_remaining)}")
            return (False, 'blocked_by_recent_symbol_trade', detail)

    cooldown_remaining = _autotrade_symbol_cooldown_remaining(uid, sym, session_label)
    detail['cooldown_remaining_sec'] = cooldown_remaining
    if cooldown_remaining > 0:
        _autotrade_log_symbol_block(uid, sym, sd, 'blocked_by_cooldown', f"remaining_sec={int(cooldown_remaining)}")
        return (False, 'blocked_by_cooldown', detail)

    return (True, '', detail)


def _bybit_get_open_orders_linear(symbol: str | None = None) -> list[dict]:
    sym = _bybit_linear_symbol(symbol) if symbol else None
    cache_key = f"bybit_open_orders_linear:{sym or 'ALL'}"
    try:
        ttl = max(1, int(BYBIT_OPEN_ORDERS_CACHE_TTL_SEC or 6))
        if cache_valid(cache_key, ttl):
            cached = cache_get(cache_key)
            return list(cached or []) if isinstance(cached, list) else []
    except Exception:
        pass
    try:
        if not BYBIT_API_KEY or not BYBIT_API_SECRET:
            return []
        merged: list[dict] = []
        seen: set[str] = set()
        order_filters = [None, 'Order', 'StopOrder', 'tpslOrder', 'TPSLOrder']
        for order_filter in order_filters:
            payload = {'category': 'linear', 'openOnly': 0, 'limit': 200}
            if sym:
                payload['symbol'] = sym
            if order_filter:
                payload['orderFilter'] = order_filter
            res = _bybit_v5_request('GET', '/v5/order/realtime', payload)
            if int((res or {}).get('retCode', -1)) != 0:
                continue
            for row in ((((res or {}).get('result') or {}).get('list') or [])):
                try:
                    oid = str(row.get('orderId') or row.get('stopOrderId') or row.get('orderLinkId') or '')
                except Exception:
                    oid = ''
                key = oid or json.dumps(row, sort_keys=True, default=str)
                if key in seen:
                    continue
                seen.add(key)
                merged.append(row)
        try:
            cache_set(cache_key, list(merged))
        except Exception:
            pass
        return merged
    except Exception:
        stale = cache_get(cache_key)
        return list(stale or []) if isinstance(stale, list) else []


def _bybit_get_order_linear_state(symbol: str, order_id: str = '', order_link_id: str = '') -> dict:
    sym = _bybit_linear_symbol(symbol)
    oid = str(order_id or '').strip()
    olid = str(order_link_id or '').strip()
    if not sym or (not oid and not olid):
        return {}
    lookups = [('/v5/order/realtime', {'openOnly': 0}), ('/v5/order/history', {'limit': 50})]
    for path, extra in lookups:
        for order_filter in (None, 'Order', 'StopOrder', 'tpslOrder', 'TPSLOrder'):
            payload = {'category': 'linear', 'symbol': sym}
            payload.update(extra)
            if oid:
                payload['orderId'] = oid
            if olid:
                payload['orderLinkId'] = olid
            if order_filter:
                payload['orderFilter'] = order_filter
            res = _bybit_v5_request('GET', path, payload)
            if int((res or {}).get('retCode', -1)) != 0:
                continue
            rows = (((res or {}).get('result') or {}).get('list') or [])
            if not rows:
                continue
            for row in rows:
                row_oid = str((row or {}).get('orderId') or '').strip()
                row_olid = str((row or {}).get('orderLinkId') or '').strip()
                if (oid and row_oid == oid) or (olid and row_olid == olid):
                    out = dict(row or {})
                    out['_source_path'] = path
                    out['_source_filter'] = order_filter
                    return out
    return {}


def _autotrade_has_live_open_order(symbol: str, side: str | None = None) -> bool:
    sym = _bybit_linear_symbol(symbol)
    side_u = str(side or '').upper().strip()
    try:
        for o in _bybit_get_open_orders_linear(sym):
            try:
                if _bybit_linear_symbol(str(o.get('symbol') or '')) != sym:
                    continue
                if side_u:
                    o_side = str(o.get('side') or '').upper().strip()
                    if (o_side == 'BUY' and side_u != 'BUY') or (o_side == 'SELL' and side_u != 'SELL'):
                        continue
                status = str(o.get('orderStatus') or '').upper()
                if status not in {'CANCELLED', 'FILLED', 'REJECTED', 'DEACTIVATED'}:
                    return True
            except Exception:
                continue
    except Exception:
        return False
    return False


def _autotrade_db_add_trade(uid: int, session_label: str, s: 'Setup', qty: float, lifecycle_state: str = 'executed_open', lifecycle_reason: str = '') -> str:
    """Persist a bot-opened trade into SQLite.

    NOTE: Some deployed DBs have a NOT NULL `day_utc` column on autotrade_trades.
    We detect it and always populate it to avoid IntegrityError.
    """
    trade_id = f"AT-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}-{uuid.uuid4().hex[:6].upper()}"
    day_utc = datetime.now(timezone.utc).strftime('%Y-%m-%d')

    with sqlite3.connect(DB_PATH) as conn:
        c = conn.cursor()

        # Detect schema (older/newer deployments)
        try:
            cols = [r[1] for r in c.execute("PRAGMA table_info(autotrade_trades)").fetchall()]
        except Exception:
            cols = []

        has_day = 'day_utc' in cols

        if has_day:
            c.execute(
                """INSERT INTO autotrade_trades
                       (trade_id, uid, opened_ts, day_utc, session, setup_id, symbol, side, entry, sl, tp, alt_target_a, alt_target_b, qty, conf, quality_score, atr_pct, engine, status)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'OPEN')""",
                (
                    trade_id,
                    int(uid),
                    int(time.time()),
                    str(day_utc),
                    str(session_label),
                    str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or ''),
                    str(getattr(s, 'symbol', '') or '').upper(),
                    str(getattr(s, 'side', '') or '').upper(),
                    float(getattr(s, 'entry', 0.0) or 0.0),
                    float(getattr(s, 'sl', 0.0) or 0.0),
                    float(_setup_target_tp(s, 0.0) or 0.0),
                    0.0,
                    0.0,
                    float(qty),
                    int(getattr(s, 'conf', 0) or 0),
                    float(getattr(s, 'quality_score', 0.0) or 0.0),
                    float(getattr(s, 'atr_pct', 0.0) or 0.0),
                    str(getattr(s, 'engine', '') or ''),
                ),
            )
        else:
            c.execute(
                """INSERT INTO autotrade_trades
                       (trade_id, uid, opened_ts, session, setup_id, symbol, side, entry, sl, tp, alt_target_a, alt_target_b, qty, conf, quality_score, atr_pct, engine, status)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'OPEN')""",
                (
                    trade_id,
                    int(uid),
                    int(time.time()),
                    str(session_label),
                    str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or ''),
                    str(getattr(s, 'symbol', '') or '').upper(),
                    str(getattr(s, 'side', '') or '').upper(),
                    float(getattr(s, 'entry', 0.0) or 0.0),
                    float(getattr(s, 'sl', 0.0) or 0.0),
                    float(_setup_target_tp(s, 0.0) or 0.0),
                    0.0,
                    0.0,
                    float(qty),
                    int(getattr(s, 'conf', 0) or 0),
                    float(getattr(s, 'quality_score', 0.0) or 0.0),
                    float(getattr(s, 'atr_pct', 0.0) or 0.0),
                    str(getattr(s, 'engine', '') or ''),
                ),
            )

        try:
            if cols:
                extra_updates = []
                extra_params = []
                if 'family_id' in cols:
                    extra_updates.append('family_id=?')
                    extra_params.append(str(getattr(s, 'family_id', '') or ''))
                if 'regime_primary' in cols:
                    extra_updates.append('regime_primary=?')
                    extra_params.append(str(getattr(s, 'regime_primary', '') or ''))
                if 'allocator_plan_id' in cols:
                    extra_updates.append('allocator_plan_id=?')
                    extra_params.append(str(getattr(s, 'allocator_plan_id', '') or ''))
                if 'param_set_id' in cols:
                    extra_updates.append('param_set_id=?')
                    extra_params.append(str(getattr(s, 'param_set_id', '') or ''))
                if extra_updates:
                    extra_params.append(str(trade_id))
                    c.execute(f"UPDATE autotrade_trades SET {', '.join(extra_updates)} WHERE trade_id=?", tuple(extra_params))
        except Exception:
            pass
        conn.commit()

    try:
        _admin_setup_lifecycle_merge(
            int(uid),
            str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or ''),
            session=str(session_label or ''),
            symbol=str(getattr(s, 'symbol', '') or ''),
            side=str(getattr(s, 'side', '') or ''),
            executed_ts=float(time.time()),
            trade_id=str(trade_id),
            state=str(lifecycle_state or 'executed_open'),
            last_reason=str(lifecycle_reason or ''),
        )
    except Exception:
        pass
    return trade_id


def _autotrade_estimated_risk_usd(entry: float, sl: float, qty: float) -> float:
    try:
        return abs(entry - sl) * abs(qty)
    except Exception:
        return 0.0

def _autotrade_open_risk_usd(uid: int, equity_usdt: float) -> float:
    total = 0.0
    for t in _autotrade_db_open_trades(uid):
        total += _autotrade_estimated_risk_usd(float(t.get('entry') or 0.0), float(t.get('sl') or 0.0), float(t.get('qty') or 0.0))
    return total

def _autotrade_qty_from_risk(entry: float, sl: float, equity_usdt: float, risk_usd: float | None = None, contract_size: float = 1.0) -> float:
    dist = abs(float(entry) - float(sl))
    cs = abs(float(contract_size or 1.0))
    if dist <= 0 or cs <= 0:
        return 0.0
    if risk_usd is None:
        # Backward-compat fallback only. Live sizing should pass explicit /riskmode-derived risk_usd.
        risk_usd = (float(equity_usdt) * (AUTOTRADE_RISK_PER_TRADE_PCT / 100.0))
    qty = float(risk_usd) / (dist * cs)
    if qty <= 0 or (not math.isfinite(qty)):
        return 0.0
    return float(qty)

def _autotrade_allowed_session(session_label: str) -> bool:
    allowed = {s.strip().upper() for s in (_autotrade_get_sessions() or []) if s.strip()}
    if not allowed:
        allowed = {'NY', 'LON', 'ASIA'}
    return str(session_label or '').upper() in allowed


# =========================================================
# AUTOTRADE: select best OPEN setup from DB (generated_setups + signals)
# =========================================================
def _autotrade_db_signal_structurally_valid(s: Any, session_name: str = "NY") -> tuple[bool, str]:
    """Validate DB-hydrated executable rows against the real executable gate when possible."""
    try:
        sess = str(session_name or "").upper().strip()
        if sess not in {"ASIA", "LON", "NY"}:
            return (False, "session_not_supported")

        has_rich_exec_snapshot = bool(
            str(getattr(s, "engine", "") or "").strip()
            and float(getattr(s, "quality_score", 0.0) or 0.0) > 0.0
        )
        if has_rich_exec_snapshot:
            return is_executable_setup_eligible(s, session_name=sess)

        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        if entry <= 0 or sl <= 0:
            return (False, "missing_prices")
        if final_tp <= 0:
            return (False, "missing_tp")
        if abs(entry - sl) <= 0:
            return (False, "zero_risk_distance")
        _, sess_conf, sess_rr = _execution_session_thresholds(sess)
        conf_floor = int(max(MIN_SETUP_CONF, sess_conf))
        conf = int(getattr(s, "conf", 0) or 0)
        if conf < conf_floor:
            return (False, "below_exec_conf")
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if final_tp > 0 else 0.0
        if rr_final < float(sess_rr):
            return (False, "below_exec_rr")
        return (True, "ok")
    except Exception:
        return (False, "db_exec_validation_exception")


def _autotrade_select_db_setups(uid: int, session_label: str, lookback_hours: int = 12, limit: int = 1) -> list:
    """Return recent OPEN executable setup candidates for autotrade.

    Authoritative source of truth:
    - executable_setups = persisted executable-qualified queue
    - emailed_setups = downstream delivery state only (debug/telemetry)
    - generated_setups(source='email') = audit/debug correlation only
    """
    try:
        from types import SimpleNamespace
        cutoff = time.time() - float(lookback_hours) * 3600.0
        req_session_u = str(session_label or '').upper().strip()

        con = sqlite3.connect(DB_PATH)
        con.row_factory = sqlite3.Row
        cur = con.cursor()
        cur.execute(
            """
            SELECT x.*, COALESCE(MAX(e.emailed_ts), 0) AS emailed_ts
            FROM executable_setups x
            LEFT JOIN emailed_setups e
                   ON e.user_id = x.user_id
                  AND e.setup_id = x.setup_id
            LEFT JOIN signal_outcomes o ON o.setup_id = x.setup_id
            WHERE x.user_id = ?
              AND x.executable_ts >= ?
              AND (? = '' OR UPPER(COALESCE(x.session, '')) = ?)
              AND COALESCE(o.outcome, 'OPEN') = 'OPEN'
            GROUP BY x.user_id, x.setup_id
            ORDER BY x.executable_ts DESC, x.setup_id DESC
            LIMIT ?
            """,
            (int(uid), float(cutoff), req_session_u, req_session_u, int(max(limit * 6, limit))),
        )
        rows = [dict(r) for r in (cur.fetchall() or [])]
        con.close()

        out = []
        for row in rows:
            try:
                item = _executable_rows_to_setup_objects([row], session_name=req_session_u)
                if not item:
                    continue
                obj = item[0]
                src_session_u = str(getattr(obj, 'source_session', '') or '').upper().strip()
                if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason('session_mismatch'), last_reason=f'session_mismatch ({src_session_u}->{req_session_u})')
                    except Exception:
                        pass
                    continue
                now_ts = float(time.time())
                canonical_ts = float(getattr(obj, 'created_ts', 0.0) or 0.0)
                expiry_grace_sec = float(max(300, int(AUTOTRADE_ENTRY_WINDOW_MIN) * 60 + 300))
                if canonical_ts <= 0 or (now_ts - canonical_ts) > expiry_grace_sec:
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u or req_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason('stale_deadline'), last_reason='stale_deadline')
                    except Exception:
                        pass
                    continue
                exec_ok, exec_why = _autotrade_db_signal_structurally_valid(obj, session_name=req_session_u or src_session_u or session_label)
                if not exec_ok:
                    try:
                        _admin_setup_lifecycle_merge(int(uid), str(getattr(obj, 'setup_id', '') or ''), session=src_session_u or req_session_u, symbol=str(getattr(obj, 'symbol', '') or ''), side=str(getattr(obj, 'side', '') or ''), state=_admin_setup_state_from_reason(exec_why), last_reason=str(exec_why))
                    except Exception:
                        pass
                    continue
                out.append(obj)
            except Exception:
                continue

        if not out:
            fallback_items = []
            try:
                fallback_items = _recent_delivery_lane_setup_objects(int(uid), session_name=req_session_u, max_age_min=max(20, int(AUTOTRADE_ENTRY_WINDOW_MIN) + 15), limit=max(1, int(limit * 4))) or []
            except Exception:
                fallback_items = []
            for obj in (fallback_items or []):
                try:
                    src_session_u = str(getattr(obj, 'source_session', '') or '').upper().strip()
                    if req_session_u and src_session_u and src_session_u not in {'', req_session_u}:
                        continue
                    now_ts = float(time.time())
                    canonical_ts = float(getattr(obj, 'created_ts', 0.0) or getattr(obj, 'email_logged_ts', 0.0) or 0.0)
                    expiry_grace_sec = float(max(300, int(AUTOTRADE_ENTRY_WINDOW_MIN) * 60 + 300))
                    if canonical_ts <= 0 or (now_ts - canonical_ts) > expiry_grace_sec:
                        continue
                    exec_ok, exec_why = _autotrade_db_signal_structurally_valid(obj, session_name=req_session_u or src_session_u or session_label)
                    if not exec_ok:
                        continue
                    out.append(obj)
                    try:
                        db_mark_executable_setup(int(uid), str(getattr(obj, 'setup_id', '') or getattr(obj, 'id', '') or ''), str(src_session_u or req_session_u or session_label), float(getattr(obj, 'email_logged_ts', 0.0) or now_ts), s=obj, source_kind=str(getattr(obj, 'source_kind', '') or 'emailed_setups'), state='executable_pending')
                    except Exception:
                        pass
                except Exception:
                    continue

        out = sorted(
            out,
            key=lambda x: (
                float(getattr(x, 'email_logged_ts', 0.0) or 0.0),
                float(getattr(x, 'created_ts', 0.0) or 0.0),
                int(getattr(x, 'conf', 0) or 0),
            ),
            reverse=True,
        )[:max(1, int(limit))]
        if out:
            try:
                for item in out:
                    _admin_setup_lifecycle_merge(
                        int(uid),
                        str(getattr(item, 'setup_id', '') or getattr(item, 'id', '') or ''),
                        session=str(getattr(item, 'source_session', '') or session_label or ''),
                        symbol=str(getattr(item, 'symbol', '') or ''),
                        side=str(getattr(item, 'side', '') or ''),
                        executable_ts=float(getattr(item, 'executable_ts', 0.0) or getattr(item, 'created_ts', 0.0) or time.time()),
                        state='executable_pending',
                        source_kind=str(getattr(item, 'source_kind', '') or 'executable_setups'),
                        signal_created_ts=float(getattr(item, 'signal_created_ts', 0.0) or 0.0),
                        emailed_ts=float(getattr(item, 'email_logged_ts', 0.0) or 0.0),
                        generated_logged_ts=float(getattr(item, 'generated_logged_ts', 0.0) or 0.0),
                    )
            except Exception:
                pass
        return out
    except Exception as e:
        try:
            logger.error(f"_autotrade_select_db_setups failed: {type(e).__name__}: {e}")
        except Exception:
            pass
        return []

def _autotrade_clear_debug_state(uid: int | None = None) -> None:
    """Clear in-memory autotrade debug state. If uid is None, clears all."""
    global _LAST_AUTOTRADE_DECISION, _LAST_AUTOTRADE_DETAIL
    try:
        if uid is None:
            _LAST_AUTOTRADE_DECISION.clear()
            _LAST_AUTOTRADE_DETAIL.clear()
        else:
            _LAST_AUTOTRADE_DECISION.pop(int(uid), None)
            _LAST_AUTOTRADE_DETAIL.pop(int(uid), None)
    except Exception:
        pass


def _autotrade_effective_risk_usd(uid: int, setup, equity: float, base_risk_usd: float, remaining_risk_usd: float, open_risk_usd: float, daily_cap_usd: float) -> tuple[float, float, str]:
    """Return (effective_risk_usd, multiplier, regime).

    Best approach used here:
    - /riskmode remains the user-selected base risk
    - dynamic multiplier scales size up/down based on setup quality
    - never exceed remaining daily capacity
    - if the clipped risk becomes too small, block the trade upstream
    """
    try:
        conf = int(getattr(setup, 'conf', 0) or 0)
        engine = str(getattr(setup, 'engine', '') or '').upper()
        market_symbol = str(getattr(setup, 'market_symbol', '') or getattr(setup, 'symbol', '') or '')

        regime = 'UNKNOWN'
        try:
            c1 = fetch_ohlcv(market_symbol, "1h", 60)
            regime = pf_market_regime(c1[-30:] if c1 else c1)
        except Exception:
            regime = 'UNKNOWN'

        mult = float(pf_dynamic_risk_multiplier(conf, regime=regime, engine=engine) or 1.0)
        # SAFETY: never scale risk ABOVE the user's /riskmode base.
        mult = min(float(mult), 1.0)
        target_risk = max(0.0, float(base_risk_usd) * float(mult))
        target_risk = min(target_risk, float(base_risk_usd))

        if daily_cap_usd > 0:
            cap_left = max(0.0, float(daily_cap_usd) - max(0.0, float(open_risk_usd)))
            target_risk = min(target_risk, cap_left)

        if remaining_risk_usd >= 0:
            target_risk = min(target_risk, float(remaining_risk_usd))

        return (max(0.0, float(target_risk)), mult, str(regime or 'UNKNOWN').upper())
    except Exception:
        return (max(0.0, float(base_risk_usd or 0.0)), 1.0, 'UNKNOWN')


def _autotrade_place_trade(uid: int, session_label: str, setups: list) -> tuple[bool, str]:
    if not _autotrade_ready():
        return (False, 'autotrade_not_ready_or_disabled')
    if int(uid) != int(AUTOTRADE_OWNER_UID):
        return (False, 'not_owner')
    if not _autotrade_allowed_session(session_label):
        return (False, f'autotrade_session_not_allowed ({session_label})')
    if not setups:
        return (False, 'no_setups')

    s = setups[0]
    side = str(getattr(s, 'side', '') or '').upper()
    intended_entry = float(getattr(s, 'entry', 0.0) or 0.0)
    intended_sl = float(getattr(s, 'sl', 0.0) or 0.0)
    sym = _bybit_linear_symbol(str(getattr(s, 'symbol', '') or '').upper())
    setup_id = str(getattr(s, 'setup_id', '') or getattr(s, 'id', '') or '').strip()
    reserved_keys: list[str] = []
    runtime_lock_acquired = False

    try:
        _admin_setup_lifecycle_merge(
            int(uid),
            setup_id,
            session=str(session_label or ''),
            symbol=str(getattr(s, 'symbol', '') or ''),
            side=str(side or ''),
            attempted_ts=float(time.time()),
            state='execution_attempted',
            source_kind=str(getattr(s, 'source_kind', '') or ''),
            signal_created_ts=float(getattr(s, 'signal_created_ts', 0.0) or 0.0),
            emailed_ts=float(getattr(s, 'email_logged_ts', 0.0) or 0.0),
            generated_logged_ts=float(getattr(s, 'generated_logged_ts', 0.0) or 0.0),
        )
    except Exception:
        pass

    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)] = {
            'when': datetime.now(timezone.utc).isoformat(timespec='seconds'),
            'session': session_label,
            'setup_id': setup_id,
            'symbol_raw': str(getattr(s, 'symbol', '') or ''),
            'symbol_sent': sym,
            'side': side,
            'entry': float(intended_entry or 0.0),
            'sl': float(intended_sl or 0.0),
            'entry_source': 'setup',
            'sl_source': 'setup',
            'setup_entry': intended_entry,
            'setup_sl_raw': intended_sl,
        }
    except Exception:
        pass

    try:
        _signal_ts = float(getattr(s, 'signal_created_ts', 0.0) or 0.0)
        _email_ts = float(getattr(s, 'email_logged_ts', 0.0) or 0.0)
        _generated_ts = float(getattr(s, 'generated_logged_ts', 0.0) or 0.0)
        _cts = float(getattr(s, 'created_ts', 0.0) or 0.0)
        _canonical_ts = max(_cts, _email_ts, _generated_ts, _signal_ts)
        _setup_dt = datetime.fromtimestamp(_canonical_ts, tz=timezone.utc) if _canonical_ts > 0 else datetime.now(timezone.utc)
        _deadline_dt = _setup_dt + timedelta(minutes=AUTOTRADE_ENTRY_WINDOW_MIN)
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'setup_time': _setup_dt.isoformat(timespec='seconds'),
            'entry_deadline': _deadline_dt.isoformat(timespec='seconds'),
            'signal_created_time': datetime.fromtimestamp(_signal_ts, tz=timezone.utc).isoformat(timespec='seconds') if _signal_ts > 0 else '',
            'email_logged_time': datetime.fromtimestamp(_email_ts, tz=timezone.utc).isoformat(timespec='seconds') if _email_ts > 0 else '',
            'generated_logged_time': datetime.fromtimestamp(_generated_ts, tz=timezone.utc).isoformat(timespec='seconds') if _generated_ts > 0 else '',
            'source_kind': str(getattr(s, 'source_kind', '') or ''),
            'source_session': str(getattr(s, 'source_session', '') or ''),
        })
        if datetime.now(timezone.utc) > _deadline_dt:
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('stale_deadline'), last_reason='stale_deadline')
            except Exception:
                pass
            return (False, 'setup_expired')
    except Exception:
        pass

    try:
        _source_kind_u = str(getattr(s, 'source_kind', '') or '').lower().strip()
    except Exception:
        _source_kind_u = ''
    if _source_kind_u in {'executable_setups', 'emailed_setups', 'recent_email_lane', 'recent_email_cache'}:
        exec_ok, exec_why = _autotrade_db_signal_structurally_valid(s, session_name=session_label)
    else:
        exec_ok, exec_why = is_executable_setup_eligible(s, session_name=session_label)
    if not exec_ok:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(exec_why), last_reason=str(exec_why))
        except Exception:
            pass
        return (False, str(exec_why))

    def _as_pos_float(x):
        try:
            v = float(x)
            return v if v > 0 else None
        except Exception:
            return None

    tp = _as_pos_float(getattr(s, 'tp', None))
    alt_target_a = _as_pos_float(getattr(s, 'alt_target_a', None))
    alt_target_b = _as_pos_float(getattr(s, 'alt_target_b', None))
    final_tp = _resolve_single_tp(intended_entry, intended_sl, tp, alt_target_a, alt_target_b, side)

    if side not in {'BUY', 'SELL'}:
        return (False, f'bad_side ({side})')
    if intended_entry <= 0 or intended_sl <= 0:
        return (False, 'bad_prices')
    if final_tp <= 0:
        return (False, 'missing_tp')
    if side == 'BUY' and intended_sl >= intended_entry:
        return (False, 'sl_not_below_entry_for_buy')
    if side == 'SELL' and intended_sl <= intended_entry:
        return (False, 'sl_not_above_entry_for_sell')

    price_ref = intended_entry
    if str(AUTOTRADE_MODE).lower() == 'live':
        live_ref = _autotrade_live_reference_price(sym, fallback_entry=intended_entry)
        if live_ref > 0:
            price_ref = live_ref

    entry_drift_pct = 0.0
    try:
        if float(intended_entry) > 0 and float(price_ref) > 0:
            entry_drift_pct = abs((float(price_ref) - float(intended_entry)) / float(intended_entry)) * 100.0
    except Exception:
        entry_drift_pct = 0.0
    if str(AUTOTRADE_MODE).lower() == 'live' and float(AUTOTRADE_MAX_ENTRY_DRIFT_PCT) > 0 and entry_drift_pct > float(AUTOTRADE_MAX_ENTRY_DRIFT_PCT):
        try:
            _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'entry': float(price_ref),
                'entry_source': 'live_ref',
                'setup_entry': float(intended_entry),
                'entry_drift_pct': float(entry_drift_pct),
                'reject_reason': 'entry_drift_too_wide',
            })
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('stale_deadline'), last_reason=f'entry_drift_too_wide ({entry_drift_pct:.2f}%>{float(AUTOTRADE_MAX_ENTRY_DRIFT_PCT):.2f}%)')
        except Exception:
            pass
        return (False, 'entry_drift_too_wide')

    filt = _bybit_get_instr_filters(sym)
    qty_step = filt.get('qtyStep')
    contract_size = float(filt.get('contractSize') or 1.0)
    stop_rounding = ROUND_UP if side == 'BUY' else ROUND_DOWN
    sl_for_order = _round_price_to_tick(sym, intended_sl, rounding=stop_rounding)
    if sl_for_order <= 0:
        sl_for_order = intended_sl
    if side == 'BUY' and sl_for_order >= price_ref:
        return (False, 'stop_invalid_after_tick_rounding_for_buy')
    if side == 'SELL' and sl_for_order <= price_ref:
        return (False, 'stop_invalid_after_tick_rounding_for_sell')

    equity = _effective_equity_for_risk(get_user(uid) or {}, prefer_live=(str(AUTOTRADE_MODE).lower() == 'live'))
    if equity <= 0:
        return (False, 'equity_unavailable_or_zero')
    try:
        if str(AUTOTRADE_MODE).lower() == 'live' and equity > 0:
            update_user(int(uid), equity=float(equity))
    except Exception:
        pass

    base_per_trade_risk = float(_autotrade_per_trade_risk_usd(uid, equity) or 0.0)
    if base_per_trade_risk <= 0:
        return (False, 'per_trade_risk_zero')

    mday = _autotrade_day_risk_metrics(int(uid), float(equity))
    try:
        live_open_count = int(mday.get('open_positions_now') or 0)
    except Exception:
        live_open_count = 0
    try:
        max_trades_day = int((get_user(uid) or {}).get('max_trades_day') or 0)
    except Exception:
        max_trades_day = 0
    try:
        opened_today_count = int(mday.get('opened_today_count') or 0)
    except Exception:
        opened_today_count = 0
    if max_trades_day > 0 and opened_today_count >= max_trades_day:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'reject_reason': 'max_trades_day_reached',
                'opened_today_count': int(opened_today_count),
                'max_trades_day': int(max_trades_day),
            })
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(
                int(uid),
                setup_id,
                state=_admin_setup_state_from_reason('risk_cap'),
                last_reason=f'max_trades_day_reached ({opened_today_count}/{max_trades_day})',
            )
        except Exception:
            pass
        return (False, 'max_trades_day_reached')
    if int(AUTOTRADE_MAX_OPEN_TRADES or 0) > 0 and live_open_count >= int(AUTOTRADE_MAX_OPEN_TRADES):
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'max_open_trades_reached', 'open_positions_now': int(live_open_count)})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason=f'max_open_trades_reached ({live_open_count}/{int(AUTOTRADE_MAX_OPEN_TRADES)})')
        except Exception:
            pass
        return (False, 'max_open_trades_reached')
    daily_cap = float(mday.get('cap') or 0.0)
    open_risk = float(mday.get('open_risk') or 0.0)
    used_total_before = float(mday.get('used_total') or 0.0)
    remaining_risk = float(mday.get('remaining')) if daily_cap > 0 else float('inf')

    effective_risk, risk_mult, risk_regime = _autotrade_effective_risk_usd(
        uid=uid,
        setup=s,
        equity=float(equity),
        base_risk_usd=float(base_per_trade_risk),
        remaining_risk_usd=float(remaining_risk) if math.isfinite(remaining_risk) else float(base_per_trade_risk),
        open_risk_usd=float(open_risk),
        daily_cap_usd=float(daily_cap),
    )

    stop_distance = abs(float(price_ref) - float(sl_for_order))
    allowed_risk_usd = min(float(base_per_trade_risk), float(effective_risk))
    if math.isfinite(remaining_risk):
        allowed_risk_usd = min(float(allowed_risk_usd), float(remaining_risk))
    allowed_risk_usd = max(0.0, float(allowed_risk_usd))

    configured_risk_pct = _risk_pct_from_amount(float(equity), float(base_per_trade_risk))
    allowed_risk_pct = _risk_pct_from_amount(float(equity), float(allowed_risk_usd))
    try:
        _LAST_AUTOTRADE_DETAIL.setdefault(int(uid), {})
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'entry': float(price_ref),
            'sl': float(sl_for_order),
            'entry_source': 'live_ref' if str(AUTOTRADE_MODE).lower() == 'live' else 'setup',
            'sl_source': 'tick_rounded',
            'setup_entry_vs_live_delta_pct': (((float(price_ref) - float(intended_entry)) / float(intended_entry)) * 100.0) if float(intended_entry) > 0 else 0.0,
            'contractSize': float(contract_size),
            'tick_size': filt.get('tickSize'),
            'equity_used': float(equity),
            'risk_mode': str((get_user(uid) or {}).get('risk_mode', DEFAULT_RISK_MODE)).upper(),
            'risk_value': float((get_user(uid) or {}).get('risk_value', DEFAULT_RISK_VALUE) or DEFAULT_RISK_VALUE),
            'risk_base_usd': float(base_per_trade_risk),
            'risk_effective_usd': float(effective_risk),
            'risk_multiplier': float(risk_mult),
            'risk_regime': str(risk_regime),
            'configured_risk_pct': float(configured_risk_pct),
            'allowed_risk_usd': float(allowed_risk_usd),
            'allowed_risk_pct': float(allowed_risk_pct),
            'daily_cap_usd': float(daily_cap),
            'open_risk_usd_before': float(open_risk),
            'daily_used_total_before': float(used_total_before),
            'realized_loss_today': float(mday.get('realized_loss_today') or 0.0),
            'remaining_risk_usd': float(remaining_risk) if math.isfinite(remaining_risk) else float('inf'),
            'stop_distance': float(stop_distance),
        })
    except Exception:
        pass

    if stop_distance <= 0:
        return (False, 'stop_distance_zero_or_invalid')
    if math.isfinite(remaining_risk) and remaining_risk <= 0:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'daily_remaining_risk_zero'})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_remaining_risk_zero')
        except Exception:
            pass
        return (False, 'daily_remaining_risk_zero')
    if allowed_risk_usd <= 0:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_risk_cap_reached')
        except Exception:
            pass
        return (False, 'daily_risk_cap_reached')
    if daily_cap > 0 and used_total_before >= daily_cap:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_risk_cap_already_exceeded')
        except Exception:
            pass
        return (False, 'daily_risk_cap_already_exceeded')

    raw_qty = _autotrade_qty_from_risk(price_ref, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
    if raw_qty <= 0:
        return (False, 'qty_calc_failed')
    qty, qreason = _round_qty_down(sym, raw_qty, price_ref)
    if qty is None:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': f'qty_invalid:{qreason}'})
        except Exception:
            pass
        return (False, f'qty_invalid:{qreason}')

    actual_risk = _autotrade_true_risk_usd(price_ref, sl_for_order, qty, contract_size)
    if actual_risk > (allowed_risk_usd * 1.0005):
        qty2 = _autotrade_qty_from_risk(price_ref, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
        qty2, qreason2 = _round_qty_down(sym, qty2, price_ref)
        if qty2 is None:
            return (False, f'qty_capped_but_invalid:{qreason2}')
        qty = qty2
        actual_risk = _autotrade_true_risk_usd(price_ref, sl_for_order, qty, contract_size)
        if actual_risk > (allowed_risk_usd * 1.0005):
            return (False, 'risk_cap_enforcement_failed')
    actual_risk_pct = _risk_pct_from_amount(float(equity), float(actual_risk))
    if math.isfinite(remaining_risk) and (used_total_before + actual_risk) > (daily_cap * 1.0005):
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('risk_cap'), last_reason='daily_cap_would_be_exceeded_by_new_trade')
        except Exception:
            pass
        return (False, 'daily_cap_would_be_exceeded_by_new_trade')

    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'raw_qty': float(raw_qty),
            'rounded_qty': float(qty),
            'qty': float(qty),
            'qty_attempted': float(qty),
            'qty_round_reason': qreason,
            'risk_actual_usd': float(actual_risk),
            'risk_actual_pct': float(actual_risk_pct),
            'daily_used_total_after_est': float(used_total_before + actual_risk),
        })
    except Exception:
        pass

    can_open, can_open_reason, can_open_detail = _autotrade_can_open_symbol(uid, sym, side, session_label)
    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'can_open_symbol': bool(can_open),
            'can_open_reason': str(can_open_reason or ''),
            'can_open_detail': can_open_detail,
        })
    except Exception:
        pass
    if not can_open:
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(can_open_reason), last_reason=str(can_open_reason))
        except Exception:
            pass
        return (False, str(can_open_reason or 'blocked_before_order'))

    runtime_lock_acquired = _autotrade_runtime_symbol_lock_acquire(uid, sym)
    if not runtime_lock_acquired:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'blocked_duplicate_inflight_lock'})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('blocked_duplicate_inflight_lock'), last_reason='blocked_duplicate_inflight_lock')
        except Exception:
            pass
        return (False, 'blocked_duplicate_inflight_lock')

    ok_reserve, reserved_keys, reserve_reason = _autotrade_exec_reserve(uid, setup_id, sym, side)
    if not ok_reserve:
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': str(reserve_reason or 'guard_reserve_failed')})
        except Exception:
            pass
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason(reserve_reason), last_reason=str(reserve_reason or 'guard_reserve_failed'))
        except Exception:
            pass
        return (False, str(reserve_reason or 'guard_reserve_failed'))

    exit_plan = _autotrade_live_exit_plan_for_trade(s)
    live_final_tp = float(exit_plan.get('final_tp') or final_tp or 0.0)
    try:
        _LAST_AUTOTRADE_DETAIL[int(uid)].update({
            'position_opened_time': datetime.now(timezone.utc).isoformat(timespec='seconds'),
            'live_exit_tp': float(live_final_tp or 0.0),
            'live_tp_design': 'single_full_position_tp_sl',
        })
    except Exception:
        pass

    try:
        if str(AUTOTRADE_MODE).lower() != 'live':
            s_paper = replace(s, entry=float(price_ref), sl=float(sl_for_order), tp=float(live_final_tp or 0.0), alt_target_a=0.0, alt_target_b=0.0)
            trade_id = _autotrade_db_add_trade(uid, session_label, s_paper, float(qty), lifecycle_state='executed_open', lifecycle_reason='paper_opened')
            _autotrade_exec_mark(reserved_keys, 'PLACED', trade_id)
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'trade_id': str(trade_id), 'mode': 'paper'})
            except Exception:
                pass
            return (True, f"[PAPER] Opened {trade_id}: {side} {sym} qty={qty:.8g} SL={sl_for_order:g} TP={live_final_tp:g}")

        open_payload = {
            'category': 'linear',
            'symbol': sym,
            'side': 'Buy' if side == 'BUY' else 'Sell',
            'orderType': 'Market',
            'qty': _fmt_qty(float(qty), qty_step),
            'timeInForce': 'IOC',
            'positionIdx': 0,
            'orderLinkId': f"pf_op_{sym}_{int(time.time()*1000)%100000000}_{uuid.uuid4().hex[:6]}"[:36],
        }
        open_res = _bybit_v5_request('POST', '/v5/order/create', open_payload)
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({'open_payload': open_payload, 'open_res': open_res})
        except Exception:
            pass
        if int((open_res or {}).get('retCode', -1)) != 0:
            err = f"{(open_res or {}).get('retCode')} {(open_res or {}).get('retMsg')}"
            _autotrade_exec_mark(reserved_keys, 'FAILED', err)
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('exchange_reject'), last_reason=str(err))
            except Exception:
                pass
            return (False, f'live_open_failed ({err})')

        corrected = False
        open_order_result = ((open_res or {}).get('result') or {})
        open_order_id = str(open_order_result.get('orderId') or '')
        open_order_link_id = str(open_order_result.get('orderLinkId') or '')
        live_conf = _autotrade_wait_live_entry_confirmation(sym, side=side, order_id=open_order_id, order_link_id=open_order_link_id, wait_sec=10.0, step_sec=0.4)
        live_pos = live_conf.get('position')
        confirmed_filled = bool(live_conf.get('filled_confirmed'))
        filled_qty = abs(float((live_conf.get('filled_qty') or (_pos_size(live_pos) if live_pos else qty)) or 0.0))
        if filled_qty <= 0:
            filled_qty = float(qty)
        filled_entry = float(live_conf.get('avg_price') or (_pos_entry(live_pos) if live_pos else price_ref) or price_ref)
        try:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'entry_confirmation': live_conf,
                'filled_qty': float(filled_qty),
                'filled_entry': float(filled_entry),
            })
        except Exception:
            pass

        if not live_pos and not confirmed_filled:
            reject_reason = str(live_conf.get('reason') or 'live_entry_fill_not_confirmed')
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': reject_reason})
            except Exception:
                pass
            _autotrade_exec_mark(reserved_keys, 'FAILED', reject_reason)
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state=_admin_setup_state_from_reason('exchange_reject'), last_reason=reject_reason)
            except Exception:
                pass
            return (False, reject_reason)

        if live_pos:
            filled_risk = _autotrade_true_risk_usd(filled_entry, sl_for_order, filled_qty, contract_size)
            filled_risk_pct = _risk_pct_from_amount(float(equity), float(filled_risk))
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'filled_risk_usd': float(filled_risk),
                'filled_risk_pct': float(filled_risk_pct),
            })
            if filled_risk > (allowed_risk_usd * 1.0005):
                allowed_qty = _autotrade_qty_from_risk(filled_entry, sl_for_order, equity, risk_usd=allowed_risk_usd, contract_size=contract_size)
                allowed_qty, reduce_reason = _round_qty_down(sym, allowed_qty, filled_entry)
                if allowed_qty is None or allowed_qty <= 0:
                    _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_no_valid_reduction:{reduce_reason}')
                    return (False, f'post_fill_risk_breach_no_valid_reduction:{reduce_reason}')
                reduce_qty = max(0.0, filled_qty - float(allowed_qty))
                reduce_qty, reduce_reason = _round_qty_down(sym, reduce_qty, filled_entry)
                if reduce_qty is None or reduce_qty <= 0:
                    _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_reduce_qty_invalid:{reduce_reason}')
                    return (False, f'post_fill_risk_breach_reduce_qty_invalid:{reduce_reason}')
                reduce_payload = {
                    'category': 'linear',
                    'symbol': sym,
                    'side': 'Sell' if side == 'BUY' else 'Buy',
                    'orderType': 'Market',
                    'qty': _fmt_qty(reduce_qty, qty_step),
                    'timeInForce': 'IOC',
                    'reduceOnly': True,
                    'closeOnTrigger': True,
                }
                reduce_res = _bybit_v5_request('POST', '/v5/order/create', reduce_payload)
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reduce_payload': reduce_payload, 'reduce_res': reduce_res})
                if int((reduce_res or {}).get('retCode', -1)) != 0:
                    err = f"{(reduce_res or {}).get('retCode')} {(reduce_res or {}).get('retMsg')}"
                    _autotrade_exec_mark(reserved_keys, 'FAILED', f'post_fill_risk_breach_reduce_failed:{err}')
                    return (False, f'post_fill_risk_breach_reduce_failed ({err})')
                corrected = True
                live_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=3.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or live_pos
                filled_qty = abs(float((_pos_size(live_pos) if live_pos else allowed_qty) or allowed_qty or 0.0))
                filled_entry = float((_pos_entry(live_pos) if live_pos else filled_entry) or filled_entry or price_ref)

        final_pos = _autotrade_wait_live_position(sym, side=side, wait_sec=5.0, step_sec=0.25) or _autotrade_find_live_position(sym, side=side) or live_pos
        qty_for_db = abs(float((_pos_size(final_pos) if final_pos else filled_qty) or qty))
        if final_pos is None:
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_position_visibility_pending_for_sltp_attach'})
            except Exception:
                pass
            _autotrade_exec_mark(reserved_keys, 'FAILED', 'live_position_visibility_pending_for_sltp_attach')
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason='live_position_visibility_pending_for_sltp_attach')
            except Exception:
                pass
            return (False, 'live_position_visibility_pending_for_sltp_attach')

        sl_res = _autotrade_apply_position_tp_sl(sym, sl_for_order, live_final_tp)
        time.sleep(0.40)
        final_pos = _autotrade_find_live_position(sym, side=side) or final_pos
        sl_live = float(_pos_stop(final_pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0) if final_pos else 0.0
        tp_live = float(_pos_take_profit(final_pos) or 0.0) if final_pos else 0.0
        sl_ok = bool(sl_for_order > 0 and sl_live > 0 and _price_close_enough(sl_live, sl_for_order, rel_tol=0.0020))
        tp_ok = bool(live_final_tp > 0 and tp_live > 0 and _price_close_enough(tp_live, live_final_tp, rel_tol=0.0020))
        if not (sl_ok and tp_ok):
            sl_res_retry = _autotrade_apply_position_tp_sl(sym, sl_for_order, live_final_tp)
            time.sleep(0.45)
            final_pos = _autotrade_find_live_position(sym, side=side) or final_pos
            sl_live = float(_pos_stop(final_pos) or _bybit_detect_open_sl_price(sym, side=side) or 0.0) if final_pos else 0.0
            tp_live = float(_pos_take_profit(final_pos) or 0.0) if final_pos else 0.0
            sl_ok = bool(sl_for_order > 0 and sl_live > 0 and _price_close_enough(sl_live, sl_for_order, rel_tol=0.0020))
            tp_ok = bool(live_final_tp > 0 and tp_live > 0 and _price_close_enough(tp_live, live_final_tp, rel_tol=0.0020))
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'sl_apply_res': sl_res,
                'sl_apply_retry_res': sl_res_retry,
                'tp_apply_res': sl_res,
                'sl_stack_ok': bool(sl_ok),
                'tp_stack_ok': bool(tp_ok),
            })
        else:
            _LAST_AUTOTRADE_DETAIL[int(uid)].update({
                'sl_apply_res': sl_res,
                'tp_apply_res': sl_res,
                'sl_stack_ok': bool(sl_ok),
                'tp_stack_ok': bool(tp_ok),
            })

        if not (sl_ok and tp_ok):
            _autotrade_exec_mark(reserved_keys, 'FAILED', 'live_exit_stack_incomplete')
            try:
                _LAST_AUTOTRADE_DETAIL[int(uid)].update({'reject_reason': 'live_exit_stack_incomplete'})
            except Exception:
                pass
            try:
                _admin_setup_lifecycle_merge(int(uid), setup_id, state='failed', last_reason='live_exit_stack_incomplete')
            except Exception:
                pass
            return (False, 'live_exit_stack_incomplete')

        s_live = replace(s, entry=float(filled_entry or price_ref), sl=float(sl_for_order), tp=float(live_final_tp or 0.0), alt_target_a=0.0, alt_target_b=0.0)
        trade_id = _autotrade_db_add_trade(uid, session_label, s_live, qty_for_db, lifecycle_state='executed_open', lifecycle_reason='live_opened')
        _autotrade_exec_mark(reserved_keys, 'PLACED', trade_id)
        try:
            _admin_setup_lifecycle_merge(int(uid), setup_id, trade_id=str(trade_id), bybit_position_symbol=str(sym or ''), state='executed_open', last_reason='live_opened')
        except Exception:
            pass
        suffix = ' corrected_for_post_fill_risk' if corrected else ''
        return (True, f"[LIVE] Opened {trade_id}: {side} {sym} qty={qty_for_db:.8g} SL={sl_for_order:g} TP={live_final_tp:g}{suffix}")

    except Exception as e:
        try:
            _autotrade_exec_mark(reserved_keys, 'FAILED', f'{type(e).__name__}: {e}')
        except Exception:
            pass
        return (False, f'autotrade_execution_error:{type(e).__name__}')
    finally:
        if runtime_lock_acquired:
            _autotrade_runtime_symbol_lock_release(uid, sym)

