def _trade_lifecycle_be_stop_history_event(side: str, entry: float, orders: list[dict], after_ts: float = 0.0) -> dict | None:
    try:
        side_u = _norm_trade_side(side)
        entry_f = float(entry or 0.0)
        after_f = float(after_ts or 0.0)
        if side_u not in {'BUY', 'SELL'} or entry_f <= 0:
            return None
        close_side = _trade_lifecycle_close_side(side_u)
        best = None
        for o in (orders or []):
            try:
                got_side = str((o or {}).get('side') or '').upper().strip()
                if close_side and got_side and got_side != close_side:
                    continue
                txt = _bybit_order_kind_text(o)
                trig = float((o or {}).get('triggerPrice') or (o or {}).get('trigger_price') or 0.0)
                order_type = str((o or {}).get('orderType') or '').upper().strip()
                if not ('stoploss' in txt or 'pf_sl' in txt or (_bybit_order_reduce_only(o) and order_type == 'MARKET' and trig > 0)):
                    continue
                px = float(_bybit_order_sl_price(o) or _bybit_order_working_price(o) or trig or _bybit_order_avg_price(o) or 0.0)
                if px <= 0 or not _trade_lifecycle_is_be_or_better(side_u, px, entry_f):
                    continue
                ts_val = float(_bybit_order_filled_time_ts(o) or 0.0)
                if ts_val <= 0:
                    ts_val = float(max(_ts_seconds_from_any((o or {}).get('updatedTime')), _ts_seconds_from_any((o or {}).get('createdTime')), _ts_seconds_from_any((o or {}).get('orderTime'))))
                if after_f > 0 and ts_val > 0 and ts_val + 1.0 < after_f:
                    continue
                ev = {'ts': ts_val, 'price': px, 'raw': dict(o or {})}
                if best is None or (float(ev.get('ts') or 0.0) > 0 and float(ev.get('ts') or 0.0) < float(best.get('ts') or 0.0)):
                    best = ev
            except Exception:
                continue
        return best
    except Exception:
        return None


def _trade_lifecycle_upsert_row(row: dict) -> None:
    if not row or not str(row.get('trade_id') or '').strip():
        return
    _trade_lifecycle_migrate()
    cols = [
        'trade_id', 'setup_id', 'uid', 'symbol', 'side', 'entry', 'sl', 'tp', 'alt_target_a', 'rr_tp_target', 'rr_tp',
        'opened_ts', 'closed_ts', 'open_day', 'close_day', 'open_session', 'close_session',
        'risk_usdt', 'risk_pct', 'confidence', 'quality_score', 'engine', 'tp_hit_ts', 'alt_target_a_hit_ts',
        'sl_hit_ts', 'be_armed_ts', 'be_hit_ts', 'result_path', 'result_label', 'close_reason',
        'risk_free_flag', 'pnl_usdt', 'r_multiple', 'duration_total_sec', 'duration_to_tp_sec',
        'duration_to_alt_target_a_sec', 'duration_to_sl_sec', 'source_confidence', 'source_note',
        'exchange_confirmed', 'last_sync_ts', 'open_reason'
    ]
    vals = [row.get(c) for c in cols]
    try:
        with sqlite3.connect(DB_PATH) as con:
            cur = con.cursor()
            cur.execute(
                f"INSERT OR REPLACE INTO trade_lifecycle ({', '.join(cols)}) VALUES ({', '.join(['?'] * len(cols))})",
                vals,
            )
            con.commit()
    except Exception:
        pass


def _trade_lifecycle_store_events(trade_id: str, events: list[dict]) -> None:
    if not trade_id or not events:
        return
    _trade_lifecycle_migrate()
    try:
        with sqlite3.connect(DB_PATH) as con:
            cur = con.cursor()
            for ev in (events or []):
                cur.execute(
                    """
                    INSERT OR IGNORE INTO trade_lifecycle_events
                    (trade_id, event_type, event_ts, price, qty, pnl_usdt, source, details_json)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        str(trade_id),
                        str(ev.get('event_type') or ''),
                        float(ev.get('event_ts') or 0.0) if ev.get('event_ts') is not None else None,
                        float(ev.get('price') or 0.0) if ev.get('price') is not None else None,
                        float(ev.get('qty') or 0.0) if ev.get('qty') is not None else None,
                        float(ev.get('pnl_usdt') or 0.0) if ev.get('pnl_usdt') is not None else None,
                        str(ev.get('source') or ''),
                        _json_dumps_safe(ev.get('details') or {}),
                    ),
                )
            con.commit()
    except Exception:
        pass


def _trade_lifecycle_owner_uid(request_uid: int) -> int:
    try:
        owner = int(AUTOTRADE_OWNER_UID or 0)
    except Exception:
        owner = 0
    if owner > 0:
        return owner
    return int(request_uid)


def _trade_lifecycle_query_rows(uid: int, start_ts: float = 0.0, session: str = 'ALL', limit: int | None = None) -> list[dict]:
    _trade_lifecycle_migrate()
    params = [int(uid)]
    q = "SELECT * FROM trade_lifecycle WHERE uid=?"
    if float(start_ts or 0.0) > 0:
        q += " AND (COALESCE(opened_ts,0)>=? OR COALESCE(closed_ts,0)>=?)"
        params.extend([float(start_ts), float(start_ts)])
    sess = str(session or 'ALL').upper().strip()
    if sess in {'ASIA', 'LON', 'NY'}:
        q += " AND UPPER(COALESCE(open_session,''))=?"
        params.append(sess)
    q += " ORDER BY COALESCE(opened_ts,0) DESC, COALESCE(closed_ts,0) DESC"
    if limit is not None:
        q += " LIMIT ?"
        params.append(int(limit))
    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            rows = cur.execute(q, tuple(params)).fetchall() or []
            return [dict(r) for r in rows]
    except Exception:
        return []


def _trade_lifecycle_metrics_from_rows(rows: list[dict]) -> dict:
    rows = [dict(r) for r in (rows or [])]
    total = len(rows)
    wins = sum(1 for r in rows if str(r.get('result_path') or '').upper() == 'HIT_TP_WIN')
    partial_wins = sum(1 for r in rows if str(r.get('result_path') or '').upper() in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'})
    losses = sum(1 for r in rows if str(r.get('result_path') or '').upper() == 'HIT_SL_LOSS')
    open_n = sum(1 for r in rows if str(r.get('result_path') or '').upper() == 'OPEN')
    manual_unknown = sum(1 for r in rows if str(r.get('result_path') or '').upper() == 'MANUAL_OR_UNKNOWN_CLOSE')
    closed_decided = wins + partial_wins + losses
    tp_hits = sum(1 for r in rows if float(r.get('tp_hit_ts') or 0.0) > 0 or str(r.get('result_path') or '').upper() in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'})
    alt_target_a_hits = sum(1 for r in rows if float(r.get('alt_target_a_hit_ts') or 0.0) > 0 or str(r.get('result_path') or '').upper() == 'HIT_TP_WIN')
    sl_hits = sum(1 for r in rows if float(r.get('sl_hit_ts') or 0.0) > 0 or str(r.get('result_path') or '').upper() in {'HIT_SL_LOSS', 'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'})
    risk_free = sum(1 for r in rows if str(r.get('risk_free_flag') or '').upper() == 'YES')
    pnls = [float(r.get('pnl_usdt') or 0.0) for r in rows if r.get('pnl_usdt') is not None and str(r.get('result_path') or '').upper() != 'OPEN']
    rs = [float(r.get('r_multiple') or 0.0) for r in rows if r.get('r_multiple') is not None and str(r.get('result_path') or '').upper() != 'OPEN']
    avg_pnl = (sum(pnls) / len(pnls)) if pnls else 0.0
    avg_r = (sum(rs) / len(rs)) if rs else 0.0
    win_rate = ((wins + partial_wins) / closed_decided * 100.0) if closed_decided > 0 else 0.0

    by_open_session = defaultdict(lambda: {'total': 0, 'closed': 0, 'wins': 0, 'partial_wins': 0, 'losses': 0, 'manual_unknown': 0, 'tp_hits': 0, 'alt_target_a_hits': 0, 'sl_hits': 0, 'risk_free': 0, 'r': [], 'pnl': []})
    by_close_session = defaultdict(lambda: {'total': 0, 'closed': 0, 'wins': 0, 'partial_wins': 0, 'losses': 0, 'manual_unknown': 0})
    by_engine = defaultdict(lambda: {'closed': 0, 'r': [], 'wins': 0, 'partial_wins': 0, 'losses': 0})
    by_conf = defaultdict(lambda: {'closed': 0, 'r': [], 'wins': 0, 'losses': 0, 'partial_wins': 0})
    by_quality = defaultdict(lambda: {'closed': 0, 'r': [], 'wins': 0, 'losses': 0, 'partial_wins': 0})
    symbols = defaultdict(lambda: {'trades': 0, 'wins': 0, 'partial_wins': 0, 'losses': 0, 'tp_hits': 0, 'alt_target_a_hits': 0, 'manual_unknown': 0, 'net_pnl': 0.0, 'r': []})
    durations_tp = []
    durations_alt_target_a = []
    durations_sl = []

    for r in rows:
        path = str(r.get('result_path') or '').upper().strip()
        osess = str(r.get('open_session') or '?').upper().strip() or '?'
        csess = str(r.get('close_session') or '?').upper().strip() or '?'
        eng = str(r.get('engine') or 'UNKNOWN').upper().strip() or 'UNKNOWN'
        conf_bucket = _trade_lifecycle_conf_bucket(r.get('confidence'))
        quality_bucket = _trade_lifecycle_quality_bucket(r.get('quality_score'))
        sym = str(r.get('symbol') or '?').upper().strip() or '?'
        pnl = float(r.get('pnl_usdt') or 0.0) if r.get('pnl_usdt') is not None else 0.0
        rr = float(r.get('r_multiple') or 0.0) if r.get('r_multiple') is not None else None

        bo = by_open_session[osess]
        bo['total'] += 1
        if path != 'OPEN':
            bo['closed'] += 1
            bo['pnl'].append(pnl)
            if rr is not None:
                bo['r'].append(rr)
        if path == 'HIT_TP_WIN':
            bo['wins'] += 1
        elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            bo['partial_wins'] += 1
        elif path == 'HIT_SL_LOSS':
            bo['losses'] += 1
        elif path == 'MANUAL_OR_UNKNOWN_CLOSE':
            bo['manual_unknown'] += 1
        if float(r.get('tp_hit_ts') or 0.0) > 0:
            bo['tp_hits'] += 1
            if r.get('duration_to_tp_sec') is not None:
                durations_tp.append(float(r.get('duration_to_tp_sec') or 0.0))
        if float(r.get('alt_target_a_hit_ts') or 0.0) > 0:
            bo['alt_target_a_hits'] += 1
            if r.get('duration_to_alt_target_a_sec') is not None:
                durations_alt_target_a.append(float(r.get('duration_to_alt_target_a_sec') or 0.0))
        if float(r.get('sl_hit_ts') or 0.0) > 0:
            bo['sl_hits'] += 1
            if r.get('duration_to_sl_sec') is not None:
                durations_sl.append(float(r.get('duration_to_sl_sec') or 0.0))
        if str(r.get('risk_free_flag') or '').upper() == 'YES':
            bo['risk_free'] += 1

        bc = by_close_session[csess]
        if path != 'OPEN':
            bc['total'] += 1
            bc['closed'] += 1
            if path == 'HIT_TP_WIN':
                bc['wins'] += 1
            elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
                bc['partial_wins'] += 1
            elif path == 'HIT_SL_LOSS':
                bc['losses'] += 1
            elif path == 'MANUAL_OR_UNKNOWN_CLOSE':
                bc['manual_unknown'] += 1

        be = by_engine[eng]
        if path != 'OPEN':
            be['closed'] += 1
            if rr is not None:
                be['r'].append(rr)
        if path == 'HIT_TP_WIN':
            be['wins'] += 1
        elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            be['partial_wins'] += 1
        elif path == 'HIT_SL_LOSS':
            be['losses'] += 1

        bcg = by_conf[conf_bucket]
        if path != 'OPEN':
            bcg['closed'] += 1
            if rr is not None:
                bcg['r'].append(rr)
        if path == 'HIT_TP_WIN':
            bcg['wins'] += 1
        elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            bcg['partial_wins'] += 1
        elif path == 'HIT_SL_LOSS':
            bcg['losses'] += 1

        bq = by_quality[quality_bucket]
        if path != 'OPEN':
            bq['closed'] += 1
            if rr is not None:
                bq['r'].append(rr)
        if path == 'HIT_TP_WIN':
            bq['wins'] += 1
        elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            bq['partial_wins'] += 1
        elif path == 'HIT_SL_LOSS':
            bq['losses'] += 1

        sy = symbols[sym]
        sy['trades'] += 1
        sy['net_pnl'] += pnl
        if rr is not None:
            sy['r'].append(rr)
        if path == 'HIT_TP_WIN':
            sy['wins'] += 1
        elif path in {'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL'}:
            sy['partial_wins'] += 1
        elif path == 'HIT_SL_LOSS':
            sy['losses'] += 1
        elif path == 'MANUAL_OR_UNKNOWN_CLOSE':
            sy['manual_unknown'] += 1
        if float(r.get('tp_hit_ts') or 0.0) > 0:
            sy['tp_hits'] += 1
        if float(r.get('alt_target_a_hit_ts') or 0.0) > 0:
            sy['alt_target_a_hits'] += 1

    def _finalize_group(src: dict) -> dict:
        out = {}
        for k, v in src.items():
            decided_k = int(v.get('wins', 0) or 0) + int(v.get('partial_wins', 0) or 0) + int(v.get('losses', 0) or 0)
            tp_hits_k = int(v.get('tp_hits', 0) or 0)
            alt_target_a_hits_k = int(v.get('alt_target_a_hits', 0) or 0)
            out[k] = {
                **{kk: vv for kk, vv in v.items() if kk not in {'r', 'pnl'}},
                'avg_r': (sum(v.get('r') or []) / len(v.get('r') or [])) if (v.get('r') or []) else 0.0,
                'avg_pnl': (sum(v.get('pnl') or []) / len(v.get('pnl') or [])) if (v.get('pnl') or []) else 0.0,
                'win_rate': ((int(v.get('wins', 0) or 0) + int(v.get('partial_wins', 0) or 0)) / decided_k * 100.0) if decided_k > 0 else 0.0,
                'tp_hit_rate': (tp_hits_k / int(v.get('total', 0) or 1) * 100.0) if int(v.get('total', 0) or 0) > 0 else 0.0,
                'alt_target_a_conversion_after_tp': (alt_target_a_hits_k / tp_hits_k * 100.0) if tp_hits_k > 0 else 0.0,
                'sl_before_tp_rate': (int(v.get('losses', 0) or 0) / decided_k * 100.0) if decided_k > 0 else 0.0,
                'risk_free_save_rate': (int(v.get('risk_free', 0) or 0) / tp_hits_k * 100.0) if tp_hits_k > 0 else 0.0,
            }
        return out

    by_open_session_out = _finalize_group(by_open_session)
    by_close_session_out = _finalize_group(by_close_session)
    by_engine_out = _finalize_group(by_engine)
    by_conf_out = _finalize_group(by_conf)
    by_quality_out = _finalize_group(by_quality)

    symbol_rows = []
    for sym, v in symbols.items():
        tp_only_fails = max(0, int(v.get('tp_hits', 0) or 0) - int(v.get('alt_target_a_hits', 0) or 0))
        symbol_rows.append({
            'symbol': sym,
            'trades': int(v.get('trades', 0) or 0),
            'wins': int(v.get('wins', 0) or 0),
            'partial_wins': int(v.get('partial_wins', 0) or 0),
            'losses': int(v.get('losses', 0) or 0),
            'tp_hits': int(v.get('tp_hits', 0) or 0),
            'alt_target_a_hits': int(v.get('alt_target_a_hits', 0) or 0),
            'tp_only_fails': int(tp_only_fails),
            'net_pnl': float(v.get('net_pnl') or 0.0),
            'avg_r': (sum(v.get('r') or []) / len(v.get('r') or [])) if (v.get('r') or []) else 0.0,
        })
    top_winners = sorted(symbol_rows, key=lambda x: (float(x.get('net_pnl') or 0.0), float(x.get('avg_r') or 0.0)), reverse=True)[:5]
    top_losers = sorted(symbol_rows, key=lambda x: (float(x.get('net_pnl') or 0.0), float(x.get('avg_r') or 0.0)))[:5]
    tp_fail_symbols = sorted(
        [x for x in symbol_rows if int(x.get('tp_hits') or 0) >= 2 and int(x.get('tp_only_fails') or 0) > 0],
        key=lambda x: ((float(x.get('tp_only_fails') or 0.0) / max(1.0, float(x.get('tp_hits') or 0.0))), int(x.get('tp_hits') or 0)),
        reverse=True,
    )[:5]

    alt_target_a_conv = (alt_target_a_hits / tp_hits * 100.0) if tp_hits > 0 else 0.0
    sl_before_tp_rate = (losses / closed_decided * 100.0) if closed_decided > 0 else 0.0
    risk_free_save_rate = (risk_free / tp_hits * 100.0) if tp_hits > 0 else 0.0
    signs = []
    if tp_hits >= 8 and alt_target_a_conv < 35.0:
        signs.append('Take profit may still be too ambitious for some symbols.')
    if closed_decided >= 8 and sl_before_tp_rate >= 55.0:
        signs.append('Many trades hit SL before TP: stop may be too tight or entries too early.')
    avg_tp = (sum(durations_tp) / len(durations_tp)) if durations_tp else 0.0
    avg_sl = (sum(durations_sl) / len(durations_sl)) if durations_sl else 0.0
    if avg_sl > 0 and avg_tp > 0 and avg_sl > (avg_tp * 2.0):
        signs.append('Losing trades hold much longer than TP winners: stop placement may be too wide or trade management too slow.')
    if tp_hits >= 8 and risk_free_save_rate >= 25.0:
        signs.append('Single-TP mode is active, so break-even logic is no longer part of the trade path.')

    return {
        'rows': rows,
        'total': int(total),
        'wins': int(wins),
        'partial_wins': int(partial_wins),
        'losses': int(losses),
        'open': int(open_n),
        'manual_unknown': int(manual_unknown),
        'closed': int(sum(1 for r in rows if str(r.get('result_path') or '').upper() != 'OPEN')),
        'closed_decided': int(closed_decided),
        'tp_hits': int(tp_hits),
        'alt_target_a_hits': int(alt_target_a_hits),
        'sl_hits': int(sl_hits),
        'risk_free_trades': int(risk_free),
        'avg_pnl': float(avg_pnl),
        'avg_r': float(avg_r),
        'net_pnl': float(sum(pnls) if pnls else 0.0),
        'win_rate': float(win_rate),
        'alt_target_a_conversion_after_tp': float(alt_target_a_conv),
        'sl_before_tp_rate': float(sl_before_tp_rate),
        'risk_free_save_rate': float(risk_free_save_rate),
        'avg_time_to_tp_sec': float(avg_tp),
        'avg_time_to_alt_target_a_sec': float((sum(durations_alt_target_a) / len(durations_alt_target_a)) if durations_alt_target_a else 0.0),
        'avg_time_to_sl_sec': float(avg_sl),
        'by_open_session': by_open_session_out,
        'by_close_session': by_close_session_out,
        'by_engine': by_engine_out,
        'by_conf_bucket': by_conf_out,
        'by_quality_bucket': by_quality_out,
        'top_winning_symbols': top_winners,
        'top_losing_symbols': top_losers,
        'symbols_tp_but_fail_alt_target_a': tp_fail_symbols,
        'signs': signs,
    }


def _trade_lifecycle_build_trade_row(uid: int, trade: dict, user: dict, next_open_ts: float = 0.0,
                                     live_mode: bool = False, live_pos: dict | None = None,
                                     order_rows: list[dict] | None = None, closed_pnl_rows: list[dict] | None = None) -> tuple[dict, list[dict]]:
    now_ts = float(time.time())
    trade = dict(trade or {})
    trade_id = str(trade.get('trade_id') or '').strip()
    setup_id = _trade_lifecycle_safe_setup_id(trade)
    symbol = _bybit_linear_symbol(str(trade.get('symbol') or ''))
    side = _norm_trade_side(str(trade.get('side') or ''))
    entry = float(trade.get('entry') or 0.0)
    sl = float(trade.get('sl') or 0.0)
    tp_raw = trade.get('tp')
    alt_target_a_raw = trade.get('alt_target_a')
    alt_target_b_raw = trade.get('alt_target_b')
    tp, alt_target_a, _ = _ensure_three_tps(entry, sl, float(alt_target_b_raw or 0.0), tp_raw, alt_target_a_raw, side)
    opened_ts = float(trade.get('opened_ts') or 0.0)
    closed_ts_journal = float(trade.get('closed_ts') or 0.0)
    qty = abs(float(trade.get('qty') or 0.0))
    risk_usdt = float(_autotrade_estimated_risk_usd(entry, sl, qty) or 0.0)
    risk_pct, risk_note = _trade_lifecycle_risk_pct_estimate(int(uid), risk_usdt)
    rr1 = float(rr_to_tp(entry, sl, tp) or 0.0) if entry > 0 and sl > 0 and float(tp or 0.0) > 0 else None
    rr2 = float(rr_to_tp(entry, sl, alt_target_a) or 0.0) if entry > 0 and sl > 0 and float(alt_target_a or 0.0) > 0 else None

    open_session = str(trade.get('session') or '').upper().strip() or str((trade.get('source_session') or '')).upper().strip() or _session_label_from_ts(opened_ts)
    open_day = _autotrade_trade_day_label(opened_ts, user) if opened_ts > 0 else ''
    open_reason = str(trade.get('open_reason') or '').strip()

    window_end = float(next_open_ts or 0.0) - 1.0 if float(next_open_ts or 0.0) > float(opened_ts or 0.0) else 0.0
    if closed_ts_journal > 0:
        if window_end <= 0 or window_end > (closed_ts_journal + 21600.0):
            window_end = closed_ts_journal + 21600.0
    if window_end <= 0:
        window_end = now_ts + 300.0

    matched_orders = _trade_lifecycle_match_orders(symbol, side, order_rows or [], opened_ts, window_end)
    matched_pnl = _trade_lifecycle_match_closed_pnl(symbol, side, closed_pnl_rows or [], opened_ts, window_end)

    tp_events = _trade_lifecycle_pick_target_events(float(tp or 0.0), matched_orders, kind='tp') if float(tp or 0.0) > 0 else []
    alt_target_a_events = _trade_lifecycle_pick_target_events(float(alt_target_a or 0.0), matched_orders, kind='tp') if float(alt_target_a or 0.0) > 0 else []
    sl_events = _trade_lifecycle_generic_sl_events(matched_orders)
    manual_events = _trade_lifecycle_manual_close_events(matched_orders, side)
    positive_pnl_events = [ev for ev in matched_pnl if float(ev.get('pnl') or 0.0) > 0.0]
    negative_pnl_events = [ev for ev in matched_pnl if float(ev.get('pnl') or 0.0) < 0.0]

    tp_hit_ts = _trade_lifecycle_pick_ts([ev.get('ts') for ev in tp_events], pick='min')
    alt_target_a_hit_ts = _trade_lifecycle_pick_ts([ev.get('ts') for ev in alt_target_a_events], pick='min')
    sl_hit_ts = _trade_lifecycle_pick_ts([ev.get('ts') for ev in sl_events], pick='min')

    source_bits = []
    if bool(trade.get('_synthetic_backfill')):
        source_bits.append(str(trade.get('_synthetic_note') or 'setup_lifecycle_backfill'))
    source_conf = 'LOW'
    exchange_confirmed = 0
    if tp_events or alt_target_a_events or sl_events or manual_events or matched_pnl:
        exchange_confirmed = 1
        source_conf = 'MEDIUM'
    if tp_events or alt_target_a_events or sl_events:
        source_conf = 'HIGH'
        source_bits.append('bybit_order_history')
    elif matched_pnl:
        source_bits.append('bybit_closed_pnl')
    if risk_note and risk_note != 'risk_pct_from_user_setting':
        source_bits.append(risk_note)

    live_qty = abs(float(_pos_size(live_pos) or 0.0)) if live_pos is not None else 0.0
    if entry <= 0 and live_pos is not None:
        try:
            live_entry = float(_pos_entry(live_pos) or 0.0)
        except Exception:
            live_entry = 0.0
        if live_entry > 0:
            entry = float(live_entry)
            tp, alt_target_a, _ = _ensure_three_tps(entry, sl, float(alt_target_b_raw or 0.0), tp_raw, alt_target_a_raw, side)
            rr1 = float(rr_to_tp(entry, sl, tp) or 0.0) if entry > 0 and sl > 0 and float(tp or 0.0) > 0 else None
            rr2 = float(rr_to_tp(entry, sl, alt_target_a) or 0.0) if entry > 0 and sl > 0 and float(alt_target_a or 0.0) > 0 else None
    if qty <= 0 and live_qty > 0:
        qty = float(live_qty)
        risk_usdt = float(_autotrade_estimated_risk_usd(entry, sl, qty) or 0.0)
        risk_pct, risk_note = _trade_lifecycle_risk_pct_estimate(int(uid), risk_usdt)
    qty_reduction_confirmed = bool(live_pos is not None and qty > 0 and live_qty > 0 and live_qty < max(qty * 0.98, qty - max(1e-9, qty * 0.02)))
    if (tp_hit_ts is None) and positive_pnl_events:
        tp_hit_ts = _trade_lifecycle_pick_ts([ev.get('ts') for ev in positive_pnl_events], pick='min')
        source_bits.append('tp_from_positive_closed_pnl')
        source_conf = 'MEDIUM' if source_conf != 'HIGH' else source_conf
        exchange_confirmed = 1

    tp_confirmed = bool(tp_hit_ts or qty_reduction_confirmed)
    if qty_reduction_confirmed and tp_hit_ts is None:
        source_bits.append('tp_from_live_qty_reduction')
        source_conf = 'MEDIUM' if source_conf != 'HIGH' else source_conf
        exchange_confirmed = 1

    current_sl_price = 0.0
    if live_pos is not None:
        try:
            current_sl_price = float(_pos_stop(live_pos) or _bybit_detect_open_sl_price(symbol, side) or 0.0)
        except Exception:
            current_sl_price = 0.0
        if current_sl_price > 0:
            source_bits.append('live_position_sl_state')
            exchange_confirmed = 1
            if source_conf != 'HIGH':
                source_conf = 'MEDIUM'

    # Historical BE-stop evidence is used later when classifying TP -> risk-free paths.
    # This must be initialized here; otherwise the later reference can raise NameError,
    # which makes the sync loop silently skip valid trades and leaves
    # /trade_lifecycle_detail empty even when bot trades exist.
    be_stop_history_event = None
    try:
        be_stop_history_event = _trade_lifecycle_be_stop_history_event(
            side,
            entry,
            matched_orders,
            after_ts=float(tp_hit_ts or 0.0),
        )
        if be_stop_history_event is not None:
            source_bits.append('be_stop_from_order_history')
            exchange_confirmed = 1
            if source_conf == 'LOW':
                source_conf = 'MEDIUM'
    except Exception:
        be_stop_history_event = None

    be_sl_event = None
    non_be_sl_event = None
    for ev in (sl_events or []):
        try:
            if _trade_lifecycle_is_be_or_better(side, float(ev.get('price') or 0.0), entry):
                if be_sl_event is None or float(ev.get('ts') or 0.0) < float(be_sl_event.get('ts') or 0.0):
                    be_sl_event = ev
            else:
                if non_be_sl_event is None or float(ev.get('ts') or 0.0) < float(non_be_sl_event.get('ts') or 0.0):
                    non_be_sl_event = ev
        except Exception:
            continue

    status = str(trade.get('status') or '').upper().strip()
    if status == 'OPEN' and (live_pos is not None or not live_mode):
        result_path = 'OPEN'
        result_label = _trade_lifecycle_result_label(result_path)
        close_reason = ''
        final_close_ts = None
    else:
        result_path = 'MANUAL_OR_UNKNOWN_CLOSE'
        result_label = _trade_lifecycle_result_label(result_path)
        close_reason = result_label
        final_close_ts = closed_ts_journal or _trade_lifecycle_pick_ts([ev.get('ts') for ev in matched_pnl] + [ev.get('ts') for ev in manual_events], pick='max')
        if alt_target_a_hit_ts is not None and (sl_hit_ts is None or float(alt_target_a_hit_ts) <= float(sl_hit_ts) + 120.0):
            result_path = 'HIT_TP_WIN'
            result_label = _trade_lifecycle_result_label(result_path)
            close_reason = 'hit TP'
            final_close_ts = float(alt_target_a_hit_ts)
        elif sl_hit_ts is not None:
            if tp_confirmed:
                if be_sl_event is not None and _trade_lifecycle_is_be_or_better(side, float(be_sl_event.get('price') or 0.0), entry):
                    result_path = 'HIT_TP_THEN_BE_SL'
                    result_label = _trade_lifecycle_result_label(result_path)
                    close_reason = 'hit TP'
                    final_close_ts = float(be_sl_event.get('ts') or sl_hit_ts)
                else:
                    result_path = 'HIT_TP_THEN_SL'
                    result_label = _trade_lifecycle_result_label(result_path)
                    close_reason = 'hit TP'
                    final_close_ts = float((non_be_sl_event or {}).get('ts') or sl_hit_ts)
            else:
                result_path = 'HIT_SL_LOSS'
                result_label = _trade_lifecycle_result_label(result_path)
                close_reason = 'hit SL'
                final_close_ts = float(sl_hit_ts)
        elif status == 'OPEN' and live_pos is None:
            # Journal still shows OPEN but exchange no longer does; stay conservative.
            result_path = 'MANUAL_OR_UNKNOWN_CLOSE'
            result_label = _trade_lifecycle_result_label(result_path)
            close_reason = result_label
            final_close_ts = closed_ts_journal or _trade_lifecycle_pick_ts([ev.get('ts') for ev in matched_pnl] + [ev.get('ts') for ev in manual_events], pick='max')
        elif closed_ts_journal <= 0 and live_pos is None and not matched_pnl and not manual_events:
            result_path = 'OPEN'
            result_label = _trade_lifecycle_result_label(result_path)
            close_reason = ''
            final_close_ts = None

    risk_free_flag = 'NO'
    be_armed_ts = None
    be_hit_ts = None
    if tp_confirmed:
        if result_path == 'HIT_TP_THEN_BE_SL':
            risk_free_flag = 'YES'
            be_armed_ts = tp_hit_ts
            be_hit_ts = float((be_sl_event or {}).get('ts') or 0.0) or final_close_ts
        elif live_pos is not None and current_sl_price > 0 and _trade_lifecycle_is_be_or_better(side, current_sl_price, entry):
            risk_free_flag = 'YES'
            be_armed_ts = tp_hit_ts
        elif be_stop_history_event is not None:
            risk_free_flag = 'YES'
            be_armed_ts = float(tp_hit_ts or be_stop_history_event.get('ts') or 0.0) or None
        elif result_path == 'HIT_TP_WIN':
            risk_free_flag = 'UNKNOWN'
        elif result_path == 'HIT_TP_THEN_SL':
            risk_free_flag = 'NO'
        elif result_path == 'OPEN' and live_pos is not None and current_sl_price > 0:
            risk_free_flag = 'NO'
        else:
            risk_free_flag = 'UNKNOWN'

    close_ts = float(final_close_ts or 0.0) if final_close_ts else None
    if result_path == 'OPEN' and live_pos is not None:
        pnl_usdt = float(_pos_unreal_pnl(live_pos) or 0.0)
    else:
        try:
            pnl_usdt = float(trade.get('pnl_usdt') if trade.get('pnl_usdt') is not None else trade.get('pnl') or 0.0)
        except Exception:
            pnl_usdt = 0.0
        if abs(pnl_usdt) < 1e-9 and matched_pnl:
            pnl_usdt = float(sum(float(ev.get('pnl') or 0.0) for ev in matched_pnl))

    r_multiple = (float(pnl_usdt) / float(risk_usdt)) if risk_usdt > 0 and pnl_usdt is not None else None
    close_day = _autotrade_trade_day_label(close_ts, user) if close_ts else ''
    close_session = _session_label_from_ts(close_ts) if close_ts else ''
    duration_total_sec = (float(close_ts) - float(opened_ts)) if close_ts and opened_ts > 0 else ((now_ts - float(opened_ts)) if opened_ts > 0 else None)
    duration_to_tp_sec = (float(tp_hit_ts) - float(opened_ts)) if tp_hit_ts and opened_ts > 0 else None
    duration_to_alt_target_a_sec = (float(alt_target_a_hit_ts) - float(opened_ts)) if alt_target_a_hit_ts and opened_ts > 0 else None
    duration_to_sl_sec = (float(sl_hit_ts) - float(opened_ts)) if sl_hit_ts and opened_ts > 0 else None

    if result_path == 'MANUAL_OR_UNKNOWN_CLOSE' and manual_events:
        source_bits.append('manual_close_fill_detected')
        exchange_confirmed = 1
        if source_conf == 'LOW':
            source_conf = 'MEDIUM'
    elif result_path == 'MANUAL_OR_UNKNOWN_CLOSE' and matched_pnl:
        source_bits.append('exchange_closed_pnl_without_path_proof')
        exchange_confirmed = 1
        if source_conf == 'LOW':
            source_conf = 'MEDIUM'
    elif result_path == 'OPEN' and live_pos is not None:
        source_bits.append('live_position_open')
        exchange_confirmed = 1
        if source_conf == 'LOW':
            source_conf = 'MEDIUM'
    elif result_path in {'HIT_SL_LOSS', 'HIT_TP_THEN_BE_SL', 'HIT_TP_THEN_SL', 'HIT_TP_WIN'}:
        exchange_confirmed = 1

    if not source_bits and live_mode:
        source_bits.append('journal_only_no_exchange_match')
    elif not source_bits:
        source_bits.append('journal_only')

    events = []
    if opened_ts > 0:
        events.append({'event_type': 'OPEN', 'event_ts': opened_ts, 'price': entry, 'qty': qty, 'source': 'journal', 'details': {'open_session': open_session, 'setup_id': setup_id}})
    if tp_hit_ts is not None:
        events.append({'event_type': 'TP_HIT', 'event_ts': tp_hit_ts, 'price': float(tp or 0.0), 'qty': None, 'source': 'exchange' if exchange_confirmed else 'inferred', 'details': {'symbol': symbol}})
    if alt_target_a_hit_ts is not None:
        events.append({'event_type': 'TP_HIT', 'event_ts': alt_target_a_hit_ts, 'price': float(alt_target_a or 0.0), 'qty': None, 'source': 'exchange' if exchange_confirmed else 'inferred', 'details': {'symbol': symbol}})
    if sl_hit_ts is not None:
        sl_px = float((be_sl_event or non_be_sl_event or {}).get('price') or sl or 0.0)
        events.append({'event_type': 'SL_HIT', 'event_ts': sl_hit_ts, 'price': sl_px, 'qty': None, 'source': 'exchange' if exchange_confirmed else 'inferred', 'details': {'symbol': symbol}})
    if be_armed_ts is not None:
        events.append({'event_type': 'BE_ARMED', 'event_ts': be_armed_ts, 'price': entry, 'qty': None, 'source': 'exchange' if exchange_confirmed else 'inferred', 'details': {'risk_free_flag': risk_free_flag}})
    if be_hit_ts is not None:
        events.append({'event_type': 'BE_HIT', 'event_ts': be_hit_ts, 'price': entry, 'qty': None, 'source': 'exchange' if exchange_confirmed else 'inferred', 'details': {'risk_free_flag': risk_free_flag}})
    if close_ts is not None:
        events.append({'event_type': 'CLOSE', 'event_ts': close_ts, 'price': None, 'qty': None, 'pnl_usdt': pnl_usdt, 'source': 'exchange' if exchange_confirmed else 'journal', 'details': {'result_path': result_path, 'reason': close_reason}})

    row = {
        'trade_id': trade_id,
        'setup_id': setup_id,
        'uid': int(uid),
        'symbol': symbol,
        'side': side,
        'entry': entry,
        'sl': sl,
        'tp': float(tp or 0.0) if float(tp or 0.0) > 0 else None,
        'alt_target_a': float(alt_target_a or 0.0) if float(alt_target_a or 0.0) > 0 else None,
        'rr_tp_target': rr1,
        'rr_tp': rr2,
        'opened_ts': opened_ts if opened_ts > 0 else None,
        'closed_ts': close_ts,
        'open_day': open_day,
        'close_day': close_day,
        'open_session': open_session,
        'close_session': close_session,
        'risk_usdt': risk_usdt if risk_usdt > 0 else None,
        'risk_pct': risk_pct,
        'confidence': int(trade.get('conf') or 0) if trade.get('conf') is not None else None,
        'quality_score': float(trade.get('quality_score') or 0.0) if trade.get('quality_score') is not None else None,
        'engine': str(trade.get('engine') or ''),
        'open_reason': open_reason,
        'tp_hit_ts': tp_hit_ts,
        'alt_target_a_hit_ts': alt_target_a_hit_ts,
        'sl_hit_ts': sl_hit_ts,
        'be_armed_ts': be_armed_ts,
        'be_hit_ts': be_hit_ts,
        'result_path': result_path,
        'result_label': result_label,
        'close_reason': close_reason,
        'risk_free_flag': risk_free_flag,
        'pnl_usdt': pnl_usdt,
        'r_multiple': r_multiple,
        'duration_total_sec': duration_total_sec,
        'duration_to_tp_sec': duration_to_tp_sec,
        'duration_to_alt_target_a_sec': duration_to_alt_target_a_sec,
        'duration_to_sl_sec': duration_to_sl_sec,
        'source_confidence': source_conf,
        'source_note': '; '.join(dict.fromkeys([s for s in source_bits if s]))[:220],
        'exchange_confirmed': int(bool(exchange_confirmed)),
        'last_sync_ts': now_ts,
    }
    return row, events


def _trade_lifecycle_parse_details_json(raw) -> dict:
    try:
        if isinstance(raw, dict):
            return dict(raw)
        txt = str(raw or '').strip()
        if not txt:
            return {}
        obj = json.loads(txt)
        return dict(obj) if isinstance(obj, dict) else {}
    except Exception:
        return {}


def _trade_lifecycle_signal_snapshot(setup_id: str) -> dict:
    sid = str(setup_id or '').strip()
    if not sid:
        return {}
    out = {}
    try:
        sig = db_get_signal(sid) or {}
    except Exception:
        sig = {}
    if sig:
        out.update({
            'symbol': _bybit_linear_symbol(str(sig.get('symbol') or '')),
            'side': _norm_trade_side(str(sig.get('side') or '')),
            'created_ts': float(sig.get('created_ts') or 0.0),
            'conf': int(sig.get('conf') or 0) if sig.get('conf') is not None else None,
            'entry': float(sig.get('entry') or 0.0) if sig.get('entry') is not None else 0.0,
            'sl': float(sig.get('sl') or 0.0) if sig.get('sl') is not None else 0.0,
            'tp': float(sig.get('tp') or 0.0) if sig.get('tp') is not None else 0.0,
            'alt_target_a': float(sig.get('alt_target_a') or 0.0) if sig.get('alt_target_a') is not None else 0.0,
            'alt_target_b': float(sig.get('alt_target_b') or 0.0) if sig.get('alt_target_b') is not None else 0.0,
        })
    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            row = cur.execute(
                """SELECT created_ts, symbol, side, conf, source, session
                       FROM generated_setups WHERE setup_id=?
                       ORDER BY created_ts DESC LIMIT 1""",
                (sid,),
            ).fetchone()
            if row:
                if not out.get('created_ts'):
                    out['created_ts'] = float(row['created_ts'] or 0.0)
                if not out.get('symbol'):
                    out['symbol'] = _bybit_linear_symbol(str(row['symbol'] or ''))
                if not out.get('side'):
                    out['side'] = _norm_trade_side(str(row['side'] or ''))
                if out.get('conf') is None and row['conf'] is not None:
                    out['conf'] = int(row['conf'] or 0)
                if not out.get('source_kind') and row['source']:
                    out['source_kind'] = str(row['source'] or '')
                if not out.get('session') and row['session']:
                    out['session'] = str(row['session'] or '')
            row2 = cur.execute(
                """SELECT session, source_kind, state, details_json
                       FROM admin_setup_lifecycle WHERE setup_id=?
                       ORDER BY COALESCE(executed_ts, attempted_ts, executable_ts, emailed_ts, signal_created_ts, generated_logged_ts, 0) DESC
                       LIMIT 1""",
                (sid,),
            ).fetchone()
            if row2:
                det = _trade_lifecycle_parse_details_json(row2['details_json'])
                if not out.get('session') and row2['session']:
                    out['session'] = str(row2['session'] or '')
                if not out.get('source_kind') and row2['source_kind']:
                    out['source_kind'] = str(row2['source_kind'] or '')
                if not out.get('open_reason'):
                    state_txt = str(row2['state'] or '').strip()
                    source_kind = str(row2['source_kind'] or '').strip()
                    if source_kind and state_txt:
                        out['open_reason'] = f"{source_kind}:{state_txt}"
                    elif state_txt:
                        out['open_reason'] = state_txt
                if not out.get('engine'):
                    out['engine'] = str(det.get('engine') or det.get('strategy') or '')
                if out.get('quality_score') is None and det.get('quality_score') not in (None, ''):
                    out['quality_score'] = float(det.get('quality_score'))
    except Exception:
        pass
    return out


def _trade_lifecycle_is_executed_lifecycle_row(life: dict) -> bool:
    try:
        state = str((life or {}).get('state') or '').strip().lower()
        if state.startswith('executed'):
            return True
        if 'live_opened' in state or 'paper_opened' in state:
            return True
        if state in {'closed', 'executed_closed'}:
            return True
        if float((life or {}).get('executed_ts') or 0.0) > 0:
            return True
        if str((life or {}).get('trade_id') or '').strip():
            return True
        if str((life or {}).get('bybit_order_id') or '').strip() or str((life or {}).get('bybit_order_link_id') or '').strip():
            return True
        if str((life or {}).get('bybit_position_symbol') or '').strip():
            return True
    except Exception:
        return False
    return False


def _trade_lifecycle_synthetic_trade_id(prefix: str, setup_id: str, opened_ts: float = 0.0) -> str:
    sid = re.sub(r'[^A-Za-z0-9_-]+', '-', str(setup_id or '').strip()) or 'UNKNOWN'
    ts_txt = str(int(float(opened_ts or 0.0))) if float(opened_ts or 0.0) > 0 else '0'
    return f"{str(prefix or 'TL').upper()}-{sid}-{ts_txt}"


def _trade_lifecycle_collect_candidates(owner_uid: int, sync_cutoff: float, days: int = 30) -> list[dict]:
    owner_uid = int(owner_uid)
    _autotrade_migrate_tables()
    _admin_setup_lifecycle_migrate()
    base_rows = []
    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            rows = cur.execute(
                """
                SELECT * FROM autotrade_trades
                WHERE uid=? AND (
                    COALESCE(opened_ts,0)>=? OR COALESCE(closed_ts,0)>=? OR UPPER(COALESCE(status,''))='OPEN'
                )
                ORDER BY COALESCE(opened_ts,0) ASC, COALESCE(closed_ts,0) ASC
                """,
                (owner_uid, float(sync_cutoff), float(sync_cutoff)),
            ).fetchall() or []
            base_rows = [dict(r) for r in rows]
    except Exception:
        base_rows = []

    out = []
    seen_trade_ids = set()
    seen_setup_ids = set()

    def _remember(row: dict):
        d = dict(row or {})
        tid = str(d.get('trade_id') or '').strip()
        sid = str(d.get('setup_id') or '').strip()
        if tid:
            seen_trade_ids.add(tid)
        if sid:
            seen_setup_ids.add(sid)
        out.append(d)

    for row in (base_rows or []):
        _remember(row)

    try:
        provisional = _autotrade_reconstruct_provisional_closes(owner_uid, days=max(7, int(days or 30) + 5)) or []
    except Exception:
        provisional = []
    for p in provisional:
        try:
            sid = str((p or {}).get('setup_id') or '').strip()
            tid = str((p or {}).get('trade_id') or '').strip() or _trade_lifecycle_synthetic_trade_id('TLPROV', sid or ((p or {}).get('symbol') or 'TRADE'), (p or {}).get('opened_ts') or (p or {}).get('closed_ts') or 0.0)
            if tid in seen_trade_ids or (sid and sid in seen_setup_ids):
                continue
            snap = _trade_lifecycle_signal_snapshot(sid)
            opened_ts = float((p or {}).get('opened_ts') or snap.get('created_ts') or 0.0)
            closed_ts = float((p or {}).get('closed_ts') or 0.0)
            row = {
                'trade_id': tid,
                'uid': owner_uid,
                'opened_ts': opened_ts,
                'session': _session_label_from_ts(opened_ts) if opened_ts > 0 else '',
                'setup_id': sid,
                'symbol': _bybit_linear_symbol(str((p or {}).get('symbol') or snap.get('symbol') or '')),
                'side': _norm_trade_side(str((p or {}).get('side') or snap.get('side') or '')),
                'entry': float((snap.get('entry') or 0.0) or 0.0),
                'sl': float((snap.get('sl') or 0.0) or 0.0),
                'tp': float((snap.get('tp') or 0.0) or 0.0),
                'alt_target_a': float((snap.get('alt_target_a') or 0.0) or 0.0),
                'alt_target_b': float((snap.get('alt_target_b') or 0.0) or 0.0),
                'qty': 0.0,
                'conf': snap.get('conf'),
                'quality_score': None,
                'atr_pct': None,
                'engine': str(snap.get('engine') or ''),
                'open_reason': str(snap.get('open_reason') or 'provisional_exchange_match_from_setup_history'),
                'status': 'CLOSED',
                'closed_ts': closed_ts,
                'pnl_usdt': float((p or {}).get('pnl') or (p or {}).get('pnl_usdt') or 0.0),
                'outcome': str((p or {}).get('outcome') or ''),
                'note': str((p or {}).get('note') or 'provisional_exchange_match_from_setup_history'),
                '_synthetic_backfill': True,
                '_synthetic_note': 'setup_linked_provisional_close',
            }
            if row['symbol'] and row['side']:
                _remember(row)
        except Exception:
            continue

    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            life_rows = cur.execute(
                """
                SELECT * FROM admin_setup_lifecycle
                WHERE uid=? AND (
                    COALESCE(executed_ts,0)>=? OR COALESCE(closed_ts,0)>=? OR (
                        COALESCE(closed_ts,0)<=0 AND (
                            TRIM(COALESCE(trade_id,''))<>'' OR
                            TRIM(COALESCE(bybit_order_id,''))<>'' OR
                            TRIM(COALESCE(bybit_order_link_id,''))<>'' OR
                            TRIM(COALESCE(bybit_position_symbol,''))<>'' OR
                            UPPER(COALESCE(state,'')) LIKE 'EXECUTED%' OR
                            LOWER(COALESCE(state,'')) LIKE '%open%'
                        )
                    )
                )
                ORDER BY COALESCE(executed_ts, attempted_ts, executable_ts, emailed_ts, signal_created_ts, generated_logged_ts, 0) ASC
                """,
                (owner_uid, float(sync_cutoff), float(sync_cutoff)),
            ).fetchall() or []
            life_rows = [dict(r) for r in life_rows]
    except Exception:
        life_rows = []

    for life in life_rows:
        try:
            if not _trade_lifecycle_is_executed_lifecycle_row(life):
                continue
            sid = str((life or {}).get('setup_id') or '').strip()
            trade_id = str((life or {}).get('trade_id') or '').strip() or _trade_lifecycle_synthetic_trade_id('TLLIFE', sid or ((life or {}).get('symbol') or 'TRADE'), (life or {}).get('executed_ts') or (life or {}).get('attempted_ts') or 0.0)
            if trade_id in seen_trade_ids or (sid and sid in seen_setup_ids):
                continue
            snap = _trade_lifecycle_signal_snapshot(sid)
            details = _trade_lifecycle_parse_details_json((life or {}).get('details_json'))
            opened_ts = float((life or {}).get('executed_ts') or (life or {}).get('attempted_ts') or (life or {}).get('executable_ts') or (life or {}).get('emailed_ts') or (life or {}).get('signal_created_ts') or (life or {}).get('generated_logged_ts') or snap.get('created_ts') or 0.0)
            if opened_ts <= 0:
                continue
            symbol = _bybit_linear_symbol(str(snap.get('symbol') or details.get('symbol') or (life or {}).get('symbol') or (life or {}).get('bybit_position_symbol') or ''))
            side = _norm_trade_side(str(snap.get('side') or details.get('side') or (life or {}).get('side') or ''))
            if not symbol or not side:
                continue
            state_txt = str((life or {}).get('state') or '').strip().lower()
            closed_ts = float((life or {}).get('closed_ts') or 0.0)
            status = 'CLOSED' if (closed_ts > 0 or str((life or {}).get('outcome') or '').strip() or 'closed' in state_txt) else 'OPEN'
            row = {
                'trade_id': trade_id,
                'uid': owner_uid,
                'opened_ts': opened_ts,
                'session': str((life or {}).get('session') or _session_label_from_ts(opened_ts) or ''),
                'setup_id': sid,
                'symbol': symbol,
                'side': side,
                'entry': float(details.get('entry') or snap.get('entry') or 0.0),
                'sl': float(details.get('sl') or snap.get('sl') or 0.0),
                'tp': float(details.get('tp') or snap.get('tp') or 0.0),
                'alt_target_a': float(details.get('alt_target_a') or snap.get('alt_target_a') or 0.0),
                'alt_target_b': float(details.get('alt_target_b') or snap.get('alt_target_b') or 0.0),
                'qty': float(details.get('qty') or 0.0),
                'conf': (details.get('conf') if details.get('conf') is not None else snap.get('conf')),
                'quality_score': (float(details.get('quality_score')) if details.get('quality_score') not in (None, '') else None),
                'atr_pct': (float(details.get('atr_pct')) if details.get('atr_pct') not in (None, '') else None),
                'engine': str(details.get('engine') or details.get('strategy') or snap.get('engine') or ''),
                'open_reason': str(details.get('open_reason') or snap.get('open_reason') or ((life or {}).get('source_kind') or '') or 'bot_executed_setup'),
                'status': status,
                'closed_ts': closed_ts if closed_ts > 0 else None,
                'pnl_usdt': (float((life or {}).get('pnl_usdt') or 0.0) if ((life or {}).get('pnl_usdt') is not None) else 0.0),
                'outcome': str((life or {}).get('outcome') or ''),
                'note': str((life or {}).get('last_reason') or 'setup_lifecycle_backfill'),
                '_synthetic_backfill': True,
                '_synthetic_note': ('setup_lifecycle_backfill:' + state_txt)[:120],
            }
            _remember(row)
        except Exception:
            continue

    out.sort(key=lambda r: (float((r or {}).get('opened_ts') or 0.0), float((r or {}).get('closed_ts') or 0.0), str((r or {}).get('trade_id') or '')))
    return out


def _trade_lifecycle_sync(owner_uid: int, days: int = 30, force: bool = False) -> dict:
    owner_uid = int(owner_uid)
    _trade_lifecycle_migrate()
    _autotrade_migrate_tables()
    if owner_uid <= 0:
        return {'synced': 0, 'rows': 0, 'skipped': 0}
    cache_key = f"trade_lifecycle_sync:{owner_uid}:{int(days)}"
    if (not force):
        try:
            if cache_valid(cache_key, 90):
                return dict(cache_get(cache_key) or {'synced': 0, 'rows': 0, 'skipped': 0})
        except Exception:
            pass

    user = _autotrade_user_settings(owner_uid)
    tz = _user_tzinfo(user)
    start_local, _ = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(user))
    start_local = start_local - timedelta(days=max(1, int(days)) - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    sync_cutoff = start_ts - 86400.0 * 5.0

    try:
        if str(AUTOTRADE_MODE).lower() == 'live' and owner_uid == int(AUTOTRADE_OWNER_UID or owner_uid):
            _autotrade_sync_closed_trades_from_exchange(owner_uid, lookback_days=max(14, int(days) + 5))
    except Exception:
        pass

    try:
        trades = _trade_lifecycle_collect_candidates(owner_uid, float(sync_cutoff), days=int(days))
    except Exception:
        trades = []

    if not trades:
        out = {'synced': 0, 'rows': 0, 'skipped': 0}
        try:
            cache_set(cache_key, out)
        except Exception:
            pass
        return out

    by_key = defaultdict(list)
    for t in trades:
        key = (_bybit_linear_symbol(str(t.get('symbol') or '')), _norm_trade_side(str(t.get('side') or '')))
        by_key[key].append(t)
    for key in list(by_key.keys()):
        by_key[key].sort(key=lambda r: float(r.get('opened_ts') or 0.0))

    windows = {}
    symbol_ranges = defaultdict(lambda: {'start': None, 'end': None})
    now_ts = float(time.time())
    for key, items in by_key.items():
        for i, tr in enumerate(items):
            opened_ts = float(tr.get('opened_ts') or 0.0)
            next_open_ts = float(items[i + 1].get('opened_ts') or 0.0) if i + 1 < len(items) else 0.0
            closed_ts = float(tr.get('closed_ts') or 0.0)
            end_ts = (next_open_ts - 1.0) if next_open_ts > opened_ts else (closed_ts + 21600.0 if closed_ts > 0 else now_ts + 300.0)
            windows[str(tr.get('trade_id') or '')] = {'next_open_ts': next_open_ts, 'window_end': end_ts}
            rng = symbol_ranges[key[0]]
            st = max(0.0, opened_ts - 86400.0)
            et = max(float(end_ts or 0.0), closed_ts, now_ts if str(tr.get('status') or '').upper().strip() == 'OPEN' else 0.0) + 3600.0
            rng['start'] = st if rng['start'] is None else min(float(rng['start']), st)
            rng['end'] = et if rng['end'] is None else max(float(rng['end']), et)

    live_mode = bool(str(AUTOTRADE_MODE).lower() == 'live' and owner_uid == int(AUTOTRADE_OWNER_UID or owner_uid))
    position_map = {}
    if live_mode:
        try:
            for p in (_bybit_get_open_positions_linear() or []):
                key = (_pos_symbol(p), _pos_side_text(p))
                if key[0] and key[1]:
                    position_map[key] = p
        except Exception:
            position_map = {}

    order_cache = {}
    pnl_cache = {}
    if live_mode:
        for sym, rng in symbol_ranges.items():
            try:
                order_cache[sym] = _bybit_get_order_history_linear(sym, float(rng['start'] or 0.0), float(rng['end'] or (now_ts + 3600.0)), limit=200)
            except Exception:
                order_cache[sym] = []
            try:
                pnl_cache[sym] = _bybit_get_closed_pnl_linear(float(rng['start'] or 0.0), float(rng['end'] or (now_ts + 3600.0)), symbol=sym, limit=200)
            except Exception:
                pnl_cache[sym] = []

    synced = 0
    for tr in trades:
        try:
            tid = str(tr.get('trade_id') or '').strip()
            if not tid:
                continue
            sym = _bybit_linear_symbol(str(tr.get('symbol') or ''))
            side = _norm_trade_side(str(tr.get('side') or ''))
            live_pos = position_map.get((sym, side)) if live_mode else None
            win = windows.get(tid) or {}
            row, events = _trade_lifecycle_build_trade_row(
                owner_uid,
                tr,
                user,
                next_open_ts=float(win.get('next_open_ts') or 0.0),
                live_mode=live_mode,
                live_pos=live_pos,
                order_rows=order_cache.get(sym) or [],
                closed_pnl_rows=pnl_cache.get(sym) or [],
            )
            _trade_lifecycle_upsert_row(row)
            _trade_lifecycle_store_events(tid, events)
            synced += 1
        except Exception:
            continue

    out = {'synced': int(synced), 'rows': int(len(trades)), 'skipped': int(max(0, len(trades) - synced))}
    try:
        cache_set(cache_key, out)
    except Exception:
        pass
    return out


def _trade_lifecycle_analytics(owner_uid: int, days: int = 30, session: str = 'ALL', sync: bool = True, force: bool = False) -> dict:
    owner_uid = int(owner_uid)
    days = int(max(1, min(int(days or 30), 3650)))
    owner_user = _autotrade_user_settings(owner_uid)
    tz = _user_tzinfo(owner_user)
    start_local, _ = _anchored_day_window(datetime.now(tz), _user_day_reset_hhmm(owner_user))
    start_local = start_local - timedelta(days=days - 1)
    start_ts = float(start_local.astimezone(timezone.utc).timestamp())
    cache_key = f"trade_lifecycle_analytics:{owner_uid}:{days}:{str(session or 'ALL').upper()}"
    if (not force):
        try:
            if cache_valid(cache_key, 120):
                return dict(cache_get(cache_key) or {})
        except Exception:
            pass
    if sync:
        try:
            sync_days = max(7, days)
            sync_gate = f"trade_lifecycle_sync_guard:{owner_uid}:{int(sync_days)}"
            if force or (not cache_valid(sync_gate, 300)):
                _trade_lifecycle_sync(owner_uid, days=sync_days, force=force)
                cache_set(sync_gate, {'ts': time.time()})
        except Exception:
            pass
    rows = _trade_lifecycle_query_rows(owner_uid, start_ts=float(start_ts), session=session)
    out = _trade_lifecycle_metrics_from_rows(rows)
    out['days'] = int(days)
    out['session_filter'] = str(session or 'ALL').upper().strip() or 'ALL'
    out['start_ts'] = float(start_ts)
    try:
        cache_set(cache_key, out)
    except Exception:
        pass
    return out


def _trade_lifecycle_detail_row(owner_uid: int, ident: str, sync: bool = True) -> dict:
    owner_uid = int(owner_uid)
    key = str(ident or '').strip()
    if not key:
        return {}
    if sync:
        try:
            _trade_lifecycle_sync(owner_uid, days=90, force=False)
        except Exception:
            pass
    keys = []
    for cand in [key, key.upper(), key.lower()]:
        cand = str(cand or '').strip()
        if cand:
            keys.append(cand)
            if cand.startswith('ID-'):
                keys.append(cand[3:])
            else:
                keys.append(f'ID-{cand}')
    norm_keys = []
    seen = set()
    for item in keys:
        item = str(item or '').strip()
        if item and item not in seen:
            seen.add(item)
            norm_keys.append(item)
    if not norm_keys:
        return {}
    _trade_lifecycle_migrate()
    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            placeholders = ','.join(['?'] * len(norm_keys))
            row = cur.execute(
                f"SELECT * FROM trade_lifecycle WHERE uid=? AND (trade_id IN ({placeholders}) OR setup_id IN ({placeholders})) ORDER BY COALESCE(opened_ts,0) DESC LIMIT 1",
                tuple([owner_uid] + norm_keys + norm_keys),
            ).fetchone()
            return dict(row) if row else {}
    except Exception:
        return {}


def _trade_lifecycle_recent_email_rows(owner_uid: int, start_ts: float, session: str = 'ALL', limit: int = 200) -> list[dict]:
    owner_uid = int(owner_uid)
    _trade_lifecycle_migrate()
    params = [owner_uid, float(start_ts or 0.0)]
    q = """
        SELECT
            e.setup_id,
            e.session AS emailed_session,
            e.emailed_ts,
            x.executable_ts,
            s.symbol,
            s.side,
            s.conf,
            s.entry,
            s.sl,
            s.tp,
            s.alt_target_a,
            tl.trade_id,
            tl.result_path,
            tl.result_label,
            tl.opened_ts,
            tl.closed_ts,
            tl.open_session,
            tl.close_session,
            tl.pnl_usdt,
            tl.r_multiple,
            tl.risk_free_flag,
            tl.exchange_confirmed,
            tl.source_note
        FROM emailed_setups e
        LEFT JOIN executable_setups x
               ON x.user_id=e.user_id AND x.setup_id=e.setup_id
        LEFT JOIN signals s
               ON s.setup_id=e.setup_id
        LEFT JOIN trade_lifecycle tl
               ON tl.uid=e.user_id AND tl.setup_id=e.setup_id
        WHERE e.user_id=? AND e.emailed_ts>=?
    """
    sess = str(session or 'ALL').upper().strip()
    if sess in {'ASIA', 'LON', 'NY'}:
        q += " AND UPPER(COALESCE(e.session,''))=?"
        params.append(sess)
    q += " ORDER BY COALESCE(e.emailed_ts,0) DESC LIMIT ?"
    params.append(int(max(1, min(int(limit or 200), 500))))
    try:
        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            return [dict(r) for r in (cur.execute(q, tuple(params)).fetchall() or [])]
    except Exception:
        return []


def _trade_lifecycle_render_row(r: dict, user: dict, show_trade_id: bool = True) -> list[str]:
    trade_id = str(r.get('trade_id') or '').strip()
    setup_id = str(r.get('setup_id') or '').strip()
    symbol = str(r.get('symbol') or '?')
    side = str(r.get('side') or '?')
    open_ts = float(r.get('opened_ts') or 0.0)
    close_ts = float(r.get('closed_ts') or 0.0)
    open_txt = _trade_lifecycle_time_text(open_ts)
    close_txt = _trade_lifecycle_time_text(close_ts)
    open_day_txt = _trade_lifecycle_day_text(open_ts, user, str(r.get('open_day') or ''))
    close_day_txt = _trade_lifecycle_day_text(close_ts, user, str(r.get('close_day') or '')) if close_ts > 0 else '—'
    hits = ', '.join(_trade_lifecycle_levels_hit(r)) or '—'
    confirm_txt = 'exchange-confirmed' if int(r.get('exchange_confirmed') or 0) == 1 else 'inferred'
    sync_note = str(r.get('source_note') or '').strip()
    open_reason = _trade_lifecycle_reason_text(r.get('open_reason'))
    engine_txt = _trade_lifecycle_engine_text(r.get('engine'))
    risk_free_txt = _trade_lifecycle_bool_text(r.get('risk_free_flag'))
    tp_hit_txt = _trade_lifecycle_hit_text(r.get('tp_hit_ts'))
    alt_target_a_hit_txt = _trade_lifecycle_hit_text(r.get('alt_target_a_hit_ts'))
    sl_hit_txt = _trade_lifecycle_hit_text(r.get('sl_hit_ts'))
    be_move_txt = risk_free_txt if tp_hit_txt == 'YES' else 'NO'
    header = f"• {symbol} {side} | {str(r.get('result_path') or '').upper()}"
    if show_trade_id:
        header += f" | {trade_id}"
    if setup_id:
        header += f" | {setup_id}"
    lines = [header]
    lines.append(
        f"  Entry {fmt_price(float(r.get('entry') or 0.0)) if float(r.get('entry') or 0.0) > 0 else '—'} | SL {fmt_price(float(r.get('sl') or 0.0)) if float(r.get('sl') or 0.0) > 0 else '—'} | TP {fmt_price(float(_resolve_single_tp(float(r.get('entry') or 0.0), float(r.get('sl') or 0.0), r.get('tp'), r.get('alt_target_a'), r.get('alt_target_b'), str(r.get('side') or '')) or 0.0)) if float(_resolve_single_tp(float(r.get('entry') or 0.0), float(r.get('sl') or 0.0), r.get('tp'), r.get('alt_target_a'), r.get('alt_target_b'), str(r.get('side') or '')) or 0.0) > 0 else '—'}"
    )
    lines.append(
        f"  RR {_trade_lifecycle_fmt_value(r.get('rr_tp_target') or r.get('rr_tp'), '.2f')} | Risk {_trade_lifecycle_fmt_value(r.get('risk_usdt'), '.2f')} USDT ({_trade_lifecycle_fmt_value(r.get('risk_pct'), '.2f')}%) | Conf {str(r.get('confidence') if r.get('confidence') is not None else '—')} | Q {_trade_lifecycle_fmt_value(r.get('quality_score'), '.1f')}"
    )
    lines.append(
        f"  Open {open_txt} | Open Day {open_day_txt} | Open Session {str(r.get('open_session') or '—')} | Open Reason {open_reason} | Engine {engine_txt}"
    )
    lines.append(
        f"  Result {str(r.get('result_label') or '—')} | Path {str(r.get('result_path') or '—')} | Hits {hits} | TP {tp_hit_txt if tp_hit_txt == 'YES' or alt_target_a_hit_txt == 'YES' else 'NO'} | SL {sl_hit_txt}"
    )
    lines.append(
        f"  Close {close_txt} | Close Day {close_day_txt} | Close Session {str(r.get('close_session') or '—') if close_ts > 0 else '—'} | Reason {str(r.get('close_reason') or ('open' if str(r.get('result_path') or '').upper() == 'OPEN' else '—'))}"
    )
    lines.append(
        f"  TP {_trade_lifecycle_fmt_duration(r.get('duration_to_tp_sec') or r.get('duration_to_alt_target_a_sec'))} | SL {_trade_lifecycle_fmt_duration(r.get('duration_to_sl_sec'))} | Total {_trade_lifecycle_fmt_duration(r.get('duration_total_sec'))}"
    )
    lines.append(
        f"  PnL {_trade_lifecycle_fmt_value(r.get('pnl_usdt'), '.2f')} USDT | R {_trade_lifecycle_fmt_value(r.get('r_multiple'), '.2f')} | {confirm_txt}" + (f" | Note {sync_note}" if sync_note else '')
    )
    return lines


def _trade_lifecycle_recent_report(owner_uid: int, hours: int = 48, session: str = 'ALL') -> str:
    owner_uid = int(owner_uid)
    hours = int(max(1, min(int(hours or 48), 24 * 90)))
    session = str(session or 'ALL').upper().strip() or 'ALL'
    sync_days = max(7, int(math.ceil(float(hours) / 24.0)) + 3)
    try:
        _trade_lifecycle_sync(owner_uid, days=sync_days, force=True)
    except Exception:
        pass
    start_ts = float(time.time()) - float(hours) * 3600.0
    rows = _trade_lifecycle_query_rows(owner_uid, start_ts=float(start_ts), session=session)
    analytics = _trade_lifecycle_metrics_from_rows(rows)

    lines = [
        '🧬 Trade Lifecycle Detail',
        HDR,
        f"Window: last {hours} hour(s) | Session: {session}",
        *_trade_lifecycle_analytics_lines(analytics, heading='Lifecycle summary', include_sessions=True, include_engines=True, include_buckets=True, include_symbols=True, include_signs=True, max_signs=3),
        SEP,
        'Detailed trades',
    ]
    if not rows:
        lines.append('• No bot trades found in this rolling window.')
        return '\n'.join(lines)

    user = _autotrade_user_settings(owner_uid)
    for r in rows[:60]:
        lines.extend(_trade_lifecycle_render_row(r, user, show_trade_id=True))
    if len(rows) > 60:
        lines.append(f"Showing first 60 of {len(rows)} real bot trades in this window.")
    return '\n'.join(lines)


def _trade_lifecycle_compact_report(owner_uid: int, days: int = 7, session: str = 'ALL') -> str:
    analytics = _trade_lifecycle_analytics(owner_uid, days=days, session=session, sync=True, force=True)
    rows = analytics.get('rows') or []
    summary = [
        '🧬 Trade Lifecycle Analytics',
        HDR,
        f"Window: last {int(analytics.get('days') or days)} anchored trading day(s) | Session: {str(analytics.get('session_filter') or session).upper()}",
        *_trade_lifecycle_analytics_lines(analytics, heading='Lifecycle summary', include_sessions=True, include_engines=True, include_buckets=True, include_symbols=True, include_signs=True, max_signs=3),
        SEP,
        'Detailed trades',
    ]
    if not rows:
        summary.append('• No bot trades found in this window.')
        return '\n'.join(summary)

    user = _autotrade_user_settings(owner_uid)
    for r in rows[:80]:
        summary.extend(_trade_lifecycle_render_row(r, user, show_trade_id=True))
    if len(rows) > 80:
        summary.extend([SEP, f"Showing first 80 of {len(rows)} trades. Narrow the window with /trade_lifecycle <days> [ASIA|LON|NY]."])
    return '\n'.join(summary)




def _trade_lifecycle_recent_analytics(owner_uid: int, hours: int = 48, session: str = 'ALL', force: bool = False) -> dict:
    owner_uid = int(owner_uid)
    hours = int(max(1, min(int(hours or 48), 24 * 90)))
    session = str(session or 'ALL').upper().strip() or 'ALL'
    sync_days = max(7, int(math.ceil(float(hours) / 24.0)) + 3)
    try:
        _trade_lifecycle_sync(owner_uid, days=sync_days, force=bool(force))
    except Exception:
        pass
    start_ts = float(time.time()) - float(hours) * 3600.0
    out = _trade_lifecycle_metrics_from_rows(_trade_lifecycle_query_rows(owner_uid, start_ts=float(start_ts), session=session))
    out['hours'] = int(hours)
    out['session_filter'] = session
    return out


def _trade_lifecycle_best_bucket(group_map: dict, metric: str = 'avg_r', min_sample: int = 3, prefer_high: bool = True) -> tuple[str, dict]:
    items = []
    for name, data in (group_map or {}).items():
        d = dict(data or {})
        sample = int(d.get('closed') or d.get('total') or 0)
        if sample < int(min_sample):
            continue
        try:
            score = float(d.get(metric) or 0.0)
        except Exception:
            score = 0.0
        items.append((str(name), d, sample, score))
    if not items:
        return '', {}
    items.sort(key=lambda x: (x[3], x[2], x[0]), reverse=bool(prefer_high))
    return items[0][0], items[0][1]


def _trade_lifecycle_analytics_lines(analytics: dict, heading: str = 'Lifecycle analytics', include_sessions: bool = True,
                                    include_engines: bool = True, include_buckets: bool = True,
                                    include_symbols: bool = True, include_signs: bool = True,
                                    max_signs: int = 3) -> list[str]:
    a = dict(analytics or {})
    total = int(a.get('total') or 0)
    if total <= 0:
        return [heading, '• No exchange-backed executed bot trades in this window yet.']

    closed = int(a.get('closed_decided') or a.get('closed') or 0)
    tp_hits = int(a.get('tp_hits') or 0)
    tp_hit_rate = (float(tp_hits) / float(total) * 100.0) if total > 0 else 0.0
    lines = [heading]
    lines.append(
        f"• Trades {total} | Closed {closed} | WR {float(a.get('win_rate') or 0.0):.1f}% | AvgR {float(a.get('avg_r') or 0.0):+.2f} | Net {float(a.get('net_pnl') or 0.0):+.2f} USDT"
    )
    lines.append(
        f"• TP hit {tp_hits + int(a.get('alt_target_a_hits') or 0)} ({tp_hit_rate:.1f}%) | SL hits {int(a.get('sl_hits') or 0)}"
    )
    lines.append(
        f"• Timing: TP {_trade_lifecycle_fmt_duration(a.get('avg_time_to_tp_sec') or a.get('avg_time_to_alt_target_a_sec'))} | SL {_trade_lifecycle_fmt_duration(a.get('avg_time_to_sl_sec'))}"
    )

    if include_sessions:
        best_sess_name, best_sess = _trade_lifecycle_best_bucket(a.get('by_open_session') or {}, metric='avg_r', min_sample=2, prefer_high=True)
        weak_sess_name, weak_sess = _trade_lifecycle_best_bucket(a.get('by_open_session') or {}, metric='avg_r', min_sample=2, prefer_high=False)
        if best_sess_name:
            lines.append(
                f"• Best open session: {best_sess_name} | WR {float(best_sess.get('win_rate') or 0.0):.1f}% | AvgR {float(best_sess.get('avg_r') or 0.0):+.2f}"
            )
        if weak_sess_name:
            lines.append(
                f"• Weakest open session: {weak_sess_name} | WR {float(weak_sess.get('win_rate') or 0.0):.1f}% | AvgR {float(weak_sess.get('avg_r') or 0.0):+.2f}"
            )

    if include_engines:
        best_engine_name, best_engine = _trade_lifecycle_best_bucket(a.get('by_engine') or {}, metric='avg_r', min_sample=2, prefer_high=True)
        weak_engine_name, weak_engine = _trade_lifecycle_best_bucket(a.get('by_engine') or {}, metric='avg_r', min_sample=2, prefer_high=False)
        if best_engine_name:
            lines.append(
                f"• Best engine: {best_engine_name} | WR {float(best_engine.get('win_rate') or 0.0):.1f}% | AvgR {float(best_engine.get('avg_r') or 0.0):+.2f}"
            )
        if weak_engine_name and weak_engine_name != best_engine_name:
            lines.append(
                f"• Weak engine: {weak_engine_name} | WR {float(weak_engine.get('win_rate') or 0.0):.1f}% | AvgR {float(weak_engine.get('avg_r') or 0.0):+.2f}"
            )

    if include_buckets:
        best_conf_name, best_conf = _trade_lifecycle_best_bucket(a.get('by_conf_bucket') or {}, metric='avg_r', min_sample=2, prefer_high=True)
        weak_conf_name, weak_conf = _trade_lifecycle_best_bucket(a.get('by_conf_bucket') or {}, metric='avg_r', min_sample=2, prefer_high=False)
        best_quality_name, best_quality = _trade_lifecycle_best_bucket(a.get('by_quality_bucket') or {}, metric='avg_r', min_sample=2, prefer_high=True)
        if best_conf_name:
            lines.append(
                f"• Best confidence bucket: {best_conf_name} | WR {float(best_conf.get('win_rate') or 0.0):.1f}% | AvgR {float(best_conf.get('avg_r') or 0.0):+.2f}"
            )
        if weak_conf_name and weak_conf_name != best_conf_name:
            lines.append(
                f"• Weak confidence bucket: {weak_conf_name} | WR {float(weak_conf.get('win_rate') or 0.0):.1f}% | AvgR {float(weak_conf.get('avg_r') or 0.0):+.2f}"
            )
        if best_quality_name:
            lines.append(
                f"• Best quality bucket: {best_quality_name} | WR {float(best_quality.get('win_rate') or 0.0):.1f}% | AvgR {float(best_quality.get('avg_r') or 0.0):+.2f}"
            )

    if include_symbols:
        top_win = list(a.get('top_winning_symbols') or [])
        top_lose = list(a.get('top_losing_symbols') or [])
        tp_fail = list(a.get('symbols_tp_but_fail_alt_target_a') or [])
        if top_win:
            x = dict(top_win[0] or {})
            lines.append(f"• Top winner: {str(x.get('symbol') or '?')} | PnL {float(x.get('net_pnl') or 0.0):+.2f} | AvgR {float(x.get('avg_r') or 0.0):+.2f}")
        if top_lose:
            x = dict(top_lose[0] or {})
            lines.append(f"• Top loser: {str(x.get('symbol') or '?')} | PnL {float(x.get('net_pnl') or 0.0):+.2f} | AvgR {float(x.get('avg_r') or 0.0):+.2f}")
        if tp_fail:
            x = dict(tp_fail[0] or {})
            lines.append(f"• Frequent TP symbol: {str(x.get('symbol') or '?')} | TP hits {int(x.get('tp_hits') or 0) + int(x.get('alt_target_a_hits') or 0)}")

    if include_signs and (a.get('signs') or []):
        lines.append('• Optimization signals:')
        for s in list(a.get('signs') or [])[:max(1, int(max_signs))]:
            lines.append(f"  - {s}")
    return lines


def _trade_lifecycle_detail_report(owner_uid: int, ident: str) -> str:
    row = _trade_lifecycle_detail_row(owner_uid, ident, sync=True)
    if not row:
        return 'No matching trade lifecycle row found.'
    trade_id = str(row.get('trade_id') or '')
    setup_id = str(row.get('setup_id') or '')
    user = _autotrade_user_settings(owner_uid)
    lines = [
        '🧬 Trade Lifecycle Detail',
        HDR,
        f"Trade ID: {trade_id}",
        f"Setup ID: {setup_id or '—'}",
    ]
    lines.extend(_trade_lifecycle_render_row(row, user, show_trade_id=False))
    lines.append(f"  Sync confidence {str(row.get('source_confidence') or '—')}")
    try:

        with sqlite3.connect(DB_PATH) as con:
            con.row_factory = sqlite3.Row
            cur = con.cursor()
            ev_rows = cur.execute(
                "SELECT * FROM trade_lifecycle_events WHERE trade_id=? ORDER BY COALESCE(event_ts,0) ASC, id ASC",
                (trade_id,),
            ).fetchall() or []
            if ev_rows:
                lines.extend([SEP, 'Events'])
                for ev in ev_rows[:20]:
                    d = dict(ev)
                    ts = float(d.get('event_ts') or 0.0)
                    ts_txt = _fmt_dt_local(datetime.fromtimestamp(ts, tz=timezone.utc)) if ts > 0 else '—'
                    px = float(d.get('price') or 0.0)
                    qty = float(d.get('qty') or 0.0)
                    pnl = d.get('pnl_usdt')
                    parts = [f"• {str(d.get('event_type') or '')} | {ts_txt}"]
                    if px > 0:
                        parts.append(f"px {fmt_price(px)}")
                    if qty > 0:
                        parts.append(f"qty {qty:g}")
                    if pnl is not None:
                        try:
                            parts.append(f"pnl {float(pnl):+.2f}")
                        except Exception:
                            pass
                    if str(d.get('source') or '').strip():
                        parts.append(str(d.get('source') or '').strip())
                    lines.append(' | '.join(parts))
    except Exception:
        pass
    return '\n'.join(lines)


async def trade_lifecycle_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    if int(uid) != int(AUTOTRADE_OWNER_UID) and (not is_admin_user(uid)):
        await update.message.reply_text('⛔️ Owner/admin only.')
        return
    days = 7
    session = 'ALL'
    try:
        for arg in (context.args or []):
            raw = str(arg or '').strip().upper()
            if not raw:
                continue
            if raw in {'ALL', 'ASIA', 'LON', 'NY'}:
                session = raw
            else:
                days = int(float(raw))
    except Exception:
        days = 7
    days = int(max(1, min(days, 3650)))
    owner_uid = _trade_lifecycle_owner_uid(uid)
    text_out = await to_thread_heavy(_trade_lifecycle_compact_report, owner_uid, days, session)
    await send_long_message(update, text_out, parse_mode=None)


async def trade_lifecycle_detail_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    if int(uid) != int(AUTOTRADE_OWNER_UID) and (not is_admin_user(uid)):
        await update.message.reply_text('⛔️ Owner/admin only.')
        return
    owner_uid = _trade_lifecycle_owner_uid(uid)
    raw_args = [str(a or '').strip() for a in (context.args or []) if str(a or '').strip()]
    hours = 48
    session = 'ALL'
    for raw in raw_args:
        up = raw.upper().strip()
        if up in {'ALL', 'ASIA', 'LON', 'NY'}:
            session = up
            continue
        num_txt = up[:-1] if up.endswith('H') else up
        if re.fullmatch(r"\d+(?:\.\d+)?", num_txt or ''):
            try:
                hours = int(max(1, min(int(float(num_txt)), 24 * 90)))
            except Exception:
                pass
            continue
    text_out = await to_thread_heavy(_trade_lifecycle_recent_report, owner_uid, hours, session)
    await send_long_message(update, text_out, parse_mode=None)


def _admin_setup_state_from_reason(reason: str) -> str:
    r = str(reason or '').strip().lower()
    if not r:
        return 'rejected'
    r = re.sub(r'[^a-z0-9_]+', '_', r)
    if not r.startswith('emailed_not_executed_'):
        r = f'emailed_not_executed_{r}'
    return r[:80]

def db_insert_signal(s: Setup, user_id: int | None = None):
    """Upsert a setup into DB (signals table). Adds market_symbol when available.

    Important: lifecycle updates must stay user-scoped. Do not default to the owner admin,
    otherwise signals generated for other users can contaminate admin lifecycle tracking.
    """
    try:
        s = _research_finalize_setup(s, session_name=str(getattr(s, 'session', '') or ''))
    except Exception:
        pass
    con = db_connect()
    cur = con.cursor()
    try:
        cur.execute("""
            INSERT OR REPLACE INTO signals (
                setup_id, created_ts, symbol, market_symbol, side, conf, entry, sl, tp, alt_target_a, alt_target_b,
                fut_vol_usd, ch24, ch4, ch1, ch15
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            s.setup_id, s.created_ts, s.symbol, getattr(s, "market_symbol", None),
            s.side, s.conf, s.entry, s.sl, float(_setup_target_tp(s, 0.0) or 0.0), 0.0, 0.0,
            s.fut_vol_usd, s.ch24, s.ch4, s.ch1, s.ch15
        ))
    except Exception:
        # Backward-compatible (older DB without market_symbol column)
        cur.execute("""
            INSERT OR REPLACE INTO signals (
                setup_id, created_ts, symbol, side, conf, entry, sl, tp, alt_target_a, alt_target_b,
                fut_vol_usd, ch24, ch4, ch1, ch15
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            s.setup_id, s.created_ts, s.symbol, s.side, s.conf, s.entry, s.sl,
            float(_setup_target_tp(s, 0.0) or 0.0), 0.0, 0.0, s.fut_vol_usd, s.ch24, s.ch4, s.ch1, s.ch15
        ))
    try:
        cur.execute(
            """UPDATE signals SET family_id=?, family_version=?, regime_id=?, regime_primary=?, allocator_plan_id=?, param_set_id=?
                   WHERE setup_id=?
            """,
            (
                str(getattr(s, 'family_id', '') or ''),
                str(getattr(s, 'family_version', '') or RESEARCH_FAMILY_VERSION),
                str(getattr(s, 'regime_id', '') or ''),
                str(getattr(s, 'regime_primary', '') or ''),
                str(getattr(s, 'allocator_plan_id', '') or ''),
                str(getattr(s, 'param_set_id', '') or ''),
                str(getattr(s, 'setup_id', '') or ''),
            ),
        )
    except Exception:
        pass
    con.commit()
    con.close()
    try:
        if user_id is not None:
            _admin_setup_lifecycle_merge(
                int(user_id),
                str(getattr(s, 'setup_id', '') or ''),
                symbol=str(getattr(s, 'symbol', '') or ''),
                side=str(getattr(s, 'side', '') or ''),
                signal_created_ts=float(getattr(s, 'created_ts', 0.0) or 0.0),
                state='screened',
            )
    except Exception:
        pass

def db_get_signal(setup_id: str) -> Optional[dict]:
    con = db_connect()
    cur = con.cursor()
    cur.execute("SELECT * FROM signals WHERE setup_id=?", (setup_id.strip(),))
    row = cur.fetchone()
    con.close()
    return dict(row) if row else None

def db_list_signals_since(ts_from: float) -> List[dict]:
    con = db_connect()
    cur = con.cursor()
    cur.execute("SELECT * FROM signals WHERE created_ts>=? ORDER BY created_ts ASC", (ts_from,))
    rows = cur.fetchall()
    con.close()
    return [dict(r) for r in rows]


