def next_setup_id() -> str:
    today = datetime.utcnow().strftime("%Y%m%d")
    con = db_connect()
    cur = con.cursor()
    try:
        cur.execute("BEGIN IMMEDIATE")
        cur.execute("""
            INSERT INTO setup_counter (day_yyyymmdd, seq)
            VALUES (?, 1)
            ON CONFLICT(day_yyyymmdd) DO UPDATE SET seq = seq + 1
        """, (today,))
        cur.execute("SELECT seq FROM setup_counter WHERE day_yyyymmdd=?", (today,))
        n = int(cur.fetchone()["seq"])
        con.commit()
    except Exception:
        con.rollback()
        raise
    finally:
        con.close()
    return f"PF-{today}-{n:04d}"


def make_setup_id(base: str = '', side: str = '') -> str:
    """Backward-compatible setup ID helper.

    Some setup builders still call make_setup_id(base, side). The setup identity
    is intentionally sequence-based and globally unique for the day, so base/side
    are accepted for compatibility but not embedded in the ID.
    """
    return next_setup_id()

# =========================================================
# SL/TP ENGINE (closer + dynamic cap + ✅ confidence-weighted TP scaling)
# =========================================================
def sl_mult_from_conf(conf: int) -> float:
    # slightly tighter than old premium; tuned for higher win-rate with closer TPs
    if conf >= 88:
        return 2.2
    if conf >= 80:
        return 1.95
    if conf >= 70:
        return 1.70
    return 1.55

def tp_rr_target_from_conf(conf: int) -> float:
    """Single final TP RR target tuned for higher win-rate pullback exits."""
    if conf >= 90:
        return 1.55
    if conf >= 84:
        return 1.42
    if conf >= 78:
        return 1.32
    return 1.22

def tp_r_mults_from_conf(conf: int) -> Tuple[float, float, float]:
    """Backward-compatible single-target RR signature."""
    rr = tp_rr_target_from_conf(conf)
    return (rr, rr, rr)

def compute_sl_tp(
    entry: float,
    side: str,
    atr: float,
    conf: int,
    tp_cap_pct: float,
    rr_bonus: float = 0.0,
    tp_cap_bonus_pct: float = 0.0,
) -> Tuple[float, float, float]:
    """
    Returns (sl, tp, R)
    """
    if entry <= 0 or atr <= 0:
        return 0.0, 0.0, 0.0

    sl_dist = sl_mult_from_conf(conf) * atr

    min_dist = (ATR_MIN_PCT / 100.0) * entry
    max_dist = (ATR_MAX_PCT / 100.0) * entry
    sl_dist = clamp(sl_dist, min_dist, max_dist)

    R = sl_dist

    # ✅ confidence-weighted RR + engine bonus
    rr_target = tp_rr_target_from_conf(conf) + rr_bonus
    tp_dist = rr_target * R

    # ✅ TP cap with engine bonus
    tp_cap = ((tp_cap_pct + tp_cap_bonus_pct) / 100.0) * entry
    tp_dist = min(tp_dist, tp_cap)

    if side == "BUY":
        sl = entry - sl_dist
        alt_target_b = entry + tp_dist
    else:
        sl = entry + sl_dist
        alt_target_b = entry - tp_dist

    return sl, alt_target_b, R

def _distinctify(a: float, b: float, c: float, entry: float, side: str) -> Tuple[float, float, float]:
    if entry <= 0:
        return a, b, c
    eps = max(entry * 1e-6, 1e-8)
    if side == "BUY":
        if a >= b: a = b - eps
        if b >= c: b = c - eps
        if a >= b: a = b - eps
    else:
        if a <= b: a = b + eps
        if b <= c: b = c + eps
        if a <= b: a = b + eps
    if abs(a - b) < eps: a = a - eps if side == "BUY" else a + eps
    if abs(b - c) < eps: b = b - eps if side == "BUY" else b + eps
    if abs(a - c) < eps: a = a - 2*eps if side == "BUY" else a + 2*eps
    return a, b, c


def multi_tp(
    entry: float,
    side: str,
    R: float,
    tp_cap_pct: float,
    conf: int,
    rr_bonus: float = 0.0,
    tp_cap_bonus_pct: float = 0.0,
) -> Tuple[float, float, float]:
    """Backward-compatible single-target TP generator.

    Returns the same TP in all tuple positions so legacy callers remain safe while
    the trading model uses just one take profit.
    """
    if entry <= 0 or R <= 0:
        return 0.0, 0.0, 0.0
    rr = tp_rr_target_from_conf(conf) + rr_bonus
    maxd = ((tp_cap_pct + tp_cap_bonus_pct) / 100.0) * entry
    dist = min(rr * R, maxd)
    tp = (entry + dist) if side == "BUY" else (entry - dist)
    return float(tp), float(tp), float(tp)



def _realized_r_option_b(outcome: str, side: str, entry: float, sl: float, tp=None, alt_target_a=None, alt_target_b=None):
    """Return realized R under the single-TP model."""
    try:
        outcome = _canon_signal_outcome_label(outcome)
        entry = float(entry)
        sl = float(sl)
        risk = abs(entry - sl)
        if risk <= 0:
            return None
        if outcome == 'SL':
            return -1.0
        if outcome != 'TP':
            return None
        tp = _resolve_single_tp(entry, sl, tp=tp, alt_target_a=alt_target_a, alt_target_b=alt_target_b, side=side)
        if tp > 0:
            rr = abs(float(tp) - entry) / risk
            if math.isfinite(rr) and rr > 0:
                return float(rr)
        return None
    except Exception:
        return None
        if outcome == 'SL':
            return -1.0
        tp = None
        if outcome == 'TP':
            tp = tp
            fallback = 1.0
        elif outcome == 'TP':
            tp = alt_target_a if alt_target_a not in (None, '', 0, 0.0) else alt_target_b
            fallback = 2.0
        else:
            return None
        if tp is not None:
            try:
                rr = abs(float(tp) - entry) / risk
                if math.isfinite(rr) and rr > 0:
                    return float(rr)
            except Exception:
                pass
        return float(fallback)
    except Exception:
        return None

def rr_to_tp(entry: float, sl: float, tp: float) -> float:
    d_sl = abs(entry - sl)
    d_tp = abs(tp - entry)
    if d_sl <= 0:
        return 0.0
    return d_tp / d_sl



