def _goal_profile_profile_bundles(profile_name: str, bundles: list[dict]) -> list[dict]:
    name = str(profile_name or '').upper().strip()
    if not bundles:
        return []
    by_name = {str((b or {}).get('name') or '').strip(): dict(b or {}) for b in (bundles or [])}
    preferred = {
        'LON_A_ONLY': ['strict', 'balanced'],
        'LON_A_REACH': ['flex', 'reach'],
        'LON_C_ONLY': ['balanced', 'c_breakout_focus'],
        'LON_A_C_ONLY': ['balanced'],
        'LON_A_C_REACH': ['flex', 'reach'],
    }.get(name, [])
    out = [by_name[n] for n in preferred if n in by_name]
    if out:
        return out
    return list(bundles or [])

def _goal_profile_apply_candidate(base_cfg: dict, profile: dict, bundle: dict) -> dict:
    cfg = json.loads(json.dumps(base_cfg or {}))
    cfg['quality_score_min_screen'] = float(bundle.get('quality_score_min_screen', cfg.get('quality_score_min_screen', QUALITY_SCORE_MIN_SCREEN)))
    cfg['quality_score_min_email'] = float(bundle.get('quality_score_min_email', cfg.get('quality_score_min_email', QUALITY_SCORE_MIN_EMAIL)))
    cfg['tf_align_1h_min_abs'] = float(bundle.get('tf_align_1h_min_abs', cfg.get('tf_align_1h_min_abs', TF_ALIGN_1H_MIN_ABS)))
    cfg['tf_align_4h_min_abs'] = float(bundle.get('tf_align_4h_min_abs', cfg.get('tf_align_4h_min_abs', TF_ALIGN_4H_MIN_ABS)))
    cfg['atr_min_pct'] = float(bundle.get('atr_min_pct', cfg.get('atr_min_pct', ATR_MIN_PCT)))
    cfg['min_rr_tp'] = float(bundle.get('min_rr_tp', cfg.get('min_rr_tp', MIN_RR_TP)))
    cfg['regime_slope_trend_min_pct'] = float(bundle.get('regime_slope_trend_min_pct', cfg.get('regime_slope_trend_min_pct', 0.06)))
    cfg['execution_sessions_allowed'] = [str(x).upper().strip() for x in (profile.get('execution_sessions_allowed') or ['LON']) if str(x).strip()]
    cfg['execution_engines_allowed'] = [str(x).upper().strip() for x in (profile.get('execution_engines_allowed') or ['A']) if str(x).strip()]
    cfg['execution_asia_enabled'] = bool(profile.get('execution_asia_enabled', False))
    cfg['execution_asia_user_override'] = True
    cfg['execution_engine_b_email_enabled'] = bool(profile.get('execution_engine_b_email_enabled', False))
    cfg['goal_profile_active_profile'] = str(profile.get('name') or 'PROFILE')
    bundle_name = str(bundle.get('name') or '').upper().strip()
    profile_name = str(profile.get('name') or '').upper().strip()
    cfg['goal_profile_reach_mode'] = bool(('REACH' in profile_name) or bundle_name in {'FLEX', 'REACH', 'C_BREAKOUT_FOCUS'})
    sess_ov = json.loads(json.dumps(cfg.get('session_exec_overrides') or {}))
    for sess in ('NY', 'LON', 'ASIA'):
        sess_ov.setdefault(sess, {'quality_add': 0.0, 'conf_add': 0, 'rr_add': 0.0})
    sess_ov['LON'] = {
        'quality_add': float(bundle.get('lon_quality_add', 0.0) or 0.0),
        'conf_add': int(bundle.get('lon_conf_add', 0) or 0),
        'rr_add': float(bundle.get('lon_rr_add', 0.0) or 0.0),
    }
    if 'NY' not in cfg.get('execution_sessions_allowed', []):
        sess_ov['NY'] = {'quality_add': max(2.0, float((sess_ov.get('NY') or {}).get('quality_add', 0.0) or 0.0)), 'conf_add': max(2, int((sess_ov.get('NY') or {}).get('conf_add', 0) or 0)), 'rr_add': max(0.12, float((sess_ov.get('NY') or {}).get('rr_add', 0.0) or 0.0))}
    if 'ASIA' not in cfg.get('execution_sessions_allowed', []):
        sess_ov['ASIA'] = {'quality_add': max(3.0, float((sess_ov.get('ASIA') or {}).get('quality_add', 0.0) or 0.0)), 'conf_add': max(3, int((sess_ov.get('ASIA') or {}).get('conf_add', 0) or 0)), 'rr_add': max(0.16, float((sess_ov.get('ASIA') or {}).get('rr_add', 0.0) or 0.0))}
    cfg['session_exec_overrides'] = sess_ov
    weights = {'NY': 0.0, 'LON': 0.0, 'ASIA': 0.0}
    allowed = cfg.get('execution_sessions_allowed') or []
    if allowed == ['LON']:
        weights = {'NY': 0.0, 'LON': 1.0, 'ASIA': 0.0}
    elif allowed == ['LON', 'NY'] or allowed == ['NY', 'LON']:
        weights = {'NY': 0.35, 'LON': 0.65, 'ASIA': 0.0}
    else:
        for sess in allowed:
            if sess in weights:
                weights[sess] = 1.0
        tot = sum(weights.values()) or 1.0
        weights = {k: float(v) / float(tot) for k, v in weights.items()}
    cfg['session_weights'] = weights
    return cfg


def _goal_profile_summary_from_rep(rep: dict) -> dict:
    ov = dict((rep or {}).get('overall') or {})
    return {
        'setups': int(ov.get('setups', 0) or 0),
        'setups_per_day': float(ov.get('setups_per_day', 0.0) or 0.0),
        'win_rate': float(ov.get('win_rate', 0.0) or 0.0),
        'avg_R': float(ov.get('avg_R', 0.0) or 0.0),
    }


def _goal_profile_stage1_score(rep30: dict, cfg: dict) -> dict:
    tgt = _goal_profile_targets(cfg)
    s30 = _goal_profile_summary_from_rep(rep30)
    n30 = int(s30['setups'])
    sdp30 = float(s30['setups_per_day'])
    wr30 = float(s30['win_rate'])
    ar30 = float(s30['avg_R'])

    def _freq_pen(v: float, lo: float, hi: float, weight_under: float, weight_over: float) -> float:
        if v < lo:
            return (lo - v) * weight_under
        if v > hi:
            return (v - hi) * weight_over
        return 0.0

    freq_pen = _freq_pen(sdp30, tgt['target_lo'], tgt['target_hi'], 40.0, 18.0)
    wr_pen = max(0.0, tgt['target_wr'] - wr30) * 2.4
    avg_r_pen = max(0.0, tgt['target_avg_r'] - ar30) * 62.0
    sample_pen = max(0, tgt['min_live_30d'] - n30) * 7.0
    zero_pen = 350.0 if n30 <= 0 else 0.0
    score = (wr30 * 2.2) + (ar30 * 55.0) + (sdp30 * 10.0) - freq_pen - wr_pen - avg_r_pen - sample_pen - zero_pen
    return {
        'score': float(score),
        'metrics_30d': s30,
        'penalties': {
            'freq_pen': float(freq_pen),
            'wr_pen': float(wr_pen),
            'avg_r_pen': float(avg_r_pen),
            'sample_pen': float(sample_pen),
            'zero_pen': float(zero_pen),
        },
    }


def _goal_profile_score_candidate(rep30: dict, rep7: dict, cfg: dict) -> dict:
    tgt = _goal_profile_targets(cfg)
    s30 = _goal_profile_summary_from_rep(rep30)
    s7 = _goal_profile_summary_from_rep(rep7)
    n30 = int(s30['setups'])
    n7 = int(s7['setups'])
    sdp30 = float(s30['setups_per_day'])
    sdp7 = float(s7['setups_per_day'])
    wr30 = float(s30['win_rate'])
    wr7 = float(s7['win_rate'])
    ar30 = float(s30['avg_R'])
    ar7 = float(s7['avg_R'])

    def _freq_pen(v: float, lo: float, hi: float, weight_under: float, weight_over: float) -> float:
        if v < lo:
            return (lo - v) * weight_under
        if v > hi:
            return (v - hi) * weight_over
        return 0.0

    freq_pen = _freq_pen(sdp30, tgt['target_lo'], tgt['target_hi'], 52.0, 18.0) + _freq_pen(sdp7, tgt['target_lo'], tgt['target_hi'], 18.0, 5.0)
    wr_pen = max(0.0, tgt['target_wr'] - wr30) * 2.3 + max(0.0, tgt['target_wr'] - wr7) * 0.6
    avg_r_pen = max(0.0, tgt['target_avg_r'] - ar30) * 65.0 + max(0.0, tgt['target_avg_r'] - ar7) * 18.0
    sample_pen = max(0, tgt['min_live_30d'] - n30) * 7.0 + max(0, tgt['min_live_7d'] - n7) * 4.5
    instability_pen = abs(wr30 - wr7) * (0.10 if (n30 > 0 and n7 > 0) else 0.0)
    zero_pen = 350.0 if n30 <= 0 else 0.0
    score = (wr30 * 2.1) + (wr7 * 0.6) + (ar30 * 55.0) + (ar7 * 15.0) + (sdp30 * 14.0) + (sdp7 * 4.0) - freq_pen - wr_pen - avg_r_pen - sample_pen - instability_pen - zero_pen
    feasible = bool(n30 >= tgt['min_live_30d'] and n7 >= tgt['min_live_7d'] and wr30 >= tgt['target_wr'] and ar30 >= tgt['target_avg_r'] and sdp30 >= (tgt['target_lo'] * 0.70) and sdp30 <= (tgt['target_hi'] * 1.25))
    return {
        'score': float(score),
        'feasible': feasible,
        'metrics_30d': s30,
        'metrics_7d': s7,
        'penalties': {
            'freq_pen': float(freq_pen),
            'wr_pen': float(wr_pen),
            'avg_r_pen': float(avg_r_pen),
            'sample_pen': float(sample_pen),
            'instability_pen': float(instability_pen),
            'zero_pen': float(zero_pen),
        },
    }


def _goal_profile_is_due(now_ts: float | None = None, cfg: dict | None = None, rep: dict | None = None) -> bool:
    now_ts = float(now_ts or time.time())
    cfg = dict(cfg or load_strategy_config(force=False) or {})
    tgt = _goal_profile_targets(cfg)
    if not bool(tgt.get('enabled')):
        return False
    rep = dict(rep or load_goal_profile_report() or {})
    status = str(rep.get('status') or '').upper().strip()
    if status in {'RUNNING', 'STOPPING'} and _goal_profile_is_running():
        return False
    last_ts = max(
        float(rep.get('ts', 0.0) or 0.0),
        float((cfg or {}).get('goal_profile_last_run_ts', 0.0) or 0.0),
        float(rep.get('started_ts', 0.0) or 0.0),
    )
    if last_ts <= 0:
        return True
    due_after = max(3600.0, float(tgt.get('interval_hours', 24.0) or 24.0) * 3600.0)
    return (now_ts - last_ts) >= max(60.0, due_after - 120.0)


def _run_goal_profile_cycle(force: bool = False) -> dict:
    cfg0 = load_strategy_config(force=True)
    tgt = _goal_profile_targets(cfg0)
    now_ts = float(time.time())
    current_profile = str((cfg0 or {}).get('goal_profile_active_profile') or 'BASELINE')
    current_sessions = list((cfg0 or {}).get('execution_sessions_allowed') or [])
    current_engines = list((cfg0 or {}).get('execution_engines_allowed') or [])
    if not tgt['enabled']:
        rep = {
            'ok': False,
            'status': 'DISABLED',
            'ts': now_ts,
            'started_ts': now_ts,
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
        }
        save_goal_profile_report(rep)
        return rep
    if not _GOAL_PROFILE_LOCK.acquire(blocking=False):
        rep = load_goal_profile_report() or {}
        return {
            'ok': False,
            'status': 'BUSY',
            'ts': now_ts,
            'started_ts': float(rep.get('started_ts', now_ts) or now_ts),
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
        }
    started_ts = float(time.time())
    stop_event = threading.Event()
    _GOAL_PROFILE_STATE['stop_event'] = stop_event
    _GOAL_PROFILE_STATE['started_ts'] = started_ts
    _GOAL_PROFILE_STATE['run_id'] = f"goal-{int(started_ts)}"
    last_final = load_goal_profile_report() or {}
    if str(last_final.get('status') or '').upper() == 'RUNNING':
        last_final = {}

    def _persist_running(stage: str, candidate_idx: int = 0, candidate_total: int = 0, current_candidate: dict | None = None, best_candidate: dict | None = None, note: str = ''):
        rep = {
            'ok': True,
            'status': 'RUNNING',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': current_profile,
                'execution_sessions_allowed': current_sessions,
                'execution_engines_allowed': current_engines,
            },
            'progress': {
                'stage': str(stage or 'running'),
                'candidate_idx': int(candidate_idx or 0),
                'candidate_total': int(candidate_total or 0),
                'current_candidate': current_candidate or {},
                'best_candidate': best_candidate or {},
                'elapsed_sec': float(max(0.0, time.time() - started_ts)),
                'note': str(note or ''),
            },
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(rep)

    try:
        if (not force) and float(last_final.get('applied_ts', 0.0) or 0.0) > 0 and (time.time() - float(last_final.get('applied_ts', 0.0) or 0.0)) < (tgt['cooldown_hours'] * 3600.0):
            rep = {'ok': False, 'status': 'COOLDOWN', 'ts': float(time.time()), 'started_ts': started_ts, 'targets': tgt, 'last': last_final}
            save_goal_profile_report(rep)
            return rep

        base_cfg = json.loads(json.dumps(cfg0 or {}))
        exec_tf = str((base_cfg or {}).get('universe_backtest_exec_tf') or (base_cfg or {}).get('exec_tf_default') or '15m').strip().lower()
        top_n = int((base_cfg or {}).get('universe_backtest_top_n', 80) or 80)
        max_run_sec = max(180.0, float(tgt.get('max_run_minutes', 18.0) or 18.0) * 60.0)

        save_strategy_config(base_cfg)
        apply_strategy_config(base_cfg)
        _persist_running('baseline')
        baseline30 = run_universe_backtest(30, 'ALL', exec_tf, top_n, None, False, False)
        baseline7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
        baseline_eval = _goal_profile_score_candidate(baseline30, baseline7, base_cfg)

        best_cfg = json.loads(json.dumps(base_cfg))
        best_eval = dict(baseline_eval)
        best_profile = {'name': 'BASELINE'}
        best_bundle = {'name': 'current'}
        stage1_rows = []
        stage2_rows = []
        profiles = _goal_profile_candidate_profiles(base_cfg)
        bundles = _goal_profile_candidate_bundles(base_cfg)
        bundle_plan = {str((p or {}).get('name') or ''): _goal_profile_profile_bundles(str((p or {}).get('name') or ''), bundles) for p in profiles}
        candidate_total = max(0, sum(len(bundle_plan.get(str((p or {}).get('name') or ''), [])) for p in profiles))
        cand_counter = 0

        for profile in profiles:
            for bundle in (bundle_plan.get(str((profile or {}).get('name') or ''), []) or []):
                cand_counter += 1
                if stop_event.is_set():
                    raise TimeoutError('goal_profile_aborted')
                if (time.time() - started_ts) > max_run_sec:
                    raise TimeoutError('goal_profile_timeout')
                current_row = {
                    'profile': str(profile.get('name') or ''),
                    'bundle': str(bundle.get('name') or ''),
                    'sessions': list(profile.get('execution_sessions_allowed') or []),
                    'engines': list(profile.get('execution_engines_allowed') or []),
                }
                _persist_running('search_30d', cand_counter, candidate_total, current_row, {
                    'profile': str(best_profile.get('name') or 'BASELINE'),
                    'bundle': str(best_bundle.get('name') or 'current'),
                    'score': float(best_eval.get('score', -1e9)),
                })
                cand_cfg = _goal_profile_apply_candidate(base_cfg, profile, bundle)
                apply_strategy_config(cand_cfg)
                rep30 = run_universe_backtest(30, 'ALL', exec_tf, top_n, None, False, False)
                apply_strategy_config(base_cfg)
                stage1 = _goal_profile_stage1_score(rep30, cand_cfg)
                stage1_rows.append({
                    'profile': str(profile.get('name') or ''),
                    'bundle': str(bundle.get('name') or ''),
                    'stage1_score': float(stage1.get('score', -1e9)),
                    'metrics_30d': stage1.get('metrics_30d') or {},
                    'penalties_30d': stage1.get('penalties') or {},
                    'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                    'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
                    'cand_cfg': cand_cfg,
                })

        shortlist_n = max(1, min(int(tgt.get('shortlist', 4) or 4), len(stage1_rows) or 1))
        shortlist = sorted(stage1_rows, key=lambda x: float(x.get('stage1_score', -1e9)), reverse=True)[:shortlist_n]

        for idx, row in enumerate(shortlist, start=1):
            if stop_event.is_set():
                raise TimeoutError('goal_profile_aborted')
            if (time.time() - started_ts) > max_run_sec:
                raise TimeoutError('goal_profile_timeout')
            current_row = {
                'profile': str(row.get('profile') or ''),
                'bundle': str(row.get('bundle') or ''),
                'sessions': list(row.get('execution_sessions_allowed') or []),
                'engines': list(row.get('execution_engines_allowed') or []),
            }
            _persist_running('search_7d', idx, len(shortlist), current_row, {
                'profile': str(best_profile.get('name') or 'BASELINE'),
                'bundle': str(best_bundle.get('name') or 'current'),
                'score': float(best_eval.get('score', -1e9)),
            }, note=f"shortlist={len(shortlist)} of {candidate_total}")
            cand_cfg = dict(row.get('cand_cfg') or {})
            apply_strategy_config(cand_cfg)
            rep7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
            apply_strategy_config(base_cfg)
            evald = _goal_profile_score_candidate({'overall': row.get('metrics_30d') or {}}, rep7, cand_cfg)
            full_row = {
                'profile': str(row.get('profile') or ''),
                'bundle': str(row.get('bundle') or ''),
                'score': float(evald.get('score', -1e9)),
                'feasible': bool(evald.get('feasible')),
                'metrics_30d': evald.get('metrics_30d') or {},
                'metrics_7d': evald.get('metrics_7d') or {},
                'penalties': evald.get('penalties') or {},
                'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
            }
            stage2_rows.append(full_row)
            if float(evald.get('score', -1e9)) > float(best_eval.get('score', -1e9)):
                best_cfg = json.loads(json.dumps(cand_cfg))
                best_eval = dict(evald)
                best_profile = {'name': str(row.get('profile') or '')}
                best_bundle = {'name': str(row.get('bundle') or '')}

        promoted = float(best_eval.get('score', -1e9)) > float(baseline_eval.get('score', -1e9)) + 0.5
        final_cfg = json.loads(json.dumps(best_cfg if promoted else base_cfg))
        final_eval = dict(best_eval if promoted else baseline_eval)
        final_cfg['goal_profile_last_run_ts'] = float(time.time())
        save_strategy_config(final_cfg)
        apply_strategy_config(final_cfg)

        report = {
            'ok': True,
            'status': 'PROMOTED' if promoted else 'NO_BETTER_PROFILE',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'applied_ts': float(time.time()) if promoted else float((last_final or {}).get('applied_ts', 0.0) or 0.0),
            'targets': tgt,
            'current': {
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
            },
            'baseline': {'score': float(baseline_eval.get('score', -1e9)), 'metrics_30d': baseline_eval.get('metrics_30d') or {}, 'metrics_7d': baseline_eval.get('metrics_7d') or {}},
            'best_candidate': {'profile': str(best_profile.get('name') or ''), 'bundle': str(best_bundle.get('name') or ''), 'score': float(best_eval.get('score', -1e9)), 'feasible': bool(best_eval.get('feasible')), 'metrics_30d': best_eval.get('metrics_30d') or {}, 'metrics_7d': best_eval.get('metrics_7d') or {}, 'execution_sessions_allowed': list(best_cfg.get('execution_sessions_allowed') or []), 'execution_engines_allowed': list(best_cfg.get('execution_engines_allowed') or [])},
            'final': {'score': float(final_eval.get('score', -1e9)), 'metrics_30d': final_eval.get('metrics_30d') or {}, 'metrics_7d': final_eval.get('metrics_7d') or {}, 'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or []), 'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or []), 'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or 'BASELINE')},
            'progress': {'stage': 'done', 'candidate_idx': len(stage2_rows), 'candidate_total': len(shortlist), 'elapsed_sec': float(max(0.0, time.time() - started_ts)), 'shortlist_from': int(candidate_total)},
            'top_candidates': sorted(stage2_rows, key=lambda x: float(x.get('score', -1e9)), reverse=True)[:8],
            'stage1_shortlist': [{k: v for k, v in row.items() if k != 'cand_cfg'} for row in shortlist],
        }
        save_goal_profile_report(report)
        return report
    except TimeoutError as e:
        status = 'ABORTED' if 'aborted' in str(e).lower() else 'TIMEOUT'
        timed_out = (status == 'TIMEOUT')
        partial_best_cfg = None
        partial_best_eval = None
        partial_best_profile = {'name': ''}
        partial_best_bundle = {'name': ''}
        try:
            partial_best_cfg = json.loads(json.dumps(best_cfg)) if isinstance(best_cfg, dict) else None
            partial_best_eval = dict(best_eval) if isinstance(best_eval, dict) else None
            partial_best_profile = dict(best_profile) if isinstance(best_profile, dict) else {'name': ''}
            partial_best_bundle = dict(best_bundle) if isinstance(best_bundle, dict) else {'name': ''}
        except Exception:
            partial_best_cfg = None
            partial_best_eval = None
        if timed_out and (not stage2_rows) and stage1_rows:
            try:
                top_stage1 = sorted(stage1_rows, key=lambda x: float(x.get('stage1_score', -1e9)), reverse=True)[0]
                cand_cfg = dict(top_stage1.get('cand_cfg') or {})
                if cand_cfg:
                    apply_strategy_config(cand_cfg)
                    rep7 = run_universe_backtest(7, 'ALL', exec_tf, top_n, None, False, False)
                    apply_strategy_config(base_cfg)
                    evald = _goal_profile_score_candidate({'overall': top_stage1.get('metrics_30d') or {}}, rep7, cand_cfg)
                    partial_best_cfg = json.loads(json.dumps(cand_cfg))
                    partial_best_eval = dict(evald)
                    partial_best_profile = {'name': str(top_stage1.get('profile') or '')}
                    partial_best_bundle = {'name': str(top_stage1.get('bundle') or '')}
                    stage2_rows.append({
                        'profile': str(top_stage1.get('profile') or ''),
                        'bundle': str(top_stage1.get('bundle') or ''),
                        'score': float(evald.get('score', -1e9)),
                        'feasible': bool(evald.get('feasible')),
                        'metrics_30d': evald.get('metrics_30d') or {},
                        'metrics_7d': evald.get('metrics_7d') or {},
                        'penalties': evald.get('penalties') or {},
                        'execution_sessions_allowed': list(cand_cfg.get('execution_sessions_allowed') or []),
                        'execution_engines_allowed': list(cand_cfg.get('execution_engines_allowed') or []),
                    })
            except Exception:
                try:
                    apply_strategy_config(base_cfg)
                except Exception:
                    pass
        baseline_score = float((baseline_eval or {}).get('score', -1e9) if isinstance(locals().get('baseline_eval'), dict) else -1e9)
        best_score = float((partial_best_eval or {}).get('score', -1e9) if isinstance(partial_best_eval, dict) else -1e9)
        promote_partial = bool(timed_out and isinstance(partial_best_cfg, dict) and best_score > baseline_score + 0.5)
        final_cfg = json.loads(json.dumps(partial_best_cfg if promote_partial else (cfg0 or {})))
        try:
            final_cfg['goal_profile_last_run_ts'] = float(time.time())
        except Exception:
            pass
        try:
            save_strategy_config(final_cfg)
            apply_strategy_config(final_cfg)
        except Exception:
            pass
        final_eval = dict(partial_best_eval) if (promote_partial and isinstance(partial_best_eval, dict)) else (dict(baseline_eval) if isinstance(locals().get('baseline_eval'), dict) else {})
        final_status = 'TIMEOUT_PROMOTED' if promote_partial else ('TIMEOUT_NO_BETTER_PROFILE' if timed_out and baseline_score >= best_score else status)
        err_report = {
            'ok': False,
            'status': final_status,
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'targets': tgt,
            'error': str(e),
            'current': {
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
            },
            'baseline': {'score': baseline_score, 'metrics_30d': (baseline_eval or {}).get('metrics_30d') or {}, 'metrics_7d': (baseline_eval or {}).get('metrics_7d') or {}},
            'best_candidate': {
                'profile': str((partial_best_profile or {}).get('name') or ''),
                'bundle': str((partial_best_bundle or {}).get('name') or ''),
                'score': best_score,
                'feasible': bool((partial_best_eval or {}).get('feasible')) if isinstance(partial_best_eval, dict) else False,
                'metrics_30d': (partial_best_eval or {}).get('metrics_30d') or {},
                'metrics_7d': (partial_best_eval or {}).get('metrics_7d') or {},
                'execution_sessions_allowed': list((partial_best_cfg or {}).get('execution_sessions_allowed') or []),
                'execution_engines_allowed': list((partial_best_cfg or {}).get('execution_engines_allowed') or []),
            },
            'final': {
                'score': float(final_eval.get('score', -1e9)) if isinstance(final_eval, dict) else -1e9,
                'metrics_30d': (final_eval or {}).get('metrics_30d') or {},
                'metrics_7d': (final_eval or {}).get('metrics_7d') or {},
                'execution_sessions_allowed': list(final_cfg.get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list(final_cfg.get('execution_engines_allowed') or current_engines),
                'goal_profile_active_profile': str(final_cfg.get('goal_profile_active_profile') or current_profile),
            },
            'progress': {
                'stage': 'timeout_finalize' if timed_out else 'aborted',
                'candidate_idx': int(len(stage1_rows) if isinstance(locals().get('stage1_rows'), list) else 0),
                'candidate_total': int(candidate_total if 'candidate_total' in locals() else 0),
                'elapsed_sec': float(max(0.0, time.time() - started_ts)),
                'shortlist_from': int(len(stage1_rows) if isinstance(locals().get('stage1_rows'), list) else 0),
            },
            'top_candidates': sorted(stage2_rows, key=lambda x: float(x.get('score', -1e9)), reverse=True)[:8] if isinstance(locals().get('stage2_rows'), list) else [],
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(err_report)
        return err_report
    except Exception as e:
        try:
            save_strategy_config(cfg0 or {})
            apply_strategy_config(cfg0 or {})
            err_cfg = load_strategy_config(force=True)
        except Exception:
            err_cfg = cfg0 or {}
        err_report = {
            'ok': False,
            'status': 'ERROR',
            'ts': float(time.time()),
            'started_ts': started_ts,
            'finished_ts': float(time.time()),
            'targets': tgt,
            'error': f'{type(e).__name__}: {e}',
            'current': {
                'goal_profile_active_profile': str((err_cfg or {}).get('goal_profile_active_profile') or current_profile),
                'execution_sessions_allowed': list((err_cfg or {}).get('execution_sessions_allowed') or current_sessions),
                'execution_engines_allowed': list((err_cfg or {}).get('execution_engines_allowed') or current_engines),
            },
            'last_final': last_final if isinstance(last_final, dict) else {},
        }
        save_goal_profile_report(err_report)
        return err_report
    finally:
        try:
            ev = _GOAL_PROFILE_STATE.get('stop_event')
            if ev is not None:
                ev.set()
        except Exception:
            pass
        _GOAL_PROFILE_STATE['stop_event'] = None
        _GOAL_PROFILE_STATE['started_ts'] = 0.0
        _GOAL_PROFILE_STATE['run_id'] = ''
        _GOAL_PROFILE_LOCK.release()


async def goal_profile_abort_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    ev = _GOAL_PROFILE_STATE.get('stop_event')
    if ev is None or ev.is_set():
        await update.message.reply_text('No goal-profile optimizer run is active.')
        return
    ev.set()
    rep = load_goal_profile_report() or {}
    rep['status'] = 'STOPPING'
    rep['ts'] = float(time.time())
    prog = dict(rep.get('progress') or {})
    prog['note'] = 'Abort requested by admin.'
    rep['progress'] = prog
    save_goal_profile_report(rep)
    await update.message.reply_text('🛑 Goal-profile optimizer abort requested. It will stop after the current evaluation step.')


async def goal_profile_run_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    force = False
    try:
        args = list(context.args or [])
        force = bool(args and str(args[0]).strip().lower() in ('force', 'now', 'override'))
    except Exception:
        force = False
    await update.message.reply_text('⏳ Running goal-profile optimizer now…')
    try:
        rep = await to_thread_heavy(_run_goal_profile_cycle, force)
    except Exception as e:
        await update.message.reply_text(f'Goal-profile optimizer failed: {type(e).__name__}: {e}')
        return
    if not isinstance(rep, dict):
        await update.message.reply_text('Goal-profile optimizer returned no report.')
        return
    if not rep.get('ok'):
        status = str(rep.get('status') or 'UNKNOWN')
        extra = str(rep.get('error') or '').strip()
        await update.message.reply_text(f"Goal-profile optimizer status: {status}{(' | ' + extra) if extra else ''}")
        return
    final = rep.get('final') or {}
    m30 = final.get('metrics_30d') or {}
    m7 = final.get('metrics_7d') or {}
    lines = [
        '🎯 Goal-Profile Optimizer',
        HDR,
        f"Status: {rep.get('status','')}",
        f"Final profile: {final.get('goal_profile_active_profile','BASELINE')} | sessions={','.join(final.get('execution_sessions_allowed') or []) or '-'} | engines={','.join(final.get('execution_engines_allowed') or []) or '-'}",
        f"30d live: setups/day={float(m30.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m30.get('setups',0) or 0)} | WR={float(m30.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m30.get('avg_R',0.0) or 0.0):.3f}",
        f"7d live: setups/day={float(m7.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m7.get('setups',0) or 0)} | WR={float(m7.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m7.get('avg_R',0.0) or 0.0):.3f}",
    ]
    top = list(rep.get('top_candidates') or [])[:5]
    if top:
        lines.append('Top candidates:')
        for row in top:
            m30c = row.get('metrics_30d') or {}
            lines.append(f"• {row.get('profile')}/{row.get('bundle')} | score={float(row.get('score',0.0) or 0.0):.2f} | 30d {float(m30c.get('setups_per_day',0.0) or 0.0):.2f}/day @ WR {float(m30c.get('win_rate',0.0) or 0.0):.1f}%")
    try:
        await send_long_message(update, '\n'.join(lines), parse_mode=None)
    except Exception:
        await update.message.reply_text('\n'.join(lines))

async def goal_profile_status_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    cfg = load_strategy_config(force=False)
    tgt = _goal_profile_targets(cfg)
    rep = load_goal_profile_report() or {}
    final = rep.get('final') or {}
    current = rep.get('current') or {}
    m30 = final.get('metrics_30d') or {}
    m7 = final.get('metrics_7d') or {}
    current_profile = str(cfg.get('goal_profile_active_profile') or current.get('goal_profile_active_profile') or 'BASELINE')
    current_sessions = ','.join(cfg.get('execution_sessions_allowed') or current.get('execution_sessions_allowed') or []) or '-'
    current_engines = ','.join(cfg.get('execution_engines_allowed') or current.get('execution_engines_allowed') or []) or '-'
    lines = [
        '🎯 Goal Profile Status',
        HDR,
        f"Enabled: {'ON' if tgt['enabled'] else 'OFF'} | Interval: {float(tgt['interval_hours']):.1f}h | Cooldown: {float(tgt['cooldown_hours']):.1f}h",
        f"Target: {float(tgt['target_lo']):.2f}–{float(tgt['target_hi']):.2f} setups/day | WR≥{float(tgt['target_wr']):.1f}% | AvgR≥{float(tgt['target_avg_r']):.2f}",
        f"Minimum live sample: 30d≥{int(tgt['min_live_30d'])} | 7d≥{int(tgt['min_live_7d'])}",
        f"Search space: NY={'ON' if bool(tgt.get('allow_ny')) else 'OFF'} | ASIA={'ON' if bool(tgt.get('allow_asia')) else 'OFF'} | Engine B={'ON' if bool(tgt.get('allow_engine_b')) else 'OFF'}",
        f"Current execution profile: {current_profile} | sessions={current_sessions} | engines={current_engines}",
    ]
    if rep:
        ts_val = float(rep.get('ts', 0.0) or 0.0)
        lines.append(f"Last run status: {rep.get('status','')} | ts={_fmt_dt_local(datetime.fromtimestamp(ts_val, tz=timezone.utc)) if ts_val > 0 else '—'}")
        if str(rep.get('status') or '').upper() in ('RUNNING', 'STOPPING'):
            started_ts = float(rep.get('started_ts', 0.0) or 0.0)
            if started_ts > 0:
                lines.append(f"Started: {_fmt_dt_local(datetime.fromtimestamp(started_ts, tz=timezone.utc))}")
            prog = dict(rep.get('progress') or {})
            if prog:
                idx = int(prog.get('candidate_idx', 0) or 0)
                total = int(prog.get('candidate_total', 0) or 0)
                stage = str(prog.get('stage') or 'running')
                elapsed = float(prog.get('elapsed_sec', 0.0) or 0.0)
                lines.append(f"Progress: {stage} | candidate {idx}/{total} | elapsed {elapsed/60.0:.1f} min")
                cur = dict(prog.get('current_candidate') or {})
                if cur:
                    lines.append(f"Current candidate: {cur.get('profile','?')}/{cur.get('bundle','?')} | sessions={','.join(cur.get('sessions') or []) or '-'} | engines={','.join(cur.get('engines') or []) or '-'}")
                best = dict(prog.get('best_candidate') or {})
                if best:
                    lines.append(f"Best so far: {best.get('profile','?')}/{best.get('bundle','?')} | score={float(best.get('score',0.0) or 0.0):.2f}")
                note = str(prog.get('note') or '').strip()
                if note:
                    lines.append(f"Note: {note}")
            last_final = dict(rep.get('last_final') or {})
            last_final_metrics = dict((last_final.get('final') or {}).get('metrics_30d') or {})
            last_final_metrics7 = dict((last_final.get('final') or {}).get('metrics_7d') or {})
            if last_final_metrics:
                lines.append(f"Last finalized 30d: setups/day={float(last_final_metrics.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(last_final_metrics.get('setups',0) or 0)} | WR={float(last_final_metrics.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(last_final_metrics.get('avg_R',0.0) or 0.0):.3f}")
            if last_final_metrics7:
                lines.append(f"Last finalized 7d: setups/day={float(last_final_metrics7.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(last_final_metrics7.get('setups',0) or 0)} | WR={float(last_final_metrics7.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(last_final_metrics7.get('avg_R',0.0) or 0.0):.3f}")
        elif final:
            lines.append(f"30d live: setups/day={float(m30.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m30.get('setups',0) or 0)} | WR={float(m30.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m30.get('avg_R',0.0) or 0.0):.3f}")
            lines.append(f"7d live: setups/day={float(m7.get('setups_per_day',0.0) or 0.0):.2f} | setups={int(m7.get('setups',0) or 0)} | WR={float(m7.get('win_rate',0.0) or 0.0):.1f}% | AvgR={float(m7.get('avg_R',0.0) or 0.0):.3f}")
        if rep.get('error'):
            lines.append(f"Error: {rep.get('error')}")
    await send_long_message(update, '\n'.join(lines), parse_mode=None)

async def goal_profile_set_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not _is_admin(update):
        await update.message.reply_text('⛔ Admin only.')
        return
    args = list(context.args or [])
    if len(args) < 3:
        await update.message.reply_text('Usage: /goal_set <setups_per_day_low> <setups_per_day_high> <win_rate_target> [avgR_target]')
        return
    try:
        lo = float(args[0])
        hi = float(args[1])
        wr = float(args[2])
        avg_r = float(args[3]) if len(args) >= 4 else None
    except Exception:
        await update.message.reply_text('Invalid numbers. Example: /goal_set 1 3 50 0.10')
        return
    cfg = load_strategy_config(force=True)
    cfg['goal_profile_target_setups_per_day_lo'] = float(max(0.1, lo))
    cfg['goal_profile_target_setups_per_day_hi'] = float(max(cfg['goal_profile_target_setups_per_day_lo'], hi))
    cfg['goal_profile_target_win_rate'] = float(max(1.0, min(95.0, wr)))
    if avg_r is not None:
        cfg['goal_profile_target_avg_r'] = float(avg_r)
    save_strategy_config(cfg)
    apply_strategy_config(cfg)
    await update.message.reply_text(f"✅ Goal updated: {cfg['goal_profile_target_setups_per_day_lo']:.2f}–{cfg['goal_profile_target_setups_per_day_hi']:.2f}/day | WR≥{cfg['goal_profile_target_win_rate']:.1f}% | AvgR≥{float(cfg.get('goal_profile_target_avg_r', 0.10) or 0.10):.2f}")


async def goal_profile_job(context: ContextTypes.DEFAULT_TYPE):
    try:
        cfg = load_strategy_config(force=False)
        tgt = _goal_profile_targets(cfg)
        if not tgt['enabled']:
            return
        if _SELF_OPT_STATE.get('stop_event') is not None:
            return
        if _goal_profile_is_running():
            return
        if not _goal_profile_is_due(time.time(), cfg=cfg):
            return
        await to_thread_heavy(_run_goal_profile_cycle, False)
    except Exception:
        return


async def research_framework_watchdog_job(context: ContextTypes.DEFAULT_TYPE):
    """Safety net for daily research refresh and goal-profile automation.

    Why it exists:
    - repeating jobs can drift or miss the exact anchored-day rollover
    - the daily research layer must populate even if the 24h job has not fired yet
    - goal-profile monitoring should auto-run when due, even after a timeout report
    """
    try:
        now_ts = float(time.time())
        cfg = load_strategy_config(force=False)

        if _cfg_bool((cfg or {}).get('family_allocator_enabled', True), True):
            if _research_daily_refresh_due(now_ts):
                await to_thread_heavy(_research_run_daily_refresh, True)

        if _goal_profile_is_due(now_ts, cfg=cfg):
            if _cfg_bool((cfg or {}).get('goal_profile_enabled', True), True) and (not _goal_profile_is_running()) and _SELF_OPT_STATE.get('stop_event') is None:
                await to_thread_heavy(_run_goal_profile_cycle, False)
    except Exception:
        return


def _session_entry_quality_limits(session_name: str, source: str = 'email') -> dict:
    sess = str(session_name or '').upper().strip() or 'NY'
    base = {
        'NY': {'max_pb_ema_dist': 0.60, 'max_ch15_abs': 0.52, 'max_ch1_abs': 1.15, 'max_atr_pct': 4.0},
        'LON': {'max_pb_ema_dist': 0.60, 'max_ch15_abs': 0.52, 'max_ch1_abs': 1.14, 'max_atr_pct': 4.4},
        'ASIA': {'max_pb_ema_dist': 0.44, 'max_ch15_abs': 0.38, 'max_ch1_abs': 0.90, 'max_atr_pct': 3.3},
    }.get(sess, {'max_pb_ema_dist': 0.52, 'max_ch15_abs': 0.44, 'max_ch1_abs': 1.00, 'max_atr_pct': 4.0}).copy()
    src = str(source or '').strip().lower()
    if src == 'screen':
        base['max_pb_ema_dist'] *= (1.07 if sess != 'ASIA' else 1.04)
        base['max_ch15_abs'] *= (1.05 if sess != 'ASIA' else 1.03)
        base['max_ch1_abs'] *= (1.05 if sess != 'ASIA' else 1.03)
        base['max_atr_pct'] *= (1.04 if sess != 'ASIA' else 1.02)
    elif src == 'exec':
        base['max_pb_ema_dist'] *= (1.05 if sess == 'LON' else (1.03 if sess != 'ASIA' else 1.01))
        base['max_ch15_abs'] *= (1.05 if sess == 'LON' else (1.02 if sess != 'ASIA' else 1.01))
        base['max_ch1_abs'] *= (1.04 if sess == 'LON' else (1.02 if sess != 'ASIA' else 1.01))
        base['max_atr_pct'] *= (1.03 if sess == 'LON' else (1.02 if sess != 'ASIA' else 1.01))
    return base


def _setup_entry_quality_gate(s: 'Setup', session_name: str = 'NY', source: str = 'email') -> tuple[bool, str]:
    try:
        limits = _session_entry_quality_limits(session_name, source=source)
        leader_base = bool(getattr(s, 'leader_base_override', False))
        engine = str(getattr(s, 'engine', '') or '').upper().strip()
        cfg_live = load_strategy_config(force=False)
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))
        sess = str(session_name or '').upper().strip()
        conf = int(getattr(s, 'conf', 0) or 0)
        score = float(getattr(s, 'quality_score', 0.0) or 0.0)
        pb_dist = float(getattr(s, 'pullback_ema_dist_pct', 999.0) or 999.0)
        ch15_abs = abs(float(getattr(s, 'ch15', 0.0) or 0.0))
        ch1_abs = abs(float(getattr(s, 'ch1', 0.0) or 0.0))
        ch4_abs = abs(float(getattr(s, 'ch4', 0.0) or 0.0))
        ch24_abs = abs(float(getattr(s, 'ch24', 0.0) or 0.0))
        atr_pct = float(getattr(s, 'atr_pct', 0.0) or 0.0)

        if leader_base:
            return (True, 'ok')

        max_pb = float(limits['max_pb_ema_dist']) + (0.10 if engine == 'B' else 0.0)
        max_ch15 = float(limits['max_ch15_abs']) + (0.20 if engine == 'B' else 0.0)
        max_ch1 = float(limits['max_ch1_abs']) + (0.50 if engine == 'B' else 0.0)
        max_atr = float(limits['max_atr_pct']) + (0.60 if engine == 'B' else 0.0)
        if reach_mode and sess == 'LON' and engine in {'A', 'C'}:
            max_pb += 0.14
            max_ch15 += 0.16
            max_ch1 += 0.18
            max_atr += 0.45

        if pb_dist > max_pb:
            return (False, 'entry_far_from_pullback_ema')
        if ch15_abs > max_ch15:
            return (False, 'entry_too_extended_15m')
        if engine not in {'B', 'C'} and ch1_abs > max_ch1:
            return (False, 'entry_too_extended_1h')
        if atr_pct > 0 and atr_pct > max_atr:
            return (False, 'poor_volatility_regime_exec')

        if engine == 'A':
            if sess == 'LON':
                lon_ctx_ch4_min = 0.48 if reach_mode else 0.64
                lon_ctx_ch1_min = 0.18 if reach_mode else 0.30
                if ch4_abs < lon_ctx_ch4_min or ch1_abs < lon_ctx_ch1_min:
                    return (False, 'lon_pullback_context_too_weak')
            if sess == 'NY' and (ch4_abs < 0.80 or ch1_abs < 0.42):
                return (False, 'ny_pullback_context_too_weak')
            if sess == 'ASIA' and (ch4_abs < 0.95 or ch1_abs < 0.50):
                return (False, 'asia_pullback_context_too_weak')
            if sess == 'LON' and ch24_abs > (13.6 if reach_mode else 11.5) and pb_dist > (0.48 if reach_mode else 0.34):
                return (False, 'lon_trend_overheated')
        if sess == 'NY' and ch1_abs >= 1.55 and ch15_abs >= 0.70 and conf < 86 and score < 82.0:
            return (False, 'ny_breakout_chase_risk')
        return (True, 'ok')
    except Exception:
        return (False, 'entry_quality_gate_exception')


def is_top_setup_eligible(

    s: "Setup",
    source: str = "screen",
    session_name: str = "LON",
) -> tuple[bool, str]:
    """Unified single-TP eligibility using scoring + a few safety checks.

    - source='screen' => loosest display lane
    - source='exec'   => authoritative executable pool pre-gate
    - source='email'  => strictest downstream lane
    """
    try:
        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        side = str(getattr(s, "side", "") or "").upper()

        if entry <= 0 or sl <= 0 or final_tp <= 0 or side not in ("BUY", "SELL"):
            return (False, "bad_prices_or_side")

        if side == "BUY" and not (sl < entry < final_tp):
            return (False, "bad_price_order_buy")
        if side == "SELL" and not (final_tp < entry < sl):
            return (False, "bad_price_order_sell")

        try:
            setattr(s, "tp", float(final_tp))
            setattr(s, "alt_target_a", 0.0)
            setattr(s, "alt_target_b", 0.0)
        except Exception:
            pass

        score, comps = compute_setup_quality_score(s, session_name=session_name)
        setattr(s, "quality_score", float(score))
        try:
            setattr(s, "quality_components", comps)
        except Exception:
            pass

        cfg_live = load_strategy_config(force=False)
        engine_c_base_score_add = float((cfg_live or {}).get('engine_c_base_score_add', 0.0) or 0.0)
        src = str(source or "screen").strip().lower()
        if src not in {"screen", "email", "exec"}:
            src = "screen"
        sess = str(session_name or 'LON').upper().strip()
        engine = str(getattr(s, 'engine', '') or '').upper().strip()
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))

        if src == "screen":
            min_score = float(QUALITY_SCORE_MIN_SCREEN)
        elif src == "exec":
            min_score = float(max(QUALITY_SCORE_MIN_SCREEN + 3.0, QUALITY_SCORE_MIN_EMAIL - 2.0))
        else:
            min_score = float(QUALITY_SCORE_MIN_EMAIL)

        if src == 'email':
            if engine == 'A':
                if sess == 'LON':
                    min_score += 0.5
                elif sess == 'NY':
                    min_score += 1.0
                elif sess == 'ASIA':
                    min_score += 1.5
            elif engine == 'B':
                min_score += 4.0 if sess in {'NY', 'ASIA'} else 2.5
            elif engine == 'C':
                min_score += (1.5 if sess != 'ASIA' else 2.0) + engine_c_base_score_add
        elif src == 'exec':
            if engine == 'A':
                min_score += -0.25 if sess == 'LON' else (0.50 if sess == 'NY' else 0.75)
            elif engine == 'B':
                min_score += 1.5 if sess in {'NY', 'ASIA'} else 1.0
            elif engine == 'C':
                min_score += (1.0 if sess != 'ASIA' else 1.5) + engine_c_base_score_add
        else:
            if engine == 'A':
                min_score += 0.0 if sess == 'LON' else (0.5 if sess == 'NY' else 1.0)
            elif engine == 'B':
                min_score += 2.0 if sess in {'NY', 'ASIA'} else 1.0
            elif engine == 'C':
                min_score += (0.8 if sess != 'ASIA' else 1.2) + engine_c_base_score_add
        if reach_mode and sess == 'LON' and engine in {'A', 'C'}:
            if src == 'exec':
                min_score -= 4.0 if engine == 'A' else 3.0
            elif src == 'email':
                min_score -= 1.5 if engine == 'A' else 1.0
            else:
                min_score -= 0.75 if engine == 'A' else 0.50
        min_score = float(clamp(min_score, 56.0 if reach_mode and sess == 'LON' else 60.0, 90.0))

        if float(score) < float(min_score):
            return (False, f"below_score_{int(round(min_score))}")

        ok_entry, why_entry = _setup_entry_quality_gate(s, session_name=session_name, source=src)
        if not ok_entry:
            return (False, why_entry)

        fut_vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)
        vol_floor = float(MIN_FUT_VOL_USD)
        if sess == 'NY':
            vol_floor = max(vol_floor, 12_000_000.0)
        elif sess == 'ASIA':
            vol_floor = max(vol_floor * 1.05, ASIA_MIN_FUT_VOL_USD)
        if fut_vol < vol_floor:
            return (False, "below_min_fut_vol")

        return (True, "ok")
    except Exception:
        return (False, "eligibility_exception")

def _execution_session_thresholds(session_name: str) -> tuple[float, int, float]:
    """Moderately strict executable thresholds for a shared cross-session pool.

    These floors are intentionally below the final per-engine executable checks so the
    authoritative executable lane does not self-starve before email/autotrade consume it.
    """
    sess = str(session_name or "").upper().strip()
    if sess == "NY":
        quality, conf, rr = 80.0, 81, 1.44
    elif sess == "LON":
        quality, conf, rr = 77.0, 79, 1.35
    elif sess == "ASIA":
        quality, conf, rr = 83.0, 84, 1.50
    else:
        quality, conf, rr = 79.0, 80, 1.38

    try:
        cfg = load_strategy_config(force=False)
        ov_all = (cfg or {}).get("session_exec_overrides") or {}
        ov = ov_all.get(sess) or {}
        quality += float(ov.get("quality_add", 0.0) or 0.0)
        conf += int(round(float(ov.get("conf_add", 0) or 0)))
        rr += float(ov.get("rr_add", 0.0) or 0.0)
    except Exception:
        pass

    quality = float(clamp(quality, 72.0, 92.0))
    conf = int(max(74, min(95, conf)))
    rr = float(clamp(rr, 1.30, 2.30))
    return (quality, conf, rr)


def is_executable_setup_eligible(
    s: "Setup",
    session_name: str = "NY",
    min_quality: float = 70.0,
    min_conf: int = 78,
    min_rr_final: float = 0.0,
) -> tuple[bool, str]:
    """Production-grade gate for executable/email/autotrade path.

    Key rule:
    - executability is session-aware by thresholds
    - executability is NOT silently session-blocked by strategy policy
    - downstream email/autotrade session preferences decide consumption
    """
    try:
        sess = str(session_name or "").upper().strip()
        if sess not in {"ASIA", "LON", "NY"}:
            return (False, "session_not_supported")

        cfg_live = load_strategy_config(force=False)
        exec_engine_b_enabled = _cfg_bool((cfg_live or {}).get("execution_engine_b_email_enabled", EXECUTION_ENGINE_B_EMAIL_ENABLED), bool(EXECUTION_ENGINE_B_EMAIL_ENABLED))
        engine_c_exec_quality_add = float((cfg_live or {}).get('engine_c_exec_quality_add', 0.0) or 0.0)
        engine_c_exec_conf_add = int(round(float((cfg_live or {}).get('engine_c_exec_conf_add', 0) or 0)))
        engine_c_exec_rr_add = float((cfg_live or {}).get('engine_c_exec_rr_add', 0.0) or 0.0)
        engine_c_exec_liq_mult = float((cfg_live or {}).get('engine_c_exec_liq_mult', 1.10) or 1.10)
        engine_c_exec_ch1_cap_lon = float((cfg_live or {}).get('engine_c_exec_ch1_cap_lon', 1.20) or 1.20)
        engine_c_exec_pb_dist_lon = float((cfg_live or {}).get('engine_c_exec_pb_dist_lon', 0.68) or 0.68)
        active_profile = str((cfg_live or {}).get('goal_profile_active_profile', '') or '').upper().strip()
        reach_mode = bool(_cfg_bool((cfg_live or {}).get('goal_profile_reach_mode', False), False) or ('REACH' in active_profile) or active_profile.endswith('_SCOUT'))
        allowed_sessions = _strategy_cfg_execution_sessions_allowed(cfg_live)
        if allowed_sessions and sess not in allowed_sessions:
            return (False, 'execution_profile_session_disabled')
        allowed_engines = _strategy_cfg_execution_engines_allowed(cfg_live)
        try:
            s = _research_finalize_setup(s, session_name=sess)
        except Exception:
            pass
        _engine_pre = str(getattr(s, "engine", "") or "").upper().strip()
        if allowed_engines and _engine_pre and _engine_pre not in allowed_engines:
            return (False, 'execution_profile_engine_disabled')

        alloc_ok, alloc_why = _research_plan_allows_setup(s, session_name=sess)
        if not alloc_ok:
            return (False, str(alloc_why or 'allocator_blocked'))

        ok, why = is_top_setup_eligible(s, source='exec', session_name=sess)
        if not ok:
            return (False, f"base_gate_{why}")

        sess_quality, sess_conf, sess_rr = _execution_session_thresholds(sess)
        score_floor = float(max(min_quality, QUALITY_SCORE_MIN_EMAIL - 3.0, sess_quality))
        conf_floor = int(max(min_conf, MIN_SETUP_CONF, sess_conf))
        rr_floor = float(max(min_rr_final, sess_rr))

        engine = str(getattr(s, "engine", "") or "").upper().strip()
        regime = str(getattr(s, 'regime', '') or '').upper()
        trend = str(getattr(s, 'trend', '') or '').upper()
        structure = str(getattr(s, 'structure', '') or '').upper()
        side = str(getattr(s, 'side', '') or '').upper()
        want = 'BULLISH' if side == 'BUY' else 'BEARISH' if side == 'SELL' else ''

        if engine == 'A':
            if sess == 'LON':
                score_floor = max((69.0 if reach_mode else 75.0), score_floor)
                conf_floor = max((75 if reach_mode else 79), conf_floor)
                rr_floor = max((1.24 if reach_mode else 1.34), rr_floor)
            elif sess == 'NY':
                score_floor = max(81.0, score_floor)
                conf_floor = max(82, conf_floor)
                rr_floor = max(1.45, rr_floor)
            else:
                score_floor = max(84.0, score_floor)
                conf_floor = max(85, conf_floor)
                rr_floor = max(1.52, rr_floor)
        elif engine == 'C':
            if sess == 'LON':
                score_floor = max((68.5 if reach_mode else 74.5), score_floor - 0.50 + engine_c_exec_quality_add)
                conf_floor = max((75 if reach_mode else 78), conf_floor + engine_c_exec_conf_add)
                rr_floor = max((1.22 if reach_mode else 1.32), rr_floor - 0.03 + engine_c_exec_rr_add)
            elif sess == 'NY':
                score_floor = max(80.0, score_floor + 1.0 + engine_c_exec_quality_add)
                conf_floor = max(83, conf_floor + 1 + engine_c_exec_conf_add)
                rr_floor = max(1.44, rr_floor + 0.05 + engine_c_exec_rr_add)
            else:
                score_floor = max(84.0, score_floor + 1.25 + engine_c_exec_quality_add)
                conf_floor = max(86, conf_floor + 2 + engine_c_exec_conf_add)
                rr_floor = max(1.54, rr_floor + 0.07 + engine_c_exec_rr_add)
        elif engine == 'B':
            if not exec_engine_b_enabled:
                return (False, 'engine_b_disabled')
            if sess == 'LON':
                score_floor = max(84.0, score_floor + 2.0)
                conf_floor = max(85, conf_floor + 2)
                rr_floor = max(1.54, rr_floor + 0.08)
            elif sess == 'NY':
                score_floor = max(86.0, score_floor + 2.5)
                conf_floor = max(87, conf_floor + 2)
                rr_floor = max(1.62, rr_floor + 0.10)
            else:
                score_floor = max(88.0, score_floor + 3.0)
                conf_floor = max(88, conf_floor + 3)
                rr_floor = max(1.68, rr_floor + 0.12)
        else:
            return (False, 'engine_not_supported')

        if 'TREND' not in regime:
            return (False, 'regime_not_trend')
        if want and (want not in trend or want not in structure):
            return (False, 'trend_structure_not_aligned')

        score = float(getattr(s, "quality_score", 0.0) or 0.0)
        if score < score_floor:
            return (False, "below_exec_quality")

        conf = int(getattr(s, "conf", 0) or 0)
        if conf < conf_floor:
            return (False, "below_exec_conf")

        entry = float(getattr(s, "entry", 0.0) or 0.0)
        sl = float(getattr(s, "sl", 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
        if rr_final < rr_floor:
            return (False, "below_exec_rr")

        fut_vol = float(getattr(s, "fut_vol_usd", 0.0) or 0.0)
        pb_dist = float(getattr(s, "pullback_ema_dist_pct", 999.0) or 999.0)
        ch15_abs = abs(float(getattr(s, "ch15", 0.0) or 0.0))
        ch1_abs = abs(float(getattr(s, "ch1", 0.0) or 0.0))
        ch4_abs = abs(float(getattr(s, "ch4", 0.0) or 0.0))
        ch24_abs = abs(float(getattr(s, "ch24", 0.0) or 0.0))

        if sess == "NY":
            if pb_dist > 0.75:
                return (False, "ny_entry_too_far_from_ema")
            if ch15_abs > 0.82 or (ch15_abs > 0.72 and ch1_abs > 1.55):
                return (False, "ny_late_extension_exec")
            if ch4_abs < 0.62 or ch1_abs < 0.32:
                return (False, "ny_context_too_weak_exec")
            if fut_vol < max(MIN_FUT_VOL_USD, 10_500_000.0):
                return (False, "ny_below_liquidity")
        elif sess == "LON":
            lon_pb_max = 0.74 if reach_mode else 0.60
            lon_ch15_cap = 0.68 if reach_mode else 0.54
            lon_ch1_cap = 1.35 if reach_mode else 1.18
            lon_ctx_ch4_min = 0.40 if reach_mode else 0.52
            lon_ctx_ch1_min = 0.16 if reach_mode else 0.24
            lon_liq_floor = max(MIN_FUT_VOL_USD * (0.82 if reach_mode else 1.0), 8_500_000.0 if reach_mode else 11_000_000.0)
            if engine == 'C':
                lon_pb_max = max(lon_pb_max, engine_c_exec_pb_dist_lon)
                lon_ch1_cap = max(lon_ch1_cap, engine_c_exec_ch1_cap_lon)
                lon_liq_floor = max(MIN_FUT_VOL_USD * engine_c_exec_liq_mult, ENGINE_C_MIN_FUT_VOL_USD)
                lon_ctx_ch4_min = min(lon_ctx_ch4_min, 0.48)
                lon_ctx_ch1_min = min(lon_ctx_ch1_min, 0.22)
            if pb_dist > lon_pb_max:
                return (False, "lon_entry_too_far_from_ema")
            if ch15_abs > lon_ch15_cap or ch1_abs > lon_ch1_cap:
                return (False, "lon_late_extension_exec")
            if ch4_abs < lon_ctx_ch4_min or ch1_abs < lon_ctx_ch1_min:
                return (False, "lon_context_too_weak_exec")
            if ch4_abs > (2.85 if reach_mode else 2.55) or ch24_abs > (15.2 if reach_mode else 13.8):
                return (False, "lon_trend_overheated_exec")
            if fut_vol < lon_liq_floor:
                return (False, "lon_below_liquidity")
        elif sess == "ASIA":
            if pb_dist > 0.58:
                return (False, "asia_entry_too_far_from_ema")
            if ch15_abs > 0.58 or ch1_abs > 1.22:
                return (False, "asia_late_extension_exec")
            if ch4_abs < 0.78 or ch1_abs < 0.38:
                return (False, "asia_context_too_weak_exec")
            if fut_vol < float(max(MIN_FUT_VOL_USD * 1.05, ASIA_MIN_FUT_VOL_USD)):
                return (False, "asia_below_liquidity")

        if engine == "A":
            if not (bool(getattr(s, "pullback_ready", False)) or bool(getattr(s, "pullback_bypass_hot", False))):
                return (False, "pullback_not_ready")
            if pb_dist > ((0.68 if reach_mode else 0.54) if sess == 'LON' else (0.60 if sess == 'NY' else 0.54)):
                return (False, "pullback_still_too_shallow")
            if sess == 'LON' and (ch15_abs > (0.62 if reach_mode else 0.46) or ch1_abs < (0.16 if reach_mode else 0.28) or ch1_abs > (1.28 if reach_mode else 1.08) or ch4_abs < (0.48 if reach_mode else 0.60)):
                return (False, 'lon_pullback_not_clean_enough')
            return (True, "ok")

        if engine == "C":
            c_quality_floor = score_floor + (0.00 if reach_mode and sess == 'LON' else 0.25)
            c_conf_floor = max(75 if (reach_mode and sess == 'LON') else conf_floor, conf_floor - (1 if reach_mode and sess == 'LON' else 0))
            c_rr_floor = max(1.20 if (reach_mode and sess == 'LON') else rr_floor, rr_floor - (0.04 if reach_mode and sess == 'LON' else 0.0))
            c_liq_floor = float(max(MIN_FUT_VOL_USD * (engine_c_exec_liq_mult if not (reach_mode and sess == 'LON') else 0.85), 8_000_000.0 if (reach_mode and sess == 'LON') else ENGINE_C_MIN_FUT_VOL_USD))
            c_ch1_cap = (max(engine_c_exec_ch1_cap_lon, 1.55) if (reach_mode and sess == 'LON') else engine_c_exec_ch1_cap_lon) if sess == 'LON' else (1.45 if sess == 'NY' else 1.10)
            if score < c_quality_floor:
                return (False, "engine_c_below_quality")
            if conf < c_conf_floor:
                return (False, "engine_c_below_conf")
            if rr_final < c_rr_floor:
                return (False, "engine_c_below_rr")
            if fut_vol < c_liq_floor:
                return (False, "engine_c_below_liquidity")
            if ch1_abs > c_ch1_cap:
                return (False, "engine_c_too_extended")
            return (True, "ok")

        if engine == "B":
            if score < (score_floor + 1.5):
                return (False, "engine_b_below_quality")
            if conf < (conf_floor + 1):
                return (False, "engine_b_below_conf")
            if rr_final < (rr_floor + 0.05):
                return (False, "engine_b_below_rr")
            if fut_vol < float(max(MIN_FUT_VOL_USD * (1.10 if sess != 'ASIA' else 1.18), 15_000_000.0 if sess != 'ASIA' else ASIA_MIN_FUT_VOL_USD)):
                return (False, "engine_b_below_liquidity")
            return (True, "ok")

        return (False, "engine_not_supported")
    except Exception:
        return (False, "executable_gate_exception")

def compute_confidence(side: str, ch24: float, ch4: float, ch1: float, ch15: float, fut_vol_usd: float) -> int:
    """
    Stricter confidence designed for:
    - Fewer, higher quality continuation signals
    - Avoiding mid-wave / pump entries
    - Preferring "pullback then continuation" (15m should be mild or slightly counter-trend)
    """
    is_long = (side == "BUY")

    # Base score starts lower to reduce inflated confidences
    score = 36.0

    # -----------------------------
    # 1) Higher-TF alignment first
    # -----------------------------
    def aligned(x: float) -> bool:
        return (x > 0) if is_long else (x < 0)

    a24 = aligned(ch24)
    a4  = aligned(ch4)
    a1  = aligned(ch1)
    a15 = aligned(ch15)

    align_count = int(a24) + int(a4) + int(a1) + int(a15)

    # Stronger reward for 4H/1H alignment (regime + execution TF)
    score += 14.0 if a4 else -18.0
    score += 12.0 if a1 else -16.0

    # 24H matters, but less than 4H/1H for trade execution quality
    score += 8.0 if a24 else -10.0

    # 15m alignment is NOT always good for entries (pumps are bad entries)
    # We'll handle 15m separately as "pullback quality"
    # (so do not add big alignment reward here)
    score += 2.0 if a15 else -2.0

    # Hard cap if the structure is weak:
    # If 4H+1H disagree with your side, confidence should never be high.
    if (not a4) and (not a1):
        return int(55)  # keep it low; you can also return 0 if you want total block

    # If at least 3 TFs align (24/4/1/15), small boost
    if align_count >= 3:
        score += 6.0
    elif align_count <= 1:
        score -= 10.0

    # -----------------------------
    # 2) Magnitude scoring (capped)
    # -----------------------------
    def signed_mag(x: float, k: float) -> float:
        return (abs(x) * k) if aligned(x) else (-abs(x) * k)

    mag = (
        signed_mag(ch24, 0.5) +
        signed_mag(ch4,  0.9) +
        signed_mag(ch1,  1.2) +
        signed_mag(ch15, 0.6)
    )
    mag = clamp(mag, -18.0, 18.0)
    score += mag

    # -----------------------------
    # 3) Anti-pump + pullback preference (15m behavior)
    # -----------------------------
    # For continuation entries:
    # - We *don't* want 15m strongly in-trend (often means mid-wave / extended).
    # - We *do* like mild pullback against the trend (e.g. -0.3% to -1.2% in BUY).
    ch15_abs = abs(float(ch15))

    if is_long:
        # Mid-wave pump penalty: 15m strongly positive
        if ch15 >= 0.8:
            score -= 12.0
        elif ch15 >= 0.4:
            score -= 6.0

        # Preferred pullback zone (slight red 15m)
        if -1.2 <= ch15 <= -0.25:
            score += 10.0
        elif -2.2 <= ch15 < -1.2:
            score += 4.0

        # Too much dump into support = unstable
        if ch15 <= -2.8:
            score -= 10.0
    else:
        # Mid-wave dump penalty: 15m strongly negative
        if ch15 <= -0.8:
            score -= 12.0
        elif ch15 <= -0.4:
            score -= 6.0

        # Preferred pullback zone (slight green 15m)
        if 0.25 <= ch15 <= 1.2:
            score += 10.0
        elif 1.2 < ch15 <= 2.2:
            score += 4.0

        # Too much pump into resistance = unstable
        if ch15 >= 2.8:
            score -= 10.0

    # -----------------------------
    # 4) Volume bonus (smaller + only when structure is already good)
    # -----------------------------
    # Volume should NOT rescue a bad setup.
    # Only add if score already indicates decent structure.
    if score >= 60.0:
        if fut_vol_usd >= 40_000_000:
            score += 5.0
        elif fut_vol_usd >= 15_000_000:
            score += 3.0
        elif fut_vol_usd >= 6_000_000:
            score += 1.5

    # Public confidence should remain conservative; quality_score is the main gate.
    score = clamp(score, 0.0, 92.0)
    return int(round(score))


def build_leaders_table(best_fut: Dict[str, MarketVol]) -> str:
    leaders = sorted(best_fut.items(), key=lambda kv: usd_notional(kv[1]), reverse=True)[:LEADERS_N]
    rows = []

    for base, mv in leaders:
        # ✅ 4H change from real 4h candles (light: limit=2)
        ch4 = 0.0
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=2)
            if c4h and len(c4h) >= 2:
                c_last = float(c4h[-1][4])
                c_prev = float(c4h[-2][4])
                if c_prev > 0:
                    ch4 = ((c_last - c_prev) / c_prev) * 100.0
        except Exception:
            ch4 = 0.0

        rows.append([
            base,
            fmt_money(usd_notional(mv)),
            pct_with_emoji(float(mv.percentage or 0.0)),  # 24H
            pct_with_emoji(float(ch4)),                  # 4H
        ])

    return "*Market Leaders (Top 10 by Futures Volume)*\n" + table_md(rows, ["SYM", "F Vol", "24H", "4H"])

def compute_directional_lists(best_fut: Dict[str, MarketVol]) -> Tuple[List[Tuple], List[Tuple]]:
    """
    Fast + rate-limit-safe directional movers.

    Cached briefly because /screen may be called repeatedly while the market snapshot
    itself has barely changed.
    """
    try:
        bases = sorted(str(k) for k in (best_fut or {}).keys())
        fingerprint = f"{len(bases)}:{'|'.join(bases[:30])}:{'|'.join(bases[-5:]) if len(bases) > 35 else ''}"
    except Exception:
        fingerprint = f"{len(best_fut or {})}"
    cache_key = f"screen_directional_lists:{fingerprint}"
    try:
        if cache_valid(cache_key, int(SCREEN_DIRECTIONAL_CACHE_TTL_SEC or 45)):
            cached = cache_get(cache_key)
            if isinstance(cached, dict):
                return list(cached.get('up') or []), list(cached.get('dn') or [])
    except Exception:
        pass

    up, dn = [], []
    try:
        candidates = []
        for base, mv in best_fut.items():
            vol = usd_notional(mv)
            if vol < MOVER_VOL_USD_MIN:
                continue
            ch24 = float(mv.percentage or 0.0)
            if ch24 < MOVER_UP_24H_MIN and ch24 > MOVER_DN_24H_MAX:
                continue
            candidates.append((base, mv, vol, ch24))
        candidates.sort(key=lambda x: x[2], reverse=True)
        candidates = candidates[:18]
    except Exception:
        candidates = []

    for base, mv, vol, ch24 in candidates:
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=2)
            if not c4h or len(c4h) < 2:
                continue
            c_last = float(c4h[-1][4])
            c_prev = float(c4h[-2][4])
            if c_prev <= 0:
                continue
            ch4 = ((c_last - c_prev) / c_prev) * 100.0
        except Exception:
            continue

        if ch24 >= MOVER_UP_24H_MIN and ch4 > 0:
            up.append((base, vol, ch24, ch4, float(mv.last or 0.0)))
        if ch24 <= MOVER_DN_24H_MAX and ch4 < 0:
            dn.append((base, vol, ch24, ch4, float(mv.last or 0.0)))

    up.sort(key=lambda x: (x[2], x[1]), reverse=True)
    dn.sort(key=lambda x: (x[2], x[1]))
    try:
        cache_set(cache_key, {'up': list(up), 'dn': list(dn)})
    except Exception:
        pass
    return up, dn

def movers_tables(best_fut: Dict[str, MarketVol]) -> Tuple[str, str]:
    up, dn = compute_directional_lists(best_fut)
    up_rows = [[b, fmt_money(v), pct_with_emoji(c24), pct_with_emoji(c4)] for b, v, c24, c4, px in up[:10]]
    dn_rows = [[b, fmt_money(v), pct_with_emoji(c24), pct_with_emoji(c4)] for b, v, c24, c4, px in dn[:10]]
    up_txt = "*Directional Leaders (24H ≥ +10%, F vol ≥ 5M, 4H aligned)*\n" + (table_md(up_rows, ["SYM", "F Vol", "24H", "4H"]) if up_rows else "_None_")
    dn_txt = "*Directional Losers (24H ≤ -10%, F vol ≥ 5M, 4H aligned)*\n" + (table_md(dn_rows, ["SYM", "F Vol", "24H", "4H"]) if dn_rows else "_None_")
    return up_txt, dn_txt


def _engine_c_detect_pump_base(
    side: str,
    entry: float,
    atr_1h: float,
    ch24: float,
    ch4: float,
    fut_vol: float,
    c15: list,
    ema_support_15m: float,
    aggressive_screen: bool = False,
) -> dict:
    """Detect post-impulse 15m compression / range continuation.

    Idea:
    - a strong impulse already happened (pump/dump candle)
    - then price pauses in a narrow 15m base near the impulse highs/lows
    - support/resistance holds and price starts to break/reclaim the base again

    This is deliberately stricter than Engine B so it targets "pump then base then continue"
    instead of raw expansion candles.
    """
    out = {
        'ok': False,
        'reason': 'na',
        'side': str(side or '').upper(),
        'impulse_pct': 0.0,
        'base_width_pct': 999.0,
        'base_bars': 0,
        'support_level': 0.0,
        'resistance_level': 0.0,
        'breakout_ready': False,
    }
    try:
        side = str(side or '').upper().strip()
        if side not in ('BUY', 'SELL'):
            out['reason'] = 'bad_side'
            return out
        if entry <= 0 or atr_1h <= 0 or not c15 or len(c15) < 18:
            out['reason'] = 'missing_inputs'
            return out
        if abs(float(ch24 or 0.0)) < float(ENGINE_C_MIN_CH24):
            out['reason'] = 'ch24_too_small'
            return out
        if abs(float(ch4 or 0.0)) < float(ENGINE_C_MIN_ABS_CH4):
            out['reason'] = 'ch4_too_small'
            return out
        if float(fut_vol or 0.0) < float(ENGINE_C_MIN_FUT_VOL_USD):
            out['reason'] = 'fut_vol_too_small'
            return out

        bars = c15[-24:]
        opens = [float(x[1]) for x in bars]
        highs = [float(x[2]) for x in bars]
        lows = [float(x[3]) for x in bars]
        closes = [float(x[4]) for x in bars]
        vols = [float(x[5]) for x in bars]
        if len(closes) < 18:
            out['reason'] = 'window_too_small'
            return out

        ranges = [max(0.0, h - l) for h, l in zip(highs, lows)]
        prior = ranges[:-1]
        med_range = sorted(prior)[len(prior)//2] if prior else 0.0
        if med_range <= 0:
            med_range = max(entry * 0.002, float(atr_1h) * 0.18)
        vol_hist = vols[:-1]
        vol_med = sorted(vol_hist)[len(vol_hist)//2] if vol_hist else 0.0

        impulse_idx = None
        impulse_score = -1.0
        lookback = min(16, len(closes) - int(ENGINE_C_MIN_BASE_BARS) - 1)
        for idx in range(max(1, len(closes) - lookback - 1), len(closes) - int(ENGINE_C_MIN_BASE_BARS)):
            o = opens[idx]
            h = highs[idx]
            l = lows[idx]
            c = closes[idx]
            rng = max(1e-12, h - l)
            body_pct = abs(c - o) / max(o, 1e-12) * 100.0
            range_mult = rng / max(med_range, 1e-12)
            vol_mult = (vols[idx] / max(vol_med, 1e-12)) if vol_med > 0 else 1.0
            close_loc = (c - l) / rng if side == 'BUY' else (h - c) / rng
            directional_ok = (c > o) if side == 'BUY' else (c < o)
            if not directional_ok:
                continue
            need_impulse = float(ENGINE_C_MIN_IMPULSE_15M_PCT) * (0.88 if aggressive_screen else 1.0)
            need_vol = float(ENGINE_C_MIN_IMPULSE_VOL_MULT) * (0.92 if aggressive_screen else 1.0)
            if body_pct < need_impulse:
                continue
            if range_mult < 2.0:
                continue
            if close_loc < 0.60:
                continue
            if vol_mult < need_vol:
                continue
            score = body_pct + (range_mult * 1.2) + min(2.5, vol_mult)
            if score > impulse_score:
                impulse_score = score
                impulse_idx = idx

        if impulse_idx is None:
            out['reason'] = 'no_impulse_bar'
            return out

        base = bars[impulse_idx + 1:]
        if len(base) < int(ENGINE_C_MIN_BASE_BARS):
            out['reason'] = 'base_too_short'
            return out
        if len(base) > int(ENGINE_C_MAX_BASE_BARS):
            base = base[-int(ENGINE_C_MAX_BASE_BARS):]

        b_highs = [float(x[2]) for x in base]
        b_lows = [float(x[3]) for x in base]
        b_closes = [float(x[4]) for x in base]
        b_opens = [float(x[1]) for x in base]
        b_ranges = [max(1e-12, float(x[2]) - float(x[3])) for x in base]

        impulse_high = highs[impulse_idx]
        impulse_low = lows[impulse_idx]
        impulse_range = max(1e-12, impulse_high - impulse_low)
        impulse_close = closes[impulse_idx]
        last_close = b_closes[-1]
        base_high = max(b_highs)
        base_low = min(b_lows)
        base_width_pct = ((base_high - base_low) / max(last_close, 1e-12)) * 100.0
        out['impulse_pct'] = abs((impulse_close - opens[impulse_idx]) / max(opens[impulse_idx], 1e-12) * 100.0)
        out['base_width_pct'] = float(base_width_pct)
        out['base_bars'] = int(len(base))
        out['support_level'] = float(base_low)
        out['resistance_level'] = float(base_high)

        width_limit = float(ENGINE_C_MAX_BASE_WIDTH_PCT) * (1.18 if aggressive_screen else 1.0)
        if base_width_pct > width_limit:
            out['reason'] = 'base_too_wide'
            return out

        hold_portion = float(ENGINE_C_HOLD_PORTION)
        if side == 'BUY':
            hold_line = impulse_low + (impulse_range * hold_portion)
            if base_low < hold_line:
                out['reason'] = 'lost_impulse_support'
                return out
            if ema_support_15m > 0 and last_close < (ema_support_15m * 0.985):
                out['reason'] = 'below_ema_support'
                return out
            upper_half = sum(1 for c in b_closes if c >= (base_low + (base_high - base_low) * 0.50))
            if upper_half < max(2, len(base) // 2):
                out['reason'] = 'base_not_holding_high'
                return out
            breakout_ready = last_close >= (base_high * (1.0 - float(ENGINE_C_BREAKOUT_BUFFER_PCT) / 100.0))
            reclaim_ok = b_closes[-1] >= b_opens[-1]
            if not (breakout_ready and reclaim_ok):
                out['reason'] = 'not_ready_for_breakout'
                out['breakout_ready'] = bool(breakout_ready)
                return out
        else:
            hold_line = impulse_high - (impulse_range * hold_portion)
            if base_high > hold_line:
                out['reason'] = 'lost_impulse_resistance'
                return out
            if ema_support_15m > 0 and last_close > (ema_support_15m * 1.015):
                out['reason'] = 'above_ema_resistance'
                return out
            lower_half = sum(1 for c in b_closes if c <= (base_low + (base_high - base_low) * 0.50))
            if lower_half < max(2, len(base) // 2):
                out['reason'] = 'base_not_holding_low'
                return out
            breakout_ready = last_close <= (base_low * (1.0 + float(ENGINE_C_BREAKOUT_BUFFER_PCT) / 100.0))
            reclaim_ok = b_closes[-1] <= b_opens[-1]
            if not (breakout_ready and reclaim_ok):
                out['reason'] = 'not_ready_for_breakdown'
                out['breakout_ready'] = bool(breakout_ready)
                return out

        # Extra stability: base should actually compress after impulse.
        avg_base_range = sum(b_ranges) / max(1, len(b_ranges))
        if avg_base_range > (impulse_range * 0.62):
            out['reason'] = 'base_not_compressed'
            return out

        out['ok'] = True
        out['reason'] = 'ok'
        out['breakout_ready'] = True
        return out
    except Exception as e:
        out['reason'] = f'exception:{type(e).__name__}'
        return out

# =========================================================
# make_setup
# =========================================================
def make_setup(
    base: str,
    mv: MarketVol,
    strict_15m: bool = True,
    session_name: str = "LON",
    allow_no_pullback: bool = True,     # /screen True, Email False (except HOT bypass)
    hot_vol_usd: float = HOT_VOL_USD,   # 50M
    trigger_loosen_mult: float = 1.0,
    waiting_near_pct: float = SCREEN_WAITING_NEAR_PCT,
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> Optional[Setup]:

    fut_vol = usd_notional(mv)
    if fut_vol <= 0:
        _rej("no_futures_volume", base, mv)
        return None

    entry = float(mv.last or 0.0)
    if entry <= 0:
        _rej("bad_entry", base, mv)
        return None

    ch24 = float(mv.percentage or 0.0)

    _note_status("evaluated", base, mv)


    notes = []  # collect internal notes for pullback policy / diagnostics
    try:

        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)

    except Exception:

        _rej("ohlcv_missing_or_insufficient", base, mv)

        return None
    # Use true 4H change from 4H candles (more stable than 1H*4 approximation)
    try:
        ch4_exact = 0.0
        try:
            c4h = fetch_ohlcv(mv.symbol, "4h", limit=6)
            if c4h and len(c4h) >= 2:
                c_last_4h = float(c4h[-1][4])
                c_prev_4h = float(c4h[-2][4])
                ch4_exact = ((c_last_4h - c_prev_4h) / c_prev_4h) * 100.0 if c_prev_4h else 0.0
        except Exception:
            ch4_exact = 0.0

        ch4_used = ch4_exact if abs(ch4_exact) > 0.0001 else ch4

        if (ch1 == 0.0 and ch4 == 0.0 and ch15 == 0.0 and atr_1h == 0.0) or (not c15) or (ema_support_15m == 0.0):
            _rej("ohlcv_missing_or_insufficient", base, mv, "metrics/ema missing")
            return None

        # Scan profile tuning
        prof = str(scan_profile or DEFAULT_SCAN_PROFILE).strip().lower()
        if prof not in SCAN_PROFILES:
            prof = DEFAULT_SCAN_PROFILE
        aggressive_screen = (prof == "aggressive" and (not strict_15m))

        # --------- SESSION-DYNAMIC 1H TRIGGER ----------
        atr_pct_now = (atr_1h / entry) * 100.0 if (atr_1h and entry) else 0.0
        trig_min_raw = trigger_1h_abs_min_atr_adaptive(atr_pct_now, session_name)

        floor_min = 0.02 if aggressive_screen else 0.04  # further loosened: allow setups in quiet 1H candles
        trig_min = max(float(floor_min), float(trig_min_raw) * float(trigger_loosen_mult))

        if abs(ch1) < trig_min:
            # Waiting for Trigger (near-miss) — store ONLY side + a color dot (no numbers)
            if trig_min > 0:
                ratio = abs(ch1) / trig_min  # internal only
                if ratio >= float(waiting_near_pct):
                    # color indicates "how close" WITHOUT revealing thresholds
                    if ratio >= 0.92:
                        dot = "🟢"
                    elif ratio >= 0.82:
                        dot = "🟡"
                    else:
                        dot = "🟠"

                    side_guess = ("BUY" if ch4 >= 0 else "SELL") if abs(ch4) >= 0.25 else ("BUY" if ch1 > 0 else "SELL")
                    _WAITING_TRIGGER[str(base)] = {"side": side_guess, "dot": dot}

            # Balanced breakout override: even if 1H change is small, allow true breakouts
            # Additional overrides: allow setups during quiet 1H candles if 4H/24H move is strong and 15m confirms.
            override_4h = (abs(float(ch4_used or 0.0)) >= max(0.75, float(trig_min) * 1.45)) and (abs(float(ch15 or 0.0)) >= 0.08)
            override_24h = (abs(float(ch24 or 0.0)) >= 8.0) and (abs(float(ch15 or 0.0)) >= 0.06)
            # Extra override: if 24H is very strong AND 4H aligns, don't require 15m confirmation (quiet consolidation after a big move)
            override_24h_strong = (abs(float(ch24 or 0.0)) >= 15.0) and (abs(float(ch4_used or 0.0)) >= 0.50) and (float(fut_vol or 0.0) >= 5_000_000.0)
            breakout_override = False
            # Trend override: if 4H regime move is meaningful, allow even if this 1H is quiet.
            try:
                if abs(float(ch4_used or 0.0)) >= max(0.60, float(trig_min) * 2.5) and float(fut_vol or 0.0) >= 5_000_000.0:
                    breakout_override = True
            except Exception:
                pass
            try:
                if c1 and len(c1) >= 25 and abs(ch24) >= 5.0:
                    highs_1h = [float(x[2]) for x in c1]
                    lows_1h  = [float(x[3]) for x in c1]
                    closes_1h = [float(x[4]) for x in c1]
                    vols_1h  = [float(x[5]) for x in c1]
                    last_close = float(closes_1h[-1])
                    last_high  = float(highs_1h[-1])
                    last_low   = float(lows_1h[-1])
                    hh20 = max(highs_1h[-21:-1])
                    ll20 = min(lows_1h[-21:-1])
                    vnow = float(vols_1h[-1])
                    vavg = (sum(vols_1h[-21:-1]) / 20.0) if vols_1h[-21:-1] else 0.0

                    vol_mult = 1.04  # balanced default
                    if (ch24 >= 6.0) and (last_high > hh20 or last_close > hh20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        breakout_override = True
                    if (ch24 <= -6.0) and (last_low < ll20 or last_close < ll20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        breakout_override = True
            except Exception:
                breakout_override = False

            # Soft override: if we are close to the trigger and the higher timeframe move supports direction,
            # allow a lower-confidence setup instead of rejecting everything on a quiet 1H candle.
            try:
                ratio = (abs(float(ch1)) / float(trig_min)) if float(trig_min) > 0 else 0.0
            except Exception:
                ratio = 0.0
            soft_override = (ratio >= 0.70) and (float(fut_vol or 0.0) >= 5_000_000.0) and (
                abs(float(ch4_used or 0.0)) >= 0.50 or abs(float(ch24 or 0.0)) >= 12.0
            )

            if not (breakout_override or override_4h or override_24h or override_24h_strong or soft_override):
                _rej("ch1_below_trigger", base, mv, f"ch1={ch1:+.2f}% trig={trig_min:.2f}% ch4={ch4:+.2f}% ch24={ch24:+.2f}% ch15={ch15:+.2f}%")
                return None


        # ✅ IMPORTANT: this must be OUTSIDE the if block (no extra indent)
        side = ("BUY" if ch4 >= 0 else "SELL") if abs(ch4) >= 0.40 else ("BUY" if ch1 > 0 else "SELL")  # trend-side gating: prefer 4H regime over 1H noise

        # 4H alignment
        # If 4H is basically flat, don't block (leaders often show ch4 ~ 0 while 24H is huge).
        if abs(ch4) >= float(ALIGN_4H_NEUTRAL_ZONE):
            if side == "BUY" and ch4 < ALIGN_4H_MIN:
                _rej("4h_not_aligned_for_long", base, mv, f"side=BUY ch4={ch4:+.2f}%")
                return None
            if side == "SELL" and ch4 > -ALIGN_4H_MIN:
                _rej("4h_not_aligned_for_short", base, mv, f"side=SELL ch4={ch4:+.2f}%")
                return None

        # ✅ HARD regime gate: don't fight the 4H direction (unless "strong reversal exception")
        if TF_ALIGN_ENABLED and abs(ch4) >= float(ALIGN_4H_NEUTRAL_ZONE):
            if side == "BUY" and ch4 < 0:
                if not strong_reversal_exception_ok(side, ch24, ch4, ch1):
                    _rej("4h_bear_regime_blocks_long", base, mv, f"ch4={ch4:+.2f}%")
                    return None
            if side == "SELL" and ch4 > 0:
                if not strong_reversal_exception_ok(side, ch24, ch4, ch1):
                    _rej("4h_bull_regime_blocks_short", base, mv, f"ch4={ch4:+.2f}%")
                    return None


        # ✅ Approach A (ASIA): require basic 1H+4H alignment with the signal direction
        # (NY/LON unchanged to keep flow)
        try:
            if str(session_name).upper() == "ASIA":
                min1, min4 = tf_align_mins_for_session(session_name)
                if side == "BUY":
                    if not (ch1 >= min1 and ch4 >= min4):
                        _rej("asia_tf_align_fail_long", base, mv, f"ch1={ch1:+.2f}% ch4={ch4:+.2f}% need>=({min1},{min4})")
                        return None
                else:
                    if not (ch1 <= -min1 and ch4 <= -min4):
                        _rej("asia_tf_align_fail_short", base, mv, f"ch1={ch1:+.2f}% ch4={ch4:+.2f}% need<=(-{min1},-{min4})")
                        return None
        except Exception:
            pass

        # =========================================================
        # ✅ PULLBACK EMA (7/14/21) selection (15m)
        # =========================================================
        closes_15 = [float(x[4]) for x in c15]
        pb_ema_val, pb_ema_p, pb_dist_pct = best_pullback_ema_15m(closes_15, c15, entry, side, session_name, atr_1h)

        # ✅ No HOT bypass: pullback is ALWAYS required for high-quality continuation entries
        pullback_bypass_hot = False

        pb_ok = False
        pb_thr_pct = 0.0
        pb_dist_pct2 = 999.0

        if pb_ema_val > 0:
            pb_ok, pb_dist_pct2, pb_thr_pct, _ = ema_support_proximity_ok(entry, pb_ema_val, atr_1h, session_name)

        pullback_ready = bool(pb_ok)

        leader_base_override = _leader_base_override_ok(side, ch24, ch4_used, ch15, fut_vol, pullback_ready, pb_dist_pct2, session_name)

        # Aggressive /screen: allow "near-EMA" pullback (slightly looser proximity)
        if (not pullback_ready) and aggressive_screen and (pb_ema_val > 0) and (pb_thr_pct > 0):
            try:
                if float(pb_dist_pct2) <= float(pb_thr_pct) * 1.35:
                    pullback_ready = True
            except Exception:
                pass

        # 15m rejection candle requirement (skip in Aggressive /screen)
        require_rejection = bool(REQUIRE_15M_EMA_REJECTION and (not aggressive_screen))

        # ✅ Strict continuation entry: must show EMA interaction + strong 15m rejection/reclaim
        if pullback_ready and require_rejection:
            if (not c15) or (pb_ema_val <= 0):
                _rej("no_ema_touch_reclaim_recent", base, mv,
                     f"ema{pb_ema_p} pb_dist={pb_dist_pct2:.2f}% thr={pb_thr_pct:.2f}%")
                return None

            if not ema_rejection_candle_ok_15m(c15, pb_ema_val, side):
                _rej("no_strong_rejection_candle_15m", base, mv, f"ema{pb_ema_p} pb_dist={pb_dist_pct2:.2f}%")
                return None

        # =========================================================
        # ENGINE A (Mean-Reversion) vs ENGINE B (Momentum)
        # =========================================================
        engine_a_ok = bool(ENGINE_A_PULLBACK_ENABLED and pullback_ready)

        engine_b_ok = False
        engine_c_ok = False
        engine_c_info = {"ok": False, "reason": "disabled"}

        if ENGINE_B_MOMENTUM_ENABLED:
            # Aggressive /screen: slightly looser momentum requirements
            mom_min_ch1 = float(MOMENTUM_MIN_CH1) * (0.75 if aggressive_screen else 1.0)
            mom_min_24h = float(MOMENTUM_MIN_24H) * (0.75 if aggressive_screen else 1.0)
            mom_body_mult = float(MOMENTUM_ATR_BODY_MULT) * (0.85 if aggressive_screen else 1.0)
            mom_max_ema_dist = float(MOMENTUM_MAX_ADAPTIVE_EMA_DIST) * ((1.60 if (not strict_15m) else 1.0)) * (1.30 if aggressive_screen else 1.0)

            # ------------------------------------------------------------------
            # B1) Momentum continuation (existing)
            # ------------------------------------------------------------------
            if abs(ch1) >= mom_min_ch1 and abs(ch24) >= mom_min_24h:
                if fut_vol >= (MOVER_VOL_USD_MIN * MOMENTUM_VOL_MULT):
                    body_pct = abs(ch1)
                    if atr_pct_now > 0 and body_pct >= (mom_body_mult * atr_pct_now):
                        _, dist_pct, _, _ = ema_support_proximity_ok(entry, ema_support_15m, atr_1h, session_name)
                        if dist_pct <= mom_max_ema_dist:
                            engine_b_ok = True

            # ------------------------------------------------------------------
            # B2) Balanced Breakout continuation (NEW)
            # Purpose: avoid "leaders full, setups empty" during expansion phases.
            # Uses the already-fetched 1H candles (c1) to avoid extra API calls / rate limits.
            # ------------------------------------------------------------------
            try:
                ch24_thr = 4.0 if aggressive_screen else 5.0
                vol_mult = 1.05 if aggressive_screen else 1.08

                # Use 4H/side gating already computed as the trend regime.
                uptrend = (ch4_used >= 0)
                downtrend = (ch4 < 0)

                if abs(ch24) >= ch24_thr and fut_vol >= max(5_000_000.0, float(MOVER_VOL_USD_MIN) * 0.70) and c1 and len(c1) >= 25:
                    highs_1h = [float(x[2]) for x in c1]
                    lows_1h  = [float(x[3]) for x in c1]
                    closes_1h = [float(x[4]) for x in c1]
                    vols_1h  = [float(x[5]) for x in c1]

                    last_close = float(closes_1h[-1])
                    last_high = float(highs_1h[-1])
                    last_low  = float(lows_1h[-1])
                    vnow = float(vols_1h[-1])
                    vavg = (sum(vols_1h[-21:-1]) / 20.0) if vols_1h[-21:-1] else 0.0

                    # Prior 20-candle extremes (exclude the current candle)
                    hh20 = max(highs_1h[-21:-1])
                    ll20 = min(lows_1h[-21:-1])

                    # Breakout BUY
                    if uptrend and ch24 >= ch24_thr and (last_high > hh20 or last_close > hh20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        engine_b_ok = True
                        mv._pf_breakout_hint = "BUY"

                    # Breakdown SELL
                    if downtrend and ch24 <= -ch24_thr and (last_low < ll20 or last_close < ll20) and ((vavg > 0 and vnow >= vavg * vol_mult) or (vavg <= 0 and vnow > 0)):
                        engine_b_ok = True
                        mv._pf_breakout_hint = "SELL"
            except Exception:
                pass
    
        # If breakout engine fired, force side to match the breakout direction (prevents green BUY / red mismatch)
        try:
            hint = getattr(mv, "_pf_breakout_hint", None)
            if engine_b_ok and hint in ("BUY", "SELL"):
                side = hint
        except Exception:
            pass

        # If breakout engine fired, force side to match the breakout direction (prevents green BUY / red mismatch)
        try:
            hint = getattr(mv, "_pf_breakout_hint", None)
            if engine_b_ok and hint in ("BUY", "SELL"):
                side = hint
        except Exception:
            pass

        # ---------------------------------------------------------
        # ENGINE C (Pump-base / range continuation after impulse)
        # ---------------------------------------------------------
        if ENGINE_C_PUMP_BASE_ENABLED:
            try:
                engine_c_info = _engine_c_detect_pump_base(
                    side=side,
                    entry=entry,
                    atr_1h=atr_1h,
                    ch24=ch24,
                    ch4=ch4_used,
                    fut_vol=fut_vol,
                    c15=c15,
                    ema_support_15m=ema_support_15m,
                    aggressive_screen=aggressive_screen,
                )
                engine_c_ok = bool(engine_c_info.get('ok'))
            except Exception:
                engine_c_ok = False

        if not engine_a_ok and not engine_b_ok and not engine_c_ok:
            _rej("no_engine_passed", base, mv, f"ch1={ch1:.2f} ch24={ch24:.2f} pb_dist={pb_dist_pct:.2f} ec={engine_c_info.get('reason','na')}")
            return None

        # ---------------------------------------------------------
        # Pullback policy (optional for Engine B / Engine C on /screen)
        # ---------------------------------------------------------
        engine = "A" if engine_a_ok else ("C" if engine_c_ok else "B")
        require_pullback = (not bool(allow_no_pullback))

        # Compute confidence BEFORE applying optional pullback penalty
        conf = compute_confidence(side, ch24, ch4, ch1, ch15, fut_vol)

        # ---------------------------------------------------------
        # ✅ PulseFutures PRO quality overlay (safe integration)
        # Uses the appended advanced engines as a confirmation layer
        # without rewriting the whole live signal pipeline.
        # ---------------------------------------------------------
        try:
            # SMC structure (HH/HL/LH/LL + BOS/CHOCH) — higher-quality trend filter
            smc = pf_market_structure_smc(c1[-220:] if c1 else c1, fractal=2, lookback=220)
            structure = str(smc.get("bias", "UNKNOWN")).upper()
            bos = str(smc.get("bos", "NONE")).upper()
            choch = str(smc.get("choch", "NONE")).upper()

            trend = pf_mtf_alignment(mv.symbol, fetch_ohlcv)  # 4H + 1H only (5m too noisy for hard gating)
            regime = pf_market_regime(c1[-60:] if c1 else c1)

            sweep_info = pf_liquidity_sweep_v2(c15[-90:] if c15 else c15, lookback_swings=90, fractal=2)
            sweep = str(sweep_info.get("event", "NONE")).upper()

            momentum = pf_orderflow_momentum(c15[-20:] if c15 else c15)

            smf = pf_smart_money_flow(c15[-90:] if c15 else c15, vol_lookback=30)
            smf_event = str(smf.get("event", "NONE")).upper()
            smf_score = int(smf.get("score", 0) or 0)


            want_trend = "BULLISH" if side == "BUY" else "BEARISH"
            # Do NOT hard-block merely because SMC structure is not the exact wanted bias.
            # In live markets many valid continuation or base-break setups print as RANGE/UNKNOWN
            # for stretches, and the stricter hard reject was starving setup generation.
            # We only hard-block when structure is explicitly opposite *and* the broader trend
            # also disagrees a few lines below. Otherwise keep the setup and let confidence /
            # quality scoring decide.
            if structure not in (want_trend, "RANGE", "UNKNOWN", "NEUTRAL", "NONE", ""):
                notes.append(f"smc_structure_soft_mismatch={structure}")
                conf = max(0.0, float(conf) - 5.0)

            # CHOCH indicates potential reversal against the prevailing bias — avoid entries against it.
            if side == "BUY" and choch == "CHOCH_DOWN":
                _rej("smc_choch_against_long", base, mv, f"choch={choch} bos={bos} structure={structure} smf={smf_event}")
                return None
            if side == "SELL" and choch == "CHOCH_UP":
                _rej("smc_choch_against_short", base, mv, f"choch={choch} bos={bos} structure={structure} smf={smf_event}")
                return None
            opposite_trend = "BEARISH" if side == "BUY" else "BULLISH"
            sweep_ok = (side == "BUY" and sweep == "BUY_SWEEP") or (side == "SELL" and sweep == "SELL_SWEEP")
            momentum_ok = (side == "BUY" and momentum == "BULLISH") or (side == "SELL" and momentum == "BEARISH")
            momentum_bad = (side == "BUY" and momentum == "BEARISH") or (side == "SELL" and momentum == "BULLISH")

            # Hard block only when the advanced engines strongly disagree.
            if structure == opposite_trend and trend == opposite_trend:
                _rej("pro_structure_trend_conflict", base, mv, f"side={side} structure={structure} trend={trend}")
                return None

            # Momentum engine works best in trend regimes, not ranging.
            if engine == "B" and strict_15m and regime == "RANGING" and (not sweep_ok):
                _rej("pro_ranging_regime_blocks_momentum_soft", base, mv, f"side={side} regime={regime}")
                conf -= 3
                notes.append("ranging_penalty")

            # Confidence nudges: reward alignment, penalize conflict.
            if structure == want_trend:
                conf += 3
            elif structure == "RANGE":
                conf -= 1

            if trend == want_trend:
                conf += 3
            elif trend == "MIXED":
                conf -= 1

            if sweep_ok:
                conf += 4
            if momentum_ok:
                conf += 3
            if momentum_bad:
                conf -= 4

            # BOS adds confidence for continuation entries
            if side == "BUY" and bos == "BOS_UP":
                conf += 2
            if side == "SELL" and bos == "BOS_DOWN":
                conf += 2

            # Smart Money Flow detection (institutional activity / liquidation / ignition)
            smf_buy = smf_event in ("BUY_IGNITION", "LIQUIDATION_BUY")
            smf_sell = smf_event in ("SELL_IGNITION", "LIQUIDATION_SELL")
            if side == "BUY" and smf_buy:
                conf += 2 + min(2, max(0, smf_score - 2))
            elif side == "SELL" and smf_sell:
                conf += 2 + min(2, max(0, smf_score - 2))
            elif (side == "BUY" and smf_sell) or (side == "SELL" and smf_buy):
                # Strong opposite smart-money signature: avoid
                _rej("smart_money_opposes_side_soft", base, mv, f"side={side} smf={smf_event} score={smf_score} structure={structure} trend={trend}")
                conf -= 6
                notes.append("smf_opposes_soft")
            # Require at least 2 of 3 core confirmations for aggressive momentum setups.
            if engine == "B":
                core_hits = 0
                if trend == want_trend:
                    core_hits += 1
                if structure == want_trend:
                    core_hits += 1
                if sweep_ok or momentum_ok:
                    core_hits += 1
                if core_hits < 2:
                    _rej("pro_quality_gate_failed_soft", base, mv, f"side={side} hits={core_hits} trend={trend} structure={structure} sweep={sweep} momentum={momentum}")
                    conf -= 5
                    notes.append(f"pro_hits={core_hits}")

            if engine == "C":
                if trend == want_trend:
                    conf += 2
                if structure == want_trend:
                    conf += 2
                if bos in ("BOS_UP", "BOS_DOWN"):
                    conf += 1
                if str(regime or "").upper() == "RANGING":
                    conf += 2
                c_base_width = float(engine_c_info.get('base_width_pct', 999.0) or 999.0)
                if c_base_width <= 4.0:
                    conf += 3
                elif c_base_width <= 6.5:
                    conf += 1
                else:
                    conf -= 2

            conf = int(clamp(float(conf), 0.0, 100.0))
        except Exception:
            pass

        # Email/autotrade quality path can require a real 15m pullback for both engines.
        # This was previously bypassed for Engine B, which let too many NY momentum setups through.
        pullback_ok_local = bool(pullback_ready) if require_pullback else True

        keep, conf2 = apply_pullback_policy(
            require_pullback=require_pullback,
            pullback_ok=pullback_ok_local,
            pullback_price=(pb_ema_val if pb_ema_val > 0 else None),
            confidence=float(conf),
            notes=notes,
        )

        conf = conf2

        if not keep:
            _rej("pullback_required_not_met", base, mv, "require_pullback=1")
            return None

        if engine == "A" and abs(float(ch1)) >= float(SHARP_1H_MOVE_PCT):
            # EMA touch/reaction on 15m is OPTIONAL: do not hard-reject if it's missing.
            # (Ramin requested: no hard requirement to touch 15m EMA.)
            if not ema_support_reaction_ok_15m(c15, pb_ema_val, side, session_name):
                notes.append("🟡 No strong 15m EMA reaction detected (optional check).")
                conf = max(0.0, float(conf) - 4.0)

        thr = clamp(max(12.0, 2.5 * ((atr_1h / entry) * 100.0 if (atr_1h and entry) else 0.0)), 12.0, 22.0)
        if side == "BUY" and ch24 <= -thr:
            _rej("24h_contradiction_for_long", base, mv, f"ch24={ch24:+.1f}% <= -{thr:.1f}%")
            return None
        if side == "SELL" and ch24 >= +thr:
            _rej("24h_contradiction_for_short", base, mv, f"ch24={ch24:+.1f}% >= +{thr:.1f}%")
            return None

        is_confirm_15m = abs(ch15) >= CONFIRM_15M_ABS_MIN
        is_early_allowed = (abs(ch1) >= EARLY_1H_ABS_MIN)

        if strict_15m:
            if (not is_confirm_15m) and (not is_early_allowed):
                _rej("15m_weak_and_not_early", base, mv, f"ch15={ch15:+.2f}% ch1={ch1:+.2f}%")
                return None

        if strict_15m and (not is_confirm_15m):
            conf = max(0, int(conf) - int(EARLY_CONF_PENALTY))


        # ---------------------------------------------------------
        # ✅ Global quality gate: session-aware confidence floor
        # ---------------------------------------------------------
        try:
            sess_min = int(_session_generation_conf_floor(session_name))
            if str(session_name or '').upper() == 'NY' and require_pullback:
                sess_min = max(int(sess_min), int(_session_generation_conf_floor('NY')) + 2)
            if int(conf) < int(sess_min):
                _rej("below_min_confidence", base, mv, f"conf={int(conf)} min={int(sess_min)} sess={session_name}")
                return None
        except Exception:

            pass

        tp_cap_pct = tp_cap_pct_for_coin(fut_vol, ch24)

        rr_bonus = ENGINE_B_RR_BONUS if engine_b_ok else 0.0
        tp_cap_bonus = ENGINE_B_TP_CAP_BONUS_PCT if engine_b_ok else 0.0
        if engine == "C":
            rr_bonus = float(rr_bonus) + float(ENGINE_C_RR_BONUS)
            tp_cap_bonus = float(tp_cap_bonus) + float(ENGINE_C_TP_CAP_BONUS_PCT)

        # ✅ Approach A: volatility-aware TP cap tightening (higher hit-rate on choppy/high-ATR coins)
        try:
            atr_pct = (float(atr_1h) / float(entry)) * 100.0 if float(entry) > 0 else 0.0
            if atr_pct >= 6.0:
                tp_cap_pct = min(float(tp_cap_pct), 9.0)
            elif atr_pct >= 4.5:
                tp_cap_pct = min(float(tp_cap_pct), 10.5)
        except Exception:
            pass

        atr_for_sl = float(atr_1h)
        if leader_base_override:
            try:
                atr_for_sl = min(float(atr_for_sl), float(entry) * (float(_leader_base_sl_cap_pct(session_name)) / 100.0))
                notes.append("leader_base_override")
            except Exception:
                atr_for_sl = float(atr_1h)

        sl, alt_target_b_single, R = compute_sl_tp(
            entry, side, atr_for_sl, conf, tp_cap_pct,
            rr_bonus=rr_bonus, tp_cap_bonus_pct=tp_cap_bonus
        )
        if sl <= 0 or alt_target_b_single <= 0 or R <= 0:
            _rej("bad_sl_tp_or_atr", base, mv, f"atr={atr_1h:.6g} entry={entry:.6g}")
            return None

        tp_target = float(alt_target_b_single)

        # ---------------------------------------------------------
        # ✅ Session-aware final-target RR floor (single TP model)
        # ---------------------------------------------------------
        try:
            rr_final = rr_to_tp(entry, sl, tp_target)
            sess_rr_min = float(_session_generation_rr_floor(session_name))
            if str(session_name or '').upper() == 'NY' and require_pullback:
                sess_rr_min = max(float(sess_rr_min), float(_session_generation_rr_floor('NY')) + 0.05)
            if float(rr_final) < float(sess_rr_min):
                _rej("below_min_rr_tp_session", base, mv, f"rr_final={rr_final:.2f} min={sess_rr_min:.2f} sess={session_name}")
                return None
        except Exception:
            pass

        sid = next_setup_id()
        hot = is_hot_coin(fut_vol, ch24)

        # ✅ trailing only for the setups that need it (Momentum + Hot)
        trailing_alt_target_b = False

        s = Setup(
            setup_id=sid,
            symbol=base,
            market_symbol=mv.symbol,
            side=side,
            conf=int(conf),
            entry=entry,
            sl=sl,
            tp=float(tp_target),
            alt_target_a=0.0,
            alt_target_b=0.0,
            fut_vol_usd=fut_vol,
            ch24=ch24,
            ch4=ch4,
            ch1=ch1,
            ch15=ch15,
            ema_support_period=int(ema_period),
            ema_support_dist_pct=float(abs(entry - float(ema_support_15m)) / entry * 100.0 if entry > 0 else 999.0),
            pullback_ema_period=int(pb_ema_p),
            pullback_ema_dist_pct=float(pb_dist_pct2),
            pullback_ready=bool(pullback_ready),
            pullback_bypass_hot=bool(pullback_bypass_hot),
            leader_base_override=bool(leader_base_override),
            engine=str(engine),
            is_trailing_alt_target_b=False,
            created_ts=time.time(),
        )
        try:
            # Attach lightweight diagnostics for scoring/backtests (safe even if unused elsewhere)
            setattr(s, 'atr_pct', float(atr_pct_now or 0.0))
            setattr(s, 'regime', str(regime or 'UNKNOWN'))
            setattr(s, 'trend', str(trend or 'UNKNOWN'))
            setattr(s, 'structure', str(structure or 'UNKNOWN'))
            setattr(s, 'bos', str(bos or 'NONE'))
            setattr(s, 'choch', str(choch or 'NONE'))
            setattr(s, 'sweep', str(sweep or 'NONE'))
            setattr(s, 'smf_event', str(smf_event or 'NONE'))
            setattr(s, 'smf_score', int(smf_score or 0))
            setattr(s, 'engine', str(engine or ''))
            setattr(s, 'raw_conf', int(conf or 0))
            try:
                setattr(s, 'engine_c_reason', str(engine_c_info.get('reason', '')))
                setattr(s, 'engine_c_base_width_pct', float(engine_c_info.get('base_width_pct', 0.0) or 0.0))
                setattr(s, 'engine_c_base_bars', int(engine_c_info.get('base_bars', 0) or 0))
                setattr(s, 'engine_c_support_level', float(engine_c_info.get('support_level', 0.0) or 0.0))
                setattr(s, 'engine_c_resistance_level', float(engine_c_info.get('resistance_level', 0.0) or 0.0))
            except Exception:
                pass
            # Single-TP model: keep only one authoritative target on tp.
            try:
                t = float(_setup_target_tp(s, 0.0) or 0.0)
                setattr(s, 'tp', t)
                setattr(s, 'alt_target_a', 0.0)
                setattr(s, 'alt_target_b', 0.0)
            except Exception:
                pass
            try:
                public_conf, quality_score, quality_components = _recalibrate_public_confidence(s, session_name=session_name)
                setattr(s, 'quality_score', float(quality_score or 0.0))
                setattr(s, 'quality_components', quality_components or {})
                setattr(s, 'conf', int(public_conf or 0))
            except Exception:
                pass
        except Exception:
            pass
        try:
            s = _research_finalize_setup(s, session_name=session_name)
        except Exception:
            pass
        return s
    except Exception as e:
        try:
            _rej("exception_in_make_setup", base, mv, f"{type(e).__name__}: {e}")
        except Exception:
            pass
        return None




def make_breakout_setup(
    base: str,
    mv: MarketVol,
    session_name: str = "LON",
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> Optional[Setup]:
    """
    Engine B: Momentum Breakout/Breakdown setups.
    Uses already-fetched 1H candles from metrics_from_candles_1h_15m().
    """
    fut_vol = usd_notional(mv)
    if fut_vol <= 0:
        _rej("no_futures_volume", base, mv)
        return None

    entry = float(mv.last or 0.0)
    if entry <= 0:
        _rej("bad_entry", base, mv)
        return None

    ch24 = float(mv.percentage or 0.0)

    try:
        ch1, ch4, ch15, atr_1h, ema_support_15m, ema_period, c15, c1 = metrics_from_candles_1h_15m(mv.symbol)
    except Exception:
        _rej("ohlcv_missing_or_insufficient", base, mv)
        return None

    # Align naming with make_setup()
    ch4_used = float(ch4 or 0.0)

    if not c1 or len(c1) < 25 or atr_1h <= 0:
        _rej("no_candles_breakout", base, mv)
        return None

    # Prefer trend regime from 4H
    trend_up = ch4_used > 0
    trend_dn = ch4_used < 0

    highs = [float(x[2]) for x in c1 if x and len(x) >= 6][-25:]
    lows  = [float(x[3]) for x in c1 if x and len(x) >= 6][-25:]
    closes= [float(x[4]) for x in c1 if x and len(x) >= 6][-25:]
    vols  = [float(x[5]) for x in c1 if x and len(x) >= 6][-25:]

    if len(highs) < 22 or len(vols) < 22:
        _rej("insufficient_1h_window", base, mv)
        return None

    # prior window excludes the last candle to avoid self-referencing
    prior_high20 = max(highs[-21:-1])
    prior_low20  = min(lows[-21:-1])

    last_high = highs[-1]
    last_low  = lows[-1]
    last_close = closes[-1]

    vol_avg20 = sum(vols[-21:-1]) / 20.0
    vol_now = vols[-1]
    vol_ok = (vol_now > 0) and ((vol_avg20 <= 0) or (vol_now >= vol_avg20 * 1.00))  # looser

    # Balanced thresholds
    ch24_buy_min = 6.0
    ch24_sell_max = -6.0

    # Breakout/Breakdown by wick OR close
    is_breakout = (last_high > prior_high20) or (last_close > prior_high20)
    is_breakdown = (last_low < prior_low20) or (last_close < prior_low20)

    # If 4H is strongly up/down, allow direction to follow regime
    if trend_up and is_breakout and vol_ok and ch24 >= ch24_buy_min:
        side = "BUY"
    elif trend_dn and is_breakdown and vol_ok and ch24 <= ch24_sell_max:
        side = "SELL"
    else:
        # As a fallback, allow if 4H is neutral but 24H is strong
        if is_breakout and vol_ok and ch24 >= max(10.0, ch24_buy_min) and (ch4 >= 0):
            side = "BUY"
        elif is_breakdown and vol_ok and ch24 <= min(-10.0, ch24_sell_max) and (ch4_used <= 0):
            side = "SELL"
        else:
            # Balanced fallback: strong momentum continuation (not a fresh HH/LL break)
            if vol_ok:
                if (ch4_used >= 4.0 and ch24 >= 12.0):
                    side = "BUY"
                elif (ch4_used <= -4.0 and ch24 <= -12.0):
                    side = "SELL"
                else:
                    _rej("no_breakout_trigger", base, mv)
                    return None
            else:
                _rej("no_breakout_trigger", base, mv)
                return None


    # SL/TP using ATR (simple + robust)
    sl_atr = 1.35
    rr_target = 2.0  # TP RR target for momentum
    if side == "BUY":
        sl = entry - (atr_1h * sl_atr)
        tp_target = entry + (entry - sl) * rr_target
    else:
        sl = entry + (atr_1h * sl_atr)
        tp_target = entry - (sl - entry) * rr_target

    if sl <= 0 or tp_target <= 0:
        _rej("bad_sl_tp", base, mv)
        return None

    # Confidence scoring (balanced)
    conf = 80
    if abs(ch4_used) >= 5:
        conf += 2
    if abs(ch24) >= 20:
        conf += 2
    if vol_avg20 > 0 and vol_now >= vol_avg20 * 1.25:
        conf += 2
    conf = int(min(conf, 90))

    setup_id = make_setup_id(base, side)
    s = Setup(
        setup_id=setup_id,
        symbol=base,
        market_symbol=mv.symbol,
        side=side,
        conf=conf,
        entry=float(entry),
        sl=float(sl),
        tp=float(tp_target),
        alt_target_a=0.0,
        alt_target_b=0.0,
        fut_vol_usd=float(fut_vol),
        ch24=float(ch24),
        ch4=float(ch4_used),
        ch1=float(ch1),
        ch15=float(ch15),
        ema_support_period=int(ema_period or 0),
        ema_support_dist_pct=float(0.0),
        pullback_ema_period=int(0),
        pullback_ema_dist_pct=float(0.0),
        pullback_ready=False,
        pullback_bypass_hot=False,
        leader_base_override=False,
        engine="B",
        is_trailing_alt_target_b=False,
        created_ts=time.time(),
    )
    setattr(s, 'atr_pct', float((float(atr_1h) / float(entry) * 100.0) if float(entry) > 0 and float(atr_1h) > 0 else 0.0))
    setattr(s, 'regime', 'EXPANSION' if abs(float(ch1 or 0.0)) >= 1.0 else ('TRENDING' if abs(float(ch4_used or 0.0)) >= 1.0 else 'BALANCE'))
    setattr(s, 'trend', 'BULLISH' if side == 'BUY' else 'BEARISH')
    setattr(s, 'structure', getattr(s, 'trend'))
    try:
        score, _ = compute_setup_quality_score(s, session_name=session_name)
        setattr(s, 'quality_score', float(score))
    except Exception:
        pass
    return _research_finalize_setup(s, session_name=session_name)


def pick_setups(
    best_fut: Dict[str, MarketVol],
    n: int,
    strict_15m: bool = True,
    session_name: str = "LON",
    universe_n: int = 35,
    trigger_loosen_mult: float = 1.0,
    waiting_near_pct: float = SCREEN_WAITING_NEAR_PCT,
    allow_no_pullback: bool = False,   # /screen True, email False (except HOT bypass inside make_setup)
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> List[Setup]:
    global _REJECT_STATS, _REJECT_SAMPLES, _REJECT_BY_SYMBOL, _WAITING_TRIGGER
    _REJECT_STATS = Counter()
    _REJECT_SAMPLES = {}
    _REJECT_BY_SYMBOL = {}
    # _WAITING_TRIGGER is cleared once per scan inside build_priority_pool().
    # Do not reset it here, otherwise later passes erase earlier near-miss symbols.

    universe_n = int(max(10, universe_n))
    universe = sorted(best_fut.items(), key=lambda kv: usd_notional(kv[1]), reverse=True)[:universe_n]

    setups: List[Setup] = []
    for base, mv in universe:
        try:
            s = make_setup(
                base,
                mv,
                strict_15m=strict_15m,
                session_name=session_name,
                allow_no_pullback=allow_no_pullback,
                trigger_loosen_mult=float(trigger_loosen_mult),
                waiting_near_pct=float(waiting_near_pct),
                scan_profile=str(scan_profile or DEFAULT_SCAN_PROFILE),
            )
        except Exception:
            try:
                _rej("make_setup_exception", base, mv)
            except Exception:
                pass
            s = None

        if s:
            try:
                _note_status("setup_generated", base, mv)
            except Exception:
                pass
            setups.append(s)
        else:
            # If make_setup returns None without recording a reject, add a generic reject
            # so /why is never empty and tuning is possible.
            try:
                ctx = _REJECT_CTX.get()
                b = str(base or "").upper().strip()
                per = (ctx or {}).get("__per__") if isinstance(ctx, dict) else None
                if b and isinstance(ctx, dict) and (not isinstance(per, dict) or b not in per):
                    _rej("no_setup_candidate", base, mv, "make_setup_returned_none")
            except Exception:
                pass

    setups.sort(key=lambda x: (x.conf, x.fut_vol_usd), reverse=True)
    return setups[:n]


# =========================================================
# EMAIL
# =========================================================

def pick_breakout_setups(
    best_fut: Dict[str, MarketVol],
    n: int,
    session_name: str,
    universe_cap: int,
    scan_profile: str = DEFAULT_SCAN_PROFILE,
) -> List[Setup]:
    """
    Engine B selector: iterate symbols and build momentum breakout/breakdown setups.
    """
    items = list((best_fut or {}).items())
    # simple volume-based ordering
    items.sort(key=lambda kv: usd_notional(kv[1] or MarketVol()), reverse=True)
    if universe_cap and universe_cap > 0:
        items = items[:universe_cap]

    out: List[Setup] = []
    for base, mv in items:
        try:
            s = make_breakout_setup(base, mv, session_name=session_name, scan_profile=scan_profile)
            if s:
                out.append(s)
        except Exception:
            continue

    # order by confidence then volume
    out.sort(key=lambda s: (s.conf, s.fut_vol_usd), reverse=True)
    return out[: max(0, int(n)) ]






def _email_market_regime(best_fut: dict) -> str:
    try:
        best = dict(best_fut or {})
        vals = list(best.values())
        if not vals:
            return 'mixed'
        adv = sum(1 for mv in vals[:40] if float(getattr(mv, 'percentage', 0.0) or 0.0) > 0.0)
        dec = sum(1 for mv in vals[:40] if float(getattr(mv, 'percentage', 0.0) or 0.0) < 0.0)
        btc = float(getattr(best.get('BTC') or MarketVol('','','',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        eth = float(getattr(best.get('ETH') or MarketVol('','','',0,0,0,0,0,0), 'percentage', 0.0) or 0.0)
        if adv >= dec + 8 and btc >= 0.8 and eth >= 0.8:
            return 'risk_on'
        if dec >= adv + 8 and btc <= -0.8 and eth <= -0.8:
            return 'risk_off'
        return 'mixed'
    except Exception:
        return 'mixed'


def _email_symbol_cluster(symbol: str) -> str:
    b = _symbol_base(symbol)
    if b in {'BTC', 'ETH', 'SOL', 'XRP', 'DOGE', 'ADA', 'LINK', 'NEAR', 'AAVE', 'TAO'}:
        return 'majors'
    if b in {'XAU', 'XAUT', 'PAXG'}:
        return 'metals'
    if b in {'PEPE', '1000PEPE', 'FARTCOIN', 'TRUMP', 'WIF', 'BONK', 'FLOKI'}:
        return 'memes'
    if b in {'UAI', 'SAHARA', 'FET', 'AGIX', 'RNDR'}:
        return 'ai'
    return b or 'other'


def _email_diversification_guard(s: 'Setup', chosen_list: list, best_fut: dict, session_name: str) -> tuple[bool, str]:
    try:
        cfg = load_strategy_config(force=False)
        sess = str(session_name or '').upper().strip() or 'NY'
        caps = (cfg or {}).get('email_same_side_cap') or {}
        same_side_cap = int((caps.get(sess) if isinstance(caps, dict) else None) or (1 if sess == 'ASIA' else 2))
        cluster_cap = int((cfg or {}).get('email_cluster_side_cap', 1) or 1)
        bias = _email_market_regime(best_fut)
        score = float(getattr(s, 'quality_score', 0.0) or 0.0)
        conf = int(getattr(s, 'conf', 0) or 0)
        entry = float(getattr(s, 'entry', 0.0) or 0.0)
        sl = float(getattr(s, 'sl', 0.0) or 0.0)
        final_tp = float(_setup_target_tp(s, 0.0) or 0.0)
        rr_final = float(rr_to_tp(entry, sl, final_tp)) if entry > 0 and sl > 0 and final_tp > 0 else 0.0
        side = str(getattr(s, 'side', '') or '').upper().strip()
        cluster = _email_symbol_cluster(str(getattr(s, 'symbol', '') or ''))
        same_side_count = 0
        same_cluster_side_count = 0
        for c in (chosen_list or []):
            c_side = str(getattr(c, 'side', '') or '').upper().strip()
            if c_side == side:
                same_side_count += 1
                if _email_symbol_cluster(str(getattr(c, 'symbol', '') or '')) == cluster:
                    same_cluster_side_count += 1
        if same_side_count >= same_side_cap:
            return (False, 'same_side_burst_cap')
        if same_cluster_side_count >= cluster_cap and not (score >= 86.0 and conf >= 90 and rr_final >= 1.90):
            return (False, 'cluster_side_burst_cap')

        q_add_map = (cfg or {}).get('counter_regime_quality_add') or {}
        c_add_map = (cfg or {}).get('counter_regime_conf_add') or {}
        r_add_map = (cfg or {}).get('counter_regime_rr_add') or {}
        q_add = float((q_add_map.get(sess) if isinstance(q_add_map, dict) else None) or (3.0 if sess == 'ASIA' else 2.5))
        c_add = int((c_add_map.get(sess) if isinstance(c_add_map, dict) else None) or (3 if sess == 'ASIA' else 2))
        r_add = float((r_add_map.get(sess) if isinstance(r_add_map, dict) else None) or (0.12 if sess == 'ASIA' else 0.10))
        sess_q, sess_c, sess_r = _execution_session_thresholds(sess)
        if bias == 'risk_on' and side == 'SELL':
            if not (score >= (sess_q + q_add) and conf >= (sess_c + c_add) and rr_final >= (sess_r + r_add)):
                return (False, 'counter_regime_sell')
        if bias == 'risk_off' and side == 'BUY':
            if not (score >= (sess_q + q_add) and conf >= (sess_c + c_add) and rr_final >= (sess_r + r_add)):
                return (False, 'counter_regime_buy')

        ch15_abs = abs(float(getattr(s, 'ch15', 0.0) or 0.0))
        pb_dist = float(getattr(s, 'pullback_ema_dist_pct', 999.0) or 999.0)
        if cluster == 'majors' and same_side_count >= 1 and ch15_abs > 0.82 and pb_dist > 0.62 and conf < 90:
            return (False, 'correlated_major_chase')
        return (True, 'ok')
    except Exception:
        return (True, 'ok')

def user_email_alerts_enabled(user: dict) -> bool:
    # Admin always receives emails
    try:
        uid = int((user or {}).get("user_id") or 0)
        if uid and is_admin_user(uid):
            return True
    except Exception:
        pass
    try:
        return int((user or {}).get("email_alerts_enabled", 1)) == 1
    except Exception:
        return True


def set_user_email_alerts_enabled(uid: int, enabled: bool):
    update_user(int(uid), email_alerts_enabled=(1 if enabled else 0))


def set_user_trade_signal_email_enabled(uid: int, enabled: bool):
    """Keep the trade-signal recipient gate aligned with the user's email master switch."""
    flag = 1 if enabled else 0
    update_user(int(uid), email_alerts_enabled=flag, notify_on=flag)


def _mask_email_addr(email: str) -> str:
    try:
        email = str(email or '').strip()
        if not email or '@' not in email:
            return '(none)'
        local, domain = email.split('@', 1)
        if not local:
            return f"***@{domain}"
        if len(local) <= 2:
            masked_local = local[0] + '*' * max(1, len(local) - 1)
        else:
            masked_local = local[0] + ('*' * max(1, len(local) - 2)) + local[-1]
        return f"{masked_local}@{domain}"
    except Exception:
        return '(none)'


def _email_runtime_limits_snapshot(uid: int, user: dict) -> dict:
    fresh_user = get_user(int(uid)) or {}
    merged = dict(fresh_user)
    merged.update(dict(user or {}))
    user = merged
    try:
        tz = ZoneInfo(str(user.get('tz') or 'UTC'))
    except Exception:
        tz = timezone.utc
    # Use the anchored trading day (/dayreset), not midnight local day.
    try:
        day_local = _user_day_local(user)
    except Exception:
        day_local = datetime.now(tz).date().isoformat()
    recipient = str(user.get('email_to') or user.get('email') or '').strip()
    alerts_on = bool(user_email_alerts_enabled(user))
    smtp_ready = bool(EMAIL_ENABLED and email_config_ok())

    try:
        st = email_state_get(int(uid))
    except Exception:
        st = {'session_key': 'NONE', 'sent_count': 0, 'last_email_ts': 0.0}

    try:
        session_cap = int(user.get('max_emails_per_session', DEFAULT_MAX_EMAILS_PER_SESSION))
    except Exception:
        session_cap = int(DEFAULT_MAX_EMAILS_PER_SESSION)
    try:
        gap_min = int(user.get('email_gap_min', DEFAULT_MIN_EMAIL_GAP_MIN))
    except Exception:
        gap_min = int(DEFAULT_MIN_EMAIL_GAP_MIN)
    try:
        day_cap = int(user.get('max_emails_per_day', DEFAULT_MAX_EMAILS_PER_DAY))
    except Exception:
        day_cap = int(DEFAULT_MAX_EMAILS_PER_DAY)

    current_sess = None
    current_session_key = ''
    try:
        current_sess = in_session_now(user)
        current_session_key = str((current_sess or {}).get('session_key') or '')
    except Exception:
        current_sess = None
        current_session_key = ''
    try:
        sent_in_session = int(st.get('sent_count', 0) or 0)
        if (not current_session_key) or str(st.get('session_key') or '') != current_session_key:
            sent_in_session = 0
    except Exception:
        sent_in_session = 0
    try:
        last_email_ts = float(st.get('last_email_ts', 0.0) or 0.0)
    except Exception:
        last_email_ts = 0.0
    try:
        sent_today = int(_email_daily_get(int(uid), day_local))
    except Exception:
        sent_today = 0

    gap_sec = max(0, int(gap_min)) * 60
    gap_remaining_sec = max(0, int(round(gap_sec - (time.time() - last_email_ts)))) if gap_sec > 0 and last_email_ts > 0 else 0

    reasons = []
    if not alerts_on:
        reasons.append('email_alerts_disabled')
    if not recipient:
        reasons.append('no_recipient_email_set')
    if not EMAIL_ENABLED:
        reasons.append('EMAIL_ENABLED=0')
    elif not smtp_ready:
        reasons.append('smtp_not_configured')
    if day_cap > 0 and sent_today >= day_cap:
        reasons.append(f'daily_email_cap_reached ({sent_today}/{day_cap})')
    if session_cap > 0 and sent_in_session >= session_cap:
        reasons.append(f'session_email_cap_reached ({sent_in_session}/{session_cap})')
    if gap_remaining_sec > 0:
        reasons.append(f'email_gap_active ({gap_remaining_sec}s remaining)')

    return {
        'alerts_on': alerts_on,
        'smtp_ready': smtp_ready,
        'recipient': recipient,
        'recipient_masked': _mask_email_addr(recipient),
        'session_key': str(current_session_key or st.get('session_key') or 'NONE'),
        'sent_in_session': sent_in_session,
        'session_cap': session_cap,
        'sent_today': sent_today,
        'day_cap': day_cap,
        'gap_min': gap_min,
        'gap_remaining_sec': gap_remaining_sec,
        'last_email_ts': last_email_ts,
        'gate_open': len(reasons) == 0,
        'gate_reasons': reasons,
        'day_local': day_local,
    }

async def email_on_off_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """User command to enable/disable ALL email alerts without removing the saved email address."""
    uid = update.effective_user.id
    user = get_user(uid) or {}

    arg = (context.args[0].strip().lower() if context.args else "")
    if arg not in ("on", "off", "enable", "disable"):
        cur = "ON" if user_email_alerts_enabled(user) else "OFF"
        await update.message.reply_text(
            "📧 Email alerts (master switch)\n"
            "────────────────────\n"
            f"Current: {cur}\n\n"
            "Usage:\n"
            "/email_on_off on\n"
            "/email_on_off off\n\n"
            "Note: This does not remove your saved email address."
        )
        return

    enabled = arg in ("on", "enable")
    set_user_trade_signal_email_enabled(uid, enabled)
    await update.message.reply_text(
        "✅ Email alerts updated\n"
        "────────────────────\n"
        f"Now: {'ON' if enabled else 'OFF'}"
    )

def email_config_ok() -> bool:
    """
    Only checks SMTP sender config.
    Recipient is per-user (users.email_to OR users.email) OR fallback EMAIL_TO.
    """
    return all([EMAIL_HOST, EMAIL_PORT, EMAIL_USER, EMAIL_PASS, EMAIL_FROM])


def send_email(
    subject: str,
    body: str,
    body_html: Optional[str] = None,
    user_id_for_debug: Optional[int] = None,
    enforce_trade_window: bool = True
) -> bool:
    """
    Sends an email.

    Recipient resolution:
    - If user_id_for_debug is provided: uses users.email_to OR users.email
    - Otherwise falls back to EMAIL_TO (if set)

    Trade window:
    - Enforced only if enforce_trade_window=True
      (use False for system alerts like big-move alerts)

    Tracks last SMTP error + last email decision for /health and /email_decision.
    """
    global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS

    uid = int(user_id_for_debug) if user_id_for_debug is not None else None

    # Per-user master email alerts switch
    if uid is not None:
        u = get_user(int(uid))
        if u and not user_email_alerts_enabled(u):
            _LAST_EMAIL_DECISION[int(uid)] = {
                "status": "SKIP",
                "reason": "user_email_alerts_disabled",
                "ts": _now(),
            }
            return False

    # --- SMTP config check (sender side) ---
    if not email_config_ok():
        msg = "Email not configured (missing SMTP env vars)."
        logger.warning(msg)
        if uid is not None:
            _LAST_SMTP_ERROR[uid] = msg
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reason": msg,
                "ts": time.time(),
            }
        return False

    # --- Resolve recipient ---
    to_email = ""
    user = None
    now_local = None

    if uid is not None:
        user = get_user(uid) or {}
        to_email = str(user.get("email_to") or user.get("email") or "").strip()

        if not to_email:
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reasons": ["no_recipient_email_set"],
                "when": datetime.now(timezone.utc).isoformat(timespec="seconds"),
            }
            return False

        if enforce_trade_window:
            try:
                try:
                    tz = ZoneInfo(str(user.get("tz") or "UTC"))
                except Exception:
                    tz = timezone.utc
                now_local = datetime.now(tz)

                if not in_trade_window_now(user, now_local):
                    _LAST_EMAIL_DECISION[uid] = {
                        "status": "SKIP",
                        "reason": "outside_trade_window",
                        "ts": time.time(),
                    }
                    return False
            except Exception:
                _LAST_EMAIL_DECISION[uid] = {
                    "status": "SKIP",
                    "reason": "trade_window_check_failed",
                    "ts": time.time(),
                }
                return False
    else:
        to_email = str(EMAIL_TO or "").strip()
        if not to_email:
            logger.warning("No recipient email (EMAIL_TO empty and no user_id provided).")
            return False

    # --- Build message ---
    msg = EmailMessage()
    msg["Subject"] = subject
    msg["From"] = EMAIL_FROM
    msg["To"] = to_email
    msg.set_content(body)
    if body_html:
        try:
            msg.add_alternative(body_html, subtype="html")
        except Exception:
            pass


      
    def _close_cached():
        global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS
        try:
            if _SMTP_CONN is not None:
                try:
                    _SMTP_CONN.quit()
                except Exception:
                    try:
                        _SMTP_CONN.close()
                    except Exception:
                        pass
        finally:
            _SMTP_CONN = None
            _SMTP_CONN_IS_SSL = None
            _SMTP_CONN_TS = 0.0

    def _need_new_conn(is_ssl: bool) -> bool:
        global _SMTP_CONN, _SMTP_CONN_IS_SSL, _SMTP_CONN_TS
        if _SMTP_CONN is None:
            return True
        if _SMTP_CONN_IS_SSL is None or _SMTP_CONN_IS_SSL != is_ssl:
            return True
        if (time.time() - float(_SMTP_CONN_TS or 0.0)) > float(SMTP_REUSE_TTL_SEC or 0.0):
            return True
        return False


    def _connect_and_login(is_ssl: bool) -> smtplib.SMTP:
        timeout = float(EMAIL_SEND_TIMEOUT_SEC)
        if is_ssl:
            ctx = ssl.create_default_context()
            s = smtplib.SMTP_SSL(EMAIL_HOST, int(EMAIL_PORT), context=ctx, timeout=timeout)
        else:
            s = smtplib.SMTP(EMAIL_HOST, int(EMAIL_PORT), timeout=timeout)
            s.ehlo()
            s.starttls(context=ssl.create_default_context())
            s.ehlo()

        # login can be slow; keep under socket timeout
        s.login(EMAIL_USER, EMAIL_PASS)
        return s

    # --- Send (with connection reuse + lock) ---
    try:
        is_ssl = (int(EMAIL_PORT) == 465)

        with _SMTP_LOCK:
            # Refresh connection if needed
            if _need_new_conn(is_ssl):
                _close_cached()
                _SMTP_CONN = _connect_and_login(is_ssl)
                _SMTP_CONN_IS_SSL = is_ssl
                _SMTP_CONN_TS = time.time()
            else:
                # Light keepalive; if dropped, reconnect
                try:
                    _SMTP_CONN.noop()
                except Exception:
                    _close_cached()
                    _SMTP_CONN = _connect_and_login(is_ssl)
                    _SMTP_CONN_IS_SSL = is_ssl
                    _SMTP_CONN_TS = time.time()

            # Actual send
            _SMTP_CONN.send_message(msg)
            _SMTP_CONN_TS = time.time()

        if uid is not None:
            _LAST_SMTP_ERROR.pop(uid, None)
            _tmp_dec = {
                "status": "SENT",
                "reason": "ok",
                "ts": time.time(),
            }
            _LAST_EMAIL_DECISION[uid] = _tmp_dec
            _LAST_EMAIL_SENT[uid] = dict(_tmp_dec)
        return True

    except Exception as e:
        err = f"{type(e).__name__}: {e}"
        logger.exception("send_email failed: %s", err)

        # On any send failure, drop cached connection (often becomes poisoned)
        try:
            with _SMTP_LOCK:
                _close_cached()
        except Exception:
            pass

        if uid is not None:
            _LAST_SMTP_ERROR[uid] = err
            _LAST_EMAIL_DECISION[uid] = {
                "status": "FAIL",
                "reason": err,
                "ts": time.time(),
            }
        return False


# =========================================================
# STRIPE CHECKOUT / CUSTOMER PORTAL
# =========================================================
def create_checkout_session(email: str, plan: str) -> str:
    price_id = (
        os.environ.get("STRIPE_PRICE_STANDARD")
        if plan == "standard"
        else os.environ.get("STRIPE_PRICE_PRO")
    )

    session = stripe.checkout.Session.create(
        mode="subscription",
        customer_email=email,
        line_items=[{"price": price_id, "quantity": 1}],
        success_url=TELEGRAM_BOT_URL,
        cancel_url=TELEGRAM_BOT_URL,
        metadata={"plan": plan},
    )
    return session.url


def create_customer_portal(email: str) -> str:
    customer = stripe.Customer.list(email=email, limit=1).data[0]
    portal = stripe.billing_portal.Session.create(
        customer=customer.id,
        return_url=TELEGRAM_BOT_URL,
    )
    return portal.url


EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

async def email_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    user = get_user(uid) or {}

    if not context.args:
        cur = "ON" if user_email_alerts_enabled(user) else "OFF"
        saved = (user.get("email_to") or user.get("email") or "").strip()
        await update.message.reply_text(
            "📧 Email Settings\n"
            "────────────────────\n"
            f"Alerts: {cur}\n"
            f"Saved: {saved if saved else '(none)'}\n\n"
            "Set email: /email you@example.com\n"
            "Turn off: /email off\n"
            "Turn on: /email on"
        )
        return

    arg = context.args[0].strip().lower()

    # Support /email off|on
    if arg in ("off", "0", "disable", "disabled"):
        set_user_trade_signal_email_enabled(uid, False)
        await update.message.reply_text("✅ Email alerts: OFF")
        return

    if arg in ("on", "1", "enable", "enabled"):
        set_user_trade_signal_email_enabled(uid, True)
        await update.message.reply_text("✅ Email alerts: ON")
        return

    # Otherwise treat as an email address
    email = context.args[0].strip()
    if not EMAIL_RE.match(email):
        await update.message.reply_text(
            "❌ Invalid email format.\n"
            "Example: /email you@example.com\n"
            "Or: /email off"
        )
        return

    try:
        set_user_email(uid, email)
        set_user_trade_signal_email_enabled(uid, True)

        await update.message.reply_text(
            f"✅ Recipient email saved:\n{email}\n\n"
            "Email alerts are ON.\n"
            "Test now: /email_test\n"
            "Turn off any time: /email off"
        )
    except Exception as e:
        logger.exception("email_cmd failed")
        await update.message.reply_text(f"❌ Failed to save email: {type(e).__name__}: {e}")


async def email_on_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    # Alias: /email_on
    context.args = ["on"]
    await email_cmd(update, context)

async def email_off_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    # Alias: /email_off
    context.args = ["off"]
    await email_cmd(update, context)

async def email_test_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid = update.effective_user.id
    user = get_user(uid) or {}

    # Always respond immediately
    await update.message.reply_text("📧 Running email test…")

    # Config checks
    if not EMAIL_ENABLED:
        await update.message.reply_text("❌ Email is disabled (EMAIL_ENABLED=False). Turn it on in your config/env.")
        return

    if not email_config_ok():
        await update.message.reply_text(
            "❌ Email config is NOT OK.\n"
            "Check env vars: EMAIL_HOST, EMAIL_PORT, EMAIL_USER, EMAIL_PASS, EMAIL_FROM.\n"
            "Tip: run /health_sys and verify Email: enabled/configured."
        )
        return

    # Recipient (match your bot’s keys)
    to_email = (user.get("email_to") or user.get("email") or "").strip()
    if not to_email:
        await update.message.reply_text(
            "❌ No recipient email found for your user.\n"
            "Set it first, e.g. /email your@email.com"
        )
        return

    # Local time (user TZ)
    tz_name = str(user.get("tz") or "UTC")
    try:
        tz = ZoneInfo(tz_name)
    except Exception:
        tz = timezone.utc
        tz_name = "UTC"
    now_local = datetime.now(tz).strftime("%Y-%m-%d %H:%M:%S")

    subject = "PulseFutures — Email Test ✅"
    body = (
        f"{HDR}\n"
        f"PulseFutures Email Test\n"
        f"{HDR}\n\n"
        f"User ID: {uid}\n"
        f"Recipient: {to_email}\n"
        f"Time: {now_local} ({tz_name})\n\n"
        f"If you received this, SMTP is working.\n"
        f"{HDR}\n"
    )

    status_msg = await update.message.reply_text("📤 Sending test email…")

    # Clear previous error for clean reporting
    try:
        _LAST_SMTP_ERROR.pop(uid, None)
    except Exception:
        pass

    # Email test should NOT be blocked by user's email master switch
    prev_enabled = None
    try:
        prev_enabled = int((user or {}).get("email_alerts_enabled", 1))
        if prev_enabled == 0:
            update_user(uid, email_alerts_enabled=1)
    except Exception:
        prev_enabled = None

    try:
        # IMPORTANT: pass correct kwargs (avoid arg mis-binding)
        ok = await _send_email_async(
            int(EMAIL_SEND_TIMEOUT_SEC),
            subject,
            body,
            user_id_for_debug=uid,
            enforce_trade_window=False,
        )
    except Exception as e:
        logger.exception("email_test_cmd failed")
        msg = f"❌ Test email crashed: {type(e).__name__}: {e}"
        try:
            await status_msg.edit_text(msg)
        except Exception:
            await update.message.reply_text(msg)
        return
    finally:
        # Restore user's email alerts flag if we temporarily changed it
        try:
            if prev_enabled is not None and prev_enabled in (0, 1):
                update_user(uid, email_alerts_enabled=prev_enabled)
        except Exception:
            pass

    if ok:
        try:
            await status_msg.edit_text(f"✅ Test email SENT to: {to_email}")
        except Exception:
            await update.message.reply_text(f"✅ Test email SENT to: {to_email}")
        return

    # FAILED: show real last smtp error if available
    err = _LAST_SMTP_ERROR.get(uid) or "unknown_error"
    await update.message.reply_text(
        "❌ Test email FAILED.\n"
        f"Reason: {err}\n\n"
        "Common causes:\n"
        "- Gmail: app password / 2FA issues\n"
        "- Wrong EMAIL_HOST/PORT (465 SSL vs 587 STARTTLS)\n"
        "- EMAIL_FROM not matching account"
    )



async def trade_window_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /trade_window
    View: /trade_window
    Set : /trade_window 09:00 17:30
    Off : /trade_window off
    """
    uid = update.effective_user.id
    user = get_user(uid)

    if not context.args:
        cur_s = (user.get("trade_window_start") or "").strip()
        cur_e = (user.get("trade_window_end") or "").strip()
        if not cur_s or not cur_e:
            current_line = "Current: OFF (no time restriction)\n\n"
            await update.message.reply_text(
                "🕒 Trade Window (Email Signals)\n"
                f"{HDR}\n"
                + current_line +
                "Set: /trade_window 09:00 17:30\n"
                "Off: /trade_window off"
            )
        else:
            await update.message.reply_text(
                "🕒 Trade Window (Email Signals)\n"
                f"{HDR}\n"
                f"Current: {cur_s} → {cur_e} (local)\n\n"
                "Change: /trade_window 09:00 17:30\n"
                "Off: /trade_window off"
            )
        return

    if len(context.args) == 1 and context.args[0].strip().lower() in {"off", "disable", "none"}:
        update_user(uid, trade_window_start="", trade_window_end="")
        await update.message.reply_text("✅ Trade window is now OFF (emails allowed anytime).")
        return

    if len(context.args) != 2:
        await update.message.reply_text("Usage: /trade_window 09:00 17:30  OR  /trade_window off")
        return

    start_s = context.args[0].strip()
    end_s = context.args[1].strip()

    try:
        _parse_hhmm_local(start_s)
        _parse_hhmm_local(end_s)
    except Exception:
        await update.message.reply_text("Invalid time format. Use HH:MM (24h). Example: /trade_window 09:00 17:30")
        return

    update_user(uid, trade_window_start=start_s, trade_window_end=end_s)
    await update.message.reply_text(f"✅ Trade window set: {start_s} → {end_s} (local time).")

