def send_email_alert_multi(user: dict, sess: dict, setups: List[Setup], best_fut) -> bool:
    """
    One email containing multiple setups.
    Requires _email_body_pretty(...) and send_email(...).
    """
    if not setups:
        return False

    uid = int(user["user_id"])
    user_tz = str(user.get("tz") or "UTC")
    try:
        tz = ZoneInfo(user_tz)
    except Exception:
        tz = timezone.utc
        user_tz = "UTC"

    now_local = datetime.now(tz)

    # Display the *market* session (NY/LON/ASIA) in the email header.
    # 'UNLIMITED' is an access mode, not a market session.
    try:
        live_sess = current_session_utc(datetime.now(timezone.utc))
    except Exception:
        live_sess = "NONE"
    sess_name = str(sess.get("name") or "")
    display_session = (live_sess if live_sess != "NONE" else "NY") if sess_name == "UNLIMITED" else sess_name

    first = setups[0]
    subject = f"PulseFutures • {display_session} • {first.side} {first.symbol}"
    if len(setups) > 1:
        subject += f" (+{len(setups)-1} more)"

    body = _email_body_pretty(
        session_name=str(display_session),
        now_local=now_local,
        user_tz=user_tz,
        setups=setups,
        best_fut=best_fut,
    )

    body_html = _email_body_pretty_html(
        session_name=str(display_session),
        now_local=now_local,
        user_tz=user_tz,
        setups=setups,
        best_fut=best_fut,
    )

    try:
        for s in setups:
            try:
                db_insert_signal(s, user_id=uid)
            except Exception:
                pass
    except Exception:
        pass

    sent = send_email(subject, body, user_id_for_debug=uid, body_html=body_html)
    if sent:
        try:
            db_log_setup_pipeline_event(int(uid), stage='email_delivery', status='sent', session=str(display_session or ''), mode='email', details={'setups': len(setups or []), 'subject': str(subject or '')[:180]})
        except Exception:
            pass
        try:
            now_ts = time.time()
            try:
                owner_uid = int(AUTOTRADE_OWNER_UID or 0)
            except Exception:
                owner_uid = 0
            # IMPORTANT:
            # The email recipient uid and the autotrade owner uid can diverge in live admin setups
            # (for example, a current admin tester receives the email while AUTOTRADE_OWNER_UID points
            # to the dedicated owner record). Mirror the confirmed email/executable queue rows to the
            # owner uid so autotrade always consumes the same setup that was actually emailed.
            target_uids = [int(uid)]
            try:
                if owner_uid > 0 and int(owner_uid) not in target_uids and is_admin_user(int(uid)):
                    target_uids.append(int(owner_uid))
            except Exception:
                pass
            for s in setups:
                for _target_uid in target_uids:
                    try:
                        db_mark_emailed_setup(_target_uid, getattr(s, "setup_id", ""), str(display_session), now_ts)
                    except Exception:
                        pass
                    try:
                        # Re-assert the exact emailed setup into the executable lane so
                        # /screen and autotrade consume the same authoritative row even if
                        # an earlier pool-write was missed or a cache branch went stale.
                        db_mark_executable_setup(
                            int(_target_uid),
                            getattr(s, "setup_id", ""),
                            str(display_session),
                            float(now_ts),
                            s=s,
                            source_kind='emailed_setups',
                            state='executable_pending',
                        )
                    except Exception:
                        pass
                    try:
                        db_log_generated_setup(_target_uid, "email", str(display_session or ""), s)
                    except Exception:
                        pass
                    try:
                        _cache_recent_emailed_setup(int(_target_uid), s, session=str(display_session or ''), emailed_ts=float(now_ts), source_kind='recent_email_cache')
                    except Exception:
                        pass
        except Exception:
            pass
    else:
        try:
            db_log_setup_pipeline_event(int(uid), stage='email_delivery', status='failed', session=str(display_session or ''), mode='email', details={'setups': len(setups or []), 'subject': str(subject or '')[:180], 'smtp_error': str(_LAST_SMTP_ERROR.get(uid, 'smtp_send_failed') or 'smtp_send_failed')})
        except Exception:
            pass
        try:
            for s in setups:
                try:
                    _admin_setup_lifecycle_merge(
                        int(uid),
                        str(getattr(s, 'setup_id', '') or ''),
                        session=str(display_session or ''),
                        symbol=str(getattr(s, 'symbol', '') or ''),
                        side=str(getattr(s, 'side', '') or ''),
                        state='email_failed',
                        last_reason='smtp_send_failed',
                    )
                except Exception:
                    pass
        except Exception:
            pass
    return sent




# =========================================================
# STRIPE WEBHOOK SERVER
# =========================================================
class StripeWebhookHandler(BaseHTTPRequestHandler):
    def do_POST(self):
        payload = self.rfile.read(int(self.headers["Content-Length"]))
        sig = self.headers.get("Stripe-Signature")

        try:
            event = stripe.Webhook.construct_event(
                payload,
                sig,
                os.environ.get("STRIPE_WEBHOOK_SECRET"),
            )
        except Exception:
            self.send_response(400)
            self.end_headers()
            return

        data = event["data"]["object"]

        if event["type"] in ("checkout.session.completed", "invoice.paid"):
            email = data.get("customer_email")
        
            # get price + plan
            line = data["lines"]["data"][0]
            price_id = line["price"]["id"]
            plan = STRIPE_PRICE_TO_PLAN.get(price_id)
        
            # reference + amount
            ref = data.get("id") or event.get("id")
            amount = (line.get("amount_total") or data.get("amount_paid") or 0) / 100
            currency = (data.get("currency") or "usd").upper()
        
            if email and plan:
                activate_user_with_ledger_by_email(
                    email=email,
                    plan=plan,
                    ref=ref,
                    amount=amount,
                    currency=currency,
                )

        if event["type"] == "customer.subscription.deleted":
            email = data.get("customer_email")
            ref = data.get("id") or event.get("id")
            if email:
                downgrade_user_with_ledger_by_email(email, ref=ref)

        self.send_response(200)
        self.end_headers()

def start_stripe_webhook():
    HTTPServer(("0.0.0.0", 4242), StripeWebhookHandler).serve_forever()

